import type { VercelRequest, VercelResponse } from '@vercel/node';
// Import from app-level utils to ensure Vercel bundling resolves path
import { withIdempotency } from '../utils/idempotency.js';
import { requireAuth } from '../src/utils/apiAuth';
import apiConfig from './config';
import { errorFromResponse, normalizeError } from '../src/utils/errors';

// Simple per-user/IP token bucket
type Bucket = { count: number; reset: number };
const buckets = new Map<string, Bucket>();
const BUCKET_MAX = 20; // per minute
const BUCKET_WINDOW_MS = 60_000;

function clientKey(req: VercelRequest): string {
  const uid = (req as any).user?.id || 'anon';
  const ip =
    (req.headers['x-forwarded-for'] as string)?.split(',')[0]?.trim() ||
    req.socket.remoteAddress ||
    'unknown';
  return `${uid}:${ip}`;
}

function checkBucket(req: VercelRequest): {
  allowed: boolean;
  retryAfter?: number;
} {
  const key = clientKey(req);
  const now = Date.now();
  const entry = buckets.get(key);
  if (!entry || now >= entry.reset) {
    buckets.set(key, { count: 1, reset: now + BUCKET_WINDOW_MS });
    return { allowed: true };
  }
  if (entry.count >= BUCKET_MAX)
    return { allowed: false, retryAfter: entry.reset - now };
  entry.count += 1;
  return { allowed: true };
}

async function fetchWithTimeout(
  input: RequestInfo | URL,
  init: RequestInit = {},
  timeoutMs = 12000
): Promise<Response> {
  const controller = new AbortController();
  const id = setTimeout(() => controller.abort(), timeoutMs);
  try {
    return await fetch(input, { ...init, signal: controller.signal });
  } finally {
    clearTimeout(id);
  }
}

const ACOUSTID_URL = 'https://api.acoustid.org/v2/lookup';

async function acoustidHandler(req: VercelRequest, res: VercelResponse) {
  if (req.method !== 'GET') {
    res
      .status(405)
      .json({ error: { code: 'BAD_REQUEST', message: 'Method not allowed' } });
    return;
  }

  const key = process.env.ACOUSTID_API_KEY;
  if (!key) {
    res.status(500).json({
      error: {
        code: 'INTERNAL_ERROR',
        message: 'Server missing ACOUSTID_API_KEY',
      },
    });
    return;
  }

  const { fingerprint, duration } = req.query;
  if (!fingerprint || !duration) {
    res.status(400).json({
      error: {
        code: 'BAD_REQUEST',
        message: 'Missing fingerprint or duration',
      },
    });
    return;
  }

  const params = new URLSearchParams({
    client: key as string,
    meta: 'recordings+releasegroups+compress',
    fingerprint: fingerprint as string,
    duration: duration as string,
    format: 'json',
  });

  try {
    const bucket = checkBucket(req);
    if (!bucket.allowed) {
      res.setHeader(
        'Retry-After',
        Math.ceil((bucket.retryAfter || 1000) / 1000).toString()
      );
      return res.status(429).json({
        error: { code: 'RATE_LIMITED', message: 'Too many requests' },
      });
    }

    const response = await fetchWithTimeout(
      `${ACOUSTID_URL}?${params.toString()}`,
      {
        headers: { 'User-Agent': 'MagicDJ/1.0' },
      },
      12000
    );
    const text = await response.text();
    if (!response.ok) {
      const err = await errorFromResponse(response, text);
      return res.status(err.httpStatus || 502).json({ error: err });
    }
    res.setHeader('Cache-Control', 'no-store');
    res.status(200).send(text);
  } catch (e: any) {
    const normalized = normalizeError(e, {
      code: 'INTERNAL_ERROR',
      message: 'AcoustID proxy failed',
    });
    res.status(normalized.httpStatus || 500).json({ error: normalized });
  }
}

export default apiConfig.ENABLE_IDEMPOTENCY
  ? withIdempotency(acoustidHandler)
  : acoustidHandler;

import type { VercelRequest, VercelResponse } from '@vercel/node';
import { getServerSupabase } from './lib/supabaseServer.js';

export default async function handler(req: VercelRequest, res: VercelResponse) {
  if (req.method !== 'GET') {
    res.setHeader('Allow', 'GET');
    return res.status(405).json({ error: 'Method not allowed' });
  }

  const supabase = getServerSupabase(req.headers.authorization);

  try {
    const { data: user } = await supabase.auth.getUser();
    const user_id = user?.user?.id;
    if (!user_id) return res.status(401).json({ error: 'Unauthorized' });

    // Last 7 days summary by type
    const { data: events, error } = await supabase
      .from('events')
      .select('type, created_at')
      .gte(
        'created_at',
        new Date(Date.now() - 7 * 24 * 3600 * 1000).toISOString()
      );

    if (error) return res.status(500).json({ error: error.message });

    const summary: Record<string, number> = {};
    for (const e of events || []) {
      summary[e.type] = (summary[e.type] || 0) + 1;
    }

    return res.status(200).json({ ok: true, summary });
  } catch (e: any) {
    return res.status(500).json({ error: e?.message || 'unknown' });
  }
}

import type { VercelRequest, VercelResponse } from '@vercel/node';
// Import from app-level utils to ensure Vercel bundling resolves path
import { withIdempotency } from '../utils/idempotency.js';
import { requireAuth } from '../src/utils/apiAuth';
import apiConfig from './config';
import { errorFromResponse, normalizeError } from '../src/utils/errors';

const AUDD_URL = 'https://api.audd.io/';

export const config = {
  api: {
    bodyParser: false,
  },
};

// Simple token bucket per user/IP
type Bucket = { count: number; reset: number };
const buckets = new Map<string, Bucket>();
const BUCKET_MAX = 15; // per minute
const BUCKET_WINDOW_MS = 60_000;

function clientKey(req: VercelRequest): string {
  const uid = (req as any).user?.id || 'anon';
  const ip =
    (req.headers['x-forwarded-for'] as string)?.split(',')[0]?.trim() ||
    req.socket.remoteAddress ||
    'unknown';
  return `${uid}:${ip}`;
}

function checkBucket(req: VercelRequest): {
  allowed: boolean;
  retryAfter?: number;
} {
  const key = clientKey(req);
  const now = Date.now();
  const entry = buckets.get(key);
  if (!entry || now >= entry.reset) {
    buckets.set(key, { count: 1, reset: now + BUCKET_WINDOW_MS });
    return { allowed: true };
  }
  if (entry.count >= BUCKET_MAX)
    return { allowed: false, retryAfter: entry.reset - now };
  entry.count += 1;
  return { allowed: true };
}

async function fetchWithTimeout(
  input: RequestInfo | URL,
  init: RequestInit = {},
  timeoutMs = 20000
): Promise<Response> {
  const controller = new AbortController();
  const id = setTimeout(() => controller.abort(), timeoutMs);
  try {
    return await fetch(input, { ...init, signal: controller.signal });
  } finally {
    clearTimeout(id);
  }
}

async function auddHandler(req: VercelRequest, res: VercelResponse) {
  if (req.method !== 'POST') {
    res
      .status(405)
      .json({ error: { code: 'BAD_REQUEST', message: 'Method not allowed' } });
    return;
  }

  try {
    const bucket = checkBucket(req);
    if (!bucket.allowed) {
      res.setHeader(
        'Retry-After',
        Math.ceil((bucket.retryAfter || 1000) / 1000).toString()
      );
      return res.status(429).json({
        error: { code: 'RATE_LIMITED', message: 'Too many requests' },
      });
    }

    const chunks: Buffer[] = [];
    for await (const chunk of req) chunks.push(Buffer.from(chunk));
    const bodyBuffer = Buffer.concat(chunks);

    const token = process.env.AUDD_API_TOKEN;
    if (!token) {
      res.status(500).json({
        error: {
          code: 'INTERNAL_ERROR',
          message: 'Server missing AUDD_API_TOKEN',
        },
      });
      return;
    }

    // Forward to AudD, injecting api_token
    const boundaryMatch = req.headers['content-type']
      ?.toString()
      .match(/boundary=(.*)$/);
    let fetchInit: RequestInit;
    if (boundaryMatch) {
      // multipart/form-data: append token as an extra field by reconstructing is non-trivial.
      // Simpler approach: rely on client not sending token and add it via query param.
      const url = new URL(AUDD_URL);
      url.searchParams.set('api_token', token);
      fetchInit = {
        method: 'POST',
        headers: { 'Content-Type': req.headers['content-type'] as string },
        body: bodyBuffer,
      };
      const response = await fetchWithTimeout(url.toString(), fetchInit, 20000);
      const text = await response.text();
      if (!response.ok) {
        const err = await errorFromResponse(response, text);
        return res.status(err.httpStatus || 502).json({ error: err });
      }
      res.setHeader('Cache-Control', 'no-store');
      res.status(200).send(text);
    } else {
      // Assume JSON with { audio: base64 } or similar
      const payload = JSON.parse(bodyBuffer.toString('utf8'));
      payload.api_token = token;
      const response = await fetchWithTimeout(
        AUDD_URL,
        {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(payload),
        },
        20000
      );
      const text = await response.text();
      if (!response.ok) {
        const err = await errorFromResponse(response, text);
        return res.status(err.httpStatus || 502).json({ error: err });
      }
      res.setHeader('Cache-Control', 'no-store');
      res.status(200).send(text);
    }
  } catch (e: any) {
    const normalized = normalizeError(e, {
      code: 'INTERNAL_ERROR',
      message: 'AudD proxy failed',
    });
    res.status(normalized.httpStatus || 500).json({ error: normalized });
  }
}

export default apiConfig.ENABLE_IDEMPOTENCY
  ? withIdempotency(auddHandler)
  : auddHandler;

// Centralized serverless (API) configuration and feature flags

// Accept both Vercel (plain) and Vite-style variables, with typo-tolerant fallback
function readEnv(name: string, fallbacks: string[] = []): string {
  const keys = [name, ...fallbacks];
  for (const key of keys) {
    const val = (process as any)?.env?.[key];
    if (val) return String(val).trim();
  }
  return '';
}

export const apiConfig = {
  // Prefer server-side secrets; accept Vite-style for convenience; ignore old typo VITA_*
  SPOTIFY_CLIENT_ID: readEnv('SPOTIFY_CLIENT_ID', [
    'VITE_SPOTIFY_CLIENT_ID',
    'VITA_SPOTIFY_CLIENT_ID',
  ]),
  SPOTIFY_CLIENT_SECRET: readEnv('SPOTIFY_CLIENT_SECRET', [
    'VITE_SPOTIFY_CLIENT_SECRET',
    'VITA_SPOTIFY_CLIENT_SECRET',
  ]),
  YOUTUBE_API_KEY: readEnv('YOUTUBE_API_KEY', ['VITE_YOUTUBE_API_KEY']),

  // Supabase configuration
  SUPABASE_URL: readEnv('SUPABASE_URL', [
    'NEXT_PUBLIC_SUPABASE_URL',
    'VITE_SUPABASE_URL',
  ]),
  SUPABASE_ANON_KEY: readEnv('SUPABASE_ANON_KEY', [
    'NEXT_PUBLIC_SUPABASE_ANON_KEY',
    'VITE_SUPABASE_ANON_KEY',
  ]),
  SUPABASE_SERVICE_ROLE_KEY: readEnv('SUPABASE_SERVICE_ROLE_KEY'),

  ENABLE_IDEMPOTENCY: readEnv('ENABLE_IDEMPOTENCY') !== 'false',
  ENABLE_RATE_LIMIT: readEnv('ENABLE_RATE_LIMIT') !== 'false',
  DURABLE_STORE_URL: readEnv('DURABLE_STORE_URL'), // optional KV/Redis URL
};

export default apiConfig;

import type { VercelRequest, VercelResponse } from '@vercel/node';
import { z } from 'zod';
import { getServerSupabase } from './lib/supabaseServer.js';

const EventSchema = z.object({
  type: z.string().min(1).max(100),
  payload: z.record(z.any()).optional().default({}),
  session_id: z.string().uuid().optional(),
  playlist_id: z.string().uuid().optional(),
});

export default async function handler(req: VercelRequest, res: VercelResponse) {
  const auth = req.headers.authorization; // Expect 'Bearer <jwt>' from client
  const supabase = getServerSupabase(auth);

  if (req.method === 'POST') {
    try {
      const bodyRaw =
        typeof req.body === 'string' ? JSON.parse(req.body) : req.body || {};
      const { type, payload, session_id, playlist_id } =
        EventSchema.parse(bodyRaw);

      const { data: user } = await supabase.auth.getUser();
      const user_id = user?.user?.id;
      if (!user_id) return res.status(401).json({ error: 'Unauthorized' });

      const { data, error } = await supabase
        .from('events')
        .insert([
          {
            user_id,
            type,
            payload: payload ?? {},
            session_id: session_id ?? null,
            playlist_id: playlist_id ?? null,
          },
        ])
        .select('*')
        .single();

      if (error) return res.status(500).json({ error: error.message });
      return res.status(200).json({ ok: true, event: data });
    } catch (e: any) {
      const message = e?.message || 'invalid_request';
      const code = e?.name === 'ZodError' ? 400 : 500;
      return res.status(code).json({ error: message });
    }
  }

  if (req.method === 'GET') {
    try {
      const { data: user } = await supabase.auth.getUser();
      const user_id = user?.user?.id;
      if (!user_id) return res.status(401).json({ error: 'Unauthorized' });

      const { data, error } = await supabase
        .from('events')
        .select('*')
        .eq('user_id', user_id)
        .order('created_at', { ascending: false })
        .limit(100);

      if (error) return res.status(500).json({ error: error.message });
      return res.status(200).json({ ok: true, events: data });
    } catch (e: any) {
      return res.status(500).json({ error: e?.message || 'unknown' });
    }
  }

  res.setHeader('Allow', 'GET, POST');
  return res.status(405).json({ error: 'Method not allowed' });
}

import type { VercelRequest, VercelResponse } from '@vercel/node';

// Get API keys from environment
const YOUTUBE_API_KEY =
  process.env.YOUTUBE_API_KEY || process.env.VITE_YOUTUBE_API_KEY;
const SPOTIFY_CLIENT_ID =
  process.env.SPOTIFY_CLIENT_ID || process.env.VITE_SPOTIFY_CLIENT_ID;
const SPOTIFY_CLIENT_SECRET =
  process.env.SPOTIFY_CLIENT_SECRET || process.env.VITE_SPOTIFY_CLIENT_SECRET;

// Get Spotify access token
async function getSpotifyToken(): Promise<string> {
  if (!SPOTIFY_CLIENT_ID || !SPOTIFY_CLIENT_SECRET) {
    throw new Error('Spotify credentials not configured');
  }

  const credentials = btoa(`${SPOTIFY_CLIENT_ID}:${SPOTIFY_CLIENT_SECRET}`);

  const response = await fetch('https://accounts.spotify.com/api/token', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
      Authorization: `Basic ${credentials}`,
    },
    body: 'grant_type=client_credentials',
  });

  if (!response.ok) {
    throw new Error(`Spotify auth failed: ${response.status}`);
  }

  const data = await response.json();
  return data.access_token;
}

// Search Spotify for tracks with preview URLs
async function searchSpotify(
  query: string,
  token: string,
  maxResults: number = 1
) {
  const searchUrl = new URL('https://api.spotify.com/v1/search');
  searchUrl.searchParams.set('q', query);
  searchUrl.searchParams.set('type', 'track');
  searchUrl.searchParams.set('limit', maxResults.toString());

  const response = await fetch(searchUrl.toString(), {
    headers: {
      Authorization: `Bearer ${token}`,
      Accept: 'application/json',
    },
  });

  if (!response.ok) {
    throw new Error(`Spotify search failed: ${response.status}`);
  }

  const data = await response.json();
  return data.tracks?.items || [];
}

// Search YouTube for real tracks
async function searchYouTube(query: string, maxResults: number = 1) {
  if (!YOUTUBE_API_KEY) {
    throw new Error('YouTube API key not configured');
  }

  const searchUrl = new URL('https://www.googleapis.com/youtube/v3/search');
  searchUrl.searchParams.set('part', 'snippet');
  searchUrl.searchParams.set('q', query);
  searchUrl.searchParams.set('type', 'video');
  searchUrl.searchParams.set('videoCategoryId', '10'); // Music category
  searchUrl.searchParams.set('videoEmbeddable', 'true');
  searchUrl.searchParams.set('maxResults', maxResults.toString());
  searchUrl.searchParams.set('order', 'relevance');
  searchUrl.searchParams.set('key', YOUTUBE_API_KEY);

  const response = await fetch(searchUrl.toString(), {
    headers: {
      Accept: 'application/json',
    },
  });

  if (!response.ok) {
    throw new Error(`YouTube search failed: ${response.status}`);
  }

  const data = await response.json();
  return data.items || [];
}

// Generate search queries based on vibe and energy
function getSearchQueries(vibe: string, energyLevel: string) {
  const genreMap: Record<string, string[]> = {
    Electronic: [
      'electronic music',
      'techno',
      'house music',
      'EDM',
      'synthesizer music',
    ],
    'Hip-Hop': [
      'hip hop music',
      'rap beats',
      'trap music',
      'hip hop instrumental',
    ],
    House: ['house music', 'deep house', 'tech house', 'progressive house'],
    Techno: [
      'techno music',
      'minimal techno',
      'acid techno',
      'industrial techno',
    ],
  };

  const energyModifiers: Record<string, string[]> = {
    low: ['chill', 'ambient', 'downtempo', 'relaxed'],
    medium: ['groove', 'steady', 'rhythmic'],
    high: ['energetic', 'upbeat', 'intense', 'peak time'],
  };

  const baseQueries = genreMap[vibe] || genreMap['Electronic'];
  const modifiers = energyModifiers[energyLevel] || energyModifiers['medium'];

  const queries = [];
  for (const base of baseQueries.slice(0, 3)) {
    for (const modifier of modifiers.slice(0, 2)) {
      queries.push(`${modifier} ${base}`);
    }
  }

  return queries;
}

// Real magic set generation with actual YouTube sources
export default async function handler(req: VercelRequest, res: VercelResponse) {
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method not allowed' });
  }

  try {
    const {
      vibe = 'Electronic',
      energyLevel = 'medium',
      trackCount = 10,
    } = req.body || {};

    console.log(
      `[Magic Set] Generating ${trackCount} tracks for ${vibe} with ${energyLevel} energy`
    );

    const tracks = [];
    const searchQueries = getSearchQueries(vibe, energyLevel);
    let totalSourceCount = 0;
    const allSourceTypes = new Set<string>();

    // Get Spotify access token for multi-provider resolution
    let spotifyToken: string | null = null;
    try {
      spotifyToken = await getSpotifyToken();
      console.log(`[Magic Set] ✅ Spotify API authenticated`);
    } catch (error) {
      console.warn(
        `[Magic Set] ⚠️ Spotify authentication failed, using YouTube only:`,
        error
      );
    }

    // Generate tracks with multi-provider sources (Spotify + YouTube)
    for (let i = 0; i < trackCount && i < searchQueries.length; i++) {
      const query = searchQueries[i];
      console.log(`[Magic Set] Multi-provider search for: "${query}"`);

      let trackSourceCount = 0;
      const trackSourceTypes: string[] = [];
      const trackData: any = {
        id: `track-${Date.now()}-${i}`,
        title: `${vibe} Track ${i + 1}`,
        artist: 'Unknown Artist',
        album: 'Magic DJ Generated',
        duration: 180 + Math.floor(Math.random() * 120),
        bpm: 120 + Math.floor(Math.random() * 20),
        energy:
          energyLevel === 'low'
            ? 40 + Math.random() * 20
            : energyLevel === 'high'
              ? 80 + Math.random() * 20
              : 60 + Math.random() * 20,
        key: ['C', 'D', 'E', 'F', 'G', 'A', 'B'][Math.floor(Math.random() * 7)],
        genre: vibe,
        created_at: new Date().toISOString(),
        updated_at: new Date().toISOString(),
        // Initialize source fields
        youtube_id: null,
        youtube_url: null,
        spotify_id: null,
        preview_url: null,
        source_url: null,
        thumbnail: null,
      };

      // Try Spotify first for better metadata and preview URLs
      if (spotifyToken) {
        try {
          console.log(`[Magic Set] Searching Spotify for: "${query}"`);
          const spotifyResults = await searchSpotify(query, spotifyToken, 1);

          if (spotifyResults && spotifyResults.length > 0) {
            const track = spotifyResults[0];
            trackData.title = track.name || trackData.title;
            trackData.artist = track.artists?.[0]?.name || trackData.artist;
            trackData.album = track.album?.name || trackData.album;
            trackData.duration = Math.floor(
              (track.duration_ms || 180000) / 1000
            );
            trackData.spotify_id = track.id;
            trackData.thumbnail =
              track.album?.images?.[1]?.url || track.album?.images?.[0]?.url;

            // Add Spotify preview URL if available
            if (track.preview_url) {
              trackData.preview_url = track.preview_url;
              trackData.source_url = track.preview_url; // Primary source
              trackSourceCount++;
              trackSourceTypes.push('spotify');
              allSourceTypes.add('spotify');
              console.log(
                `[Magic Set] ✅ Spotify preview resolved: trackId="${trackData.id}", preview_url="${track.preview_url}"`
              );
            }
          }
        } catch (error) {
          console.warn(
            `[Magic Set] Spotify search failed for "${query}":`,
            error
          );
        }
      }

      // Try YouTube as secondary/fallback source
      try {
        console.log(
          `[Magic Set] Searching YouTube for: "${trackData.title} ${trackData.artist}"`
        );
        const youtubeQuery = `${trackData.title} ${trackData.artist}`;
        const youtubeResults = await searchYouTube(youtubeQuery, 1);

        if (youtubeResults && youtubeResults.length > 0) {
          const video = youtubeResults[0];
          const videoId = video.id?.videoId;

          if (videoId) {
            const youtubeUrl = `https://www.youtube.com/watch?v=${videoId}`;
            trackData.youtube_id = videoId;
            trackData.youtube_url = youtubeUrl;

            // Use YouTube as primary source if no Spotify preview
            if (!trackData.source_url) {
              trackData.source_url = youtubeUrl;
            }

            trackSourceCount++;
            trackSourceTypes.push('youtube');
            allSourceTypes.add('youtube');
            console.log(
              `[Magic Set] ✅ YouTube resolved: trackId="${trackData.id}", youtube_url="${youtubeUrl}"`
            );
          }
        }
      } catch (error) {
        console.warn(
          `[Magic Set] YouTube search failed for "${trackData.title}":`,
          error
        );
      }

      // Add track regardless of source resolution (with clear logging)
      tracks.push(trackData);
      totalSourceCount += trackSourceCount;

      if (trackSourceCount > 0) {
        console.log(
          `[Magic Set] ✅ Multi-provider resolution: trackId="${trackData.id}", sourceCount=${trackSourceCount}, sourceTypes=${JSON.stringify(trackSourceTypes)}`
        );
      } else {
        console.log(
          `[Magic Set] ❌ No sources resolved: trackId="${trackData.id}", sourceCount=0, sourceTypes=[]`
        );
      }
    }

    // Fill remaining slots with more searches if needed
    while (tracks.length < trackCount) {
      const query = `${vibe} music ${energyLevel} energy`;
      try {
        console.log(`[Magic Set] Additional search for: "${query}"`);
        const youtubeResults = await searchYouTube(query, 1);

        if (youtubeResults && youtubeResults.length > 0) {
          const video = youtubeResults[0];
          const videoId = video.id?.videoId;

          if (videoId) {
            const youtubeUrl = `https://www.youtube.com/watch?v=${videoId}`;
            tracks.push({
              id: `track-${Date.now()}-${tracks.length}`,
              title:
                video.snippet?.title || `${vibe} Track ${tracks.length + 1}`,
              artist: video.snippet?.channelTitle || 'Unknown Artist',
              album: 'Magic DJ Generated',
              duration: 180 + Math.floor(Math.random() * 120),
              bpm: 120 + Math.floor(Math.random() * 20),
              energy:
                energyLevel === 'low'
                  ? 40 + Math.random() * 20
                  : energyLevel === 'high'
                    ? 80 + Math.random() * 20
                    : 60 + Math.random() * 20,
              key: ['C', 'D', 'E', 'F', 'G', 'A', 'B'][
                Math.floor(Math.random() * 7)
              ],
              genre: vibe,
              youtube_id: videoId,
              youtube_url: youtubeUrl,
              source_url: youtubeUrl,
              thumbnail:
                video.snippet?.thumbnails?.medium?.url ||
                video.snippet?.thumbnails?.default?.url,
              created_at: new Date().toISOString(),
              updated_at: new Date().toISOString(),
            });

            totalSourceCount++;
            console.log(
              `[Magic Set] ✅ Additional source resolved: trackId="${tracks[tracks.length - 1].id}", sourceCount=1, sourceTypes=["youtube"], url="${youtubeUrl}"`
            );
          }
        } else {
          break; // No more results available
        }
      } catch (error) {
        console.error(`[Magic Set] Additional search failed:`, error);
        break;
      }
    }

    // Calculate final statistics
    const tracksWithSources = tracks.filter(track => track.source_url).length;
    const sourceTypesArray = Array.from(allSourceTypes);

    console.log(
      `[Magic Set] Generation complete: ${tracks.length} tracks, ${tracksWithSources} with sources, ${totalSourceCount} total sources`
    );

    const playlist = {
      id: `playlist-${Date.now()}`,
      name: `Magic ${vibe} Set (${energyLevel} energy)`,
      description: `AI-generated ${vibe} playlist with ${energyLevel} energy level. Multi-provider sources: ${sourceTypesArray.join(', ')}. ${tracksWithSources}/${tracks.length} tracks playable.`,
      tracks: tracks,
      total_duration: tracks.reduce((sum, track) => sum + track.duration, 0),
      user_id: 'api-generated',
      genre: vibe,
      energy_level: energyLevel,
      created_at: new Date().toISOString(),
      updated_at: new Date().toISOString(),
      // MULTI-PROVIDER AUDIO SOURCE METADATA
      source_metadata: {
        total_tracks: tracks.length,
        sourced_tracks: tracksWithSources,
        total_sources: totalSourceCount,
        source_types: sourceTypesArray,
        source_coverage: Math.round((tracksWithSources / tracks.length) * 100),
        multi_provider: sourceTypesArray.length > 1,
        providers_available: sourceTypesArray.length,
      },
    };

    console.log(
      `[Magic Set] MULTI-PROVIDER RESULT: totalTracks=${playlist.source_metadata.total_tracks}, sourcedTracks=${playlist.source_metadata.sourced_tracks}, totalSources=${playlist.source_metadata.total_sources}, sourceTypes=${JSON.stringify(playlist.source_metadata.source_types)}, multiProvider=${playlist.source_metadata.multi_provider}, coverage=${playlist.source_metadata.source_coverage}%`
    );

    res.status(200).json(playlist);
  } catch (error) {
    console.error('[Magic Set] Generation failed:', error);
    res.status(500).json({
      error: 'Failed to generate magic set',
      details:
        process.env.NODE_ENV === 'development' ? error.message : undefined,
    });
  }
}

import type { VercelRequest, VercelResponse } from '@vercel/node';
import { getServerSupabase } from './lib/supabaseServer.js';

export default async function handler(req: VercelRequest, res: VercelResponse) {
  try {
    const envOk =
      !!(
        process.env.VITE_SUPABASE_URL ||
        process.env.PUBLIC_SUPABASE_URL ||
        process.env.NEXT_PUBLIC_SUPABASE_URL
      ) &&
      !!(
        process.env.VITE_SUPABASE_ANON_KEY ||
        process.env.PUBLIC_SUPABASE_ANON_KEY ||
        process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY
      );

    const supabase = getServerSupabase(req.headers.authorization);
    // Lightweight reachability check (RLS may return empty, that's fine)
    const { error } = await supabase.from('playlists').select('id').limit(1);

    const ok = envOk && !error;
    res.setHeader('Cache-Control', 'no-store');
    return res.status(ok ? 200 : 500).json({
      ok,
      envOk,
      dbOk: !error,
      timestamp: new Date().toISOString(),
      error: error?.message || null,
    });
  } catch (e: any) {
    return res.status(500).json({ ok: false, error: e?.message || 'unknown' });
  }
}

import type { VercelRequest, VercelResponse } from '@vercel/node';
import { z } from 'zod';
import { getServerSupabase } from './lib/supabaseServer.js';

const CreateSessionSchema = z.object({
  name: z.string().min(1).max(200),
  playlist_id: z.string().uuid().optional(),
});

export default async function handler(req: VercelRequest, res: VercelResponse) {
  const auth = req.headers.authorization;
  const supabase = getServerSupabase(auth);

  if (req.method === 'GET') {
    const { data: user } = await supabase.auth.getUser();
    const user_id = user?.user?.id;
    if (!user_id) return res.status(401).json({ error: 'Unauthorized' });

    const { data, error } = await supabase
      .from('sessions')
      .select('*')
      .eq('user_id', user_id)
      .order('started_at', { ascending: false })
      .limit(50);

    if (error) return res.status(500).json({ error: error.message });
    return res.status(200).json({ ok: true, sessions: data });
  }

  if (req.method === 'POST') {
    const raw =
      typeof req.body === 'string' ? JSON.parse(req.body) : req.body || {};
    const { name, playlist_id } = CreateSessionSchema.parse(raw);
    const { data: user } = await supabase.auth.getUser();
    const user_id = user?.user?.id;
    if (!user_id) return res.status(401).json({ error: 'Unauthorized' });

    const { data, error } = await supabase
      .from('sessions')
      .insert([
        {
          user_id,
          playlist_id: playlist_id ?? null,
          status: 'active',
          started_at: new Date().toISOString(),
        },
      ])
      .select('*')
      .single();

    if (error) return res.status(500).json({ error: error.message });
    return res.status(200).json({ ok: true, session: data });
  }

  res.setHeader('Allow', 'GET, POST');
  return res.status(405).json({ error: 'Method not allowed' });
}

import type { VercelRequest, VercelResponse } from '@vercel/node';
import { withIdempotency } from '../utils/idempotency.js';
import apiConfig from './config.js';
import {
  AppError,
  errorFromResponse,
  normalizeError,
} from '../src/utils/errors.js';
import { checkAndConsume } from '../utils/apiRateLimiter.js';

type TokenCache = {
  access_token: string;
  token_type: string;
  expires_at: number;
  expires_in: number;
} | null;

let tokenCache: TokenCache = null;
let inflight: Promise<any> | null = null;

type Bucket = { count: number; reset: number };
const buckets = new Map<string, Bucket>();
const BUCKET_MAX = 30;
const BUCKET_WINDOW_MS = 60_000;

function getClientKey(req: VercelRequest): string {
  const ip =
    (req.headers['x-forwarded-for'] as string)?.split(',')[0]?.trim() ||
    req.socket.remoteAddress ||
    'unknown';
  return `token:${ip}`;
}

function checkBucket(req: VercelRequest) {
  const key = getClientKey(req);
  const now = Date.now();
  const entry = buckets.get(key);
  if (!entry || now >= entry.reset) {
    buckets.set(key, { count: 1, reset: now + BUCKET_WINDOW_MS });
    return { allowed: true };
  }
  if (entry.count >= BUCKET_MAX) {
    return { allowed: false, retryAfter: entry.reset - now };
  }
  entry.count += 1;
  return { allowed: true };
}

async function fetchWithTimeout(
  input: RequestInfo | URL,
  init: RequestInit = {},
  timeoutMs = 12000
): Promise<Response> {
  const controller = new AbortController();
  const id = setTimeout(() => controller.abort(), timeoutMs);
  try {
    return await fetch(input, { ...init, signal: controller.signal });
  } finally {
    clearTimeout(id);
  }
}

async function spotifyTokenHandler(req: VercelRequest, res: VercelResponse) {
  if (req.method !== 'GET') {
    res.setHeader('Content-Type', 'application/json');
    return res
      .status(405)
      .json({ error: { code: 'BAD_REQUEST', message: 'Method not allowed' } });
  }

  const clientId = apiConfig.SPOTIFY_CLIENT_ID;
  const clientSecret = apiConfig.SPOTIFY_CLIENT_SECRET;

  if (!clientId || !clientSecret) {
    // Don't spam logs in production, return graceful error
    res.setHeader('Content-Type', 'application/json');
    return res.status(503).json({
      error: {
        code: 'MISSING_CREDENTIALS',
        message: 'Spotify service temporarily unavailable',
        httpStatus: 503,
        retryable: true,
      },
    });
  }

  const credentials = Buffer.from(`${clientId}:${clientSecret}`).toString(
    'base64'
  );

  try {
    const decision = await checkAndConsume(req, 'spotify-token', 30, 60_000);
    if (!decision.allowed) {
      res.setHeader(
        'Retry-After',
        Math.ceil(decision.retryAfter / 1000).toString()
      );
      res.setHeader('Content-Type', 'application/json');
      return res
        .status(429)
        .json({
          error: { code: 'RATE_LIMITED', message: 'Too many requests' },
        });
    }

    const now = Date.now();
    if (tokenCache && now < tokenCache.expires_at - 60_000) {
      res.setHeader('Cache-Control', 'no-store');
      res.setHeader('Content-Type', 'application/json');
      return res.status(200).json({
        access_token: tokenCache.access_token,
        token_type: tokenCache.token_type,
        expires_in: Math.max(
          0,
          Math.floor((tokenCache.expires_at - now) / 1000)
        ),
      });
    }

    if (!inflight) {
      inflight = (async () => {
        const resp = await fetchWithTimeout(
          'https://accounts.spotify.com/api/token',
          {
            method: 'POST',
            headers: {
              Authorization: `Basic ${credentials}`,
              'Content-Type': 'application/x-www-form-urlencoded',
            },
            body: 'grant_type=client_credentials',
          },
          12000
        );

        if (resp.ok) {
          const json = await resp.json();
          const expires_at = Date.now() + json.expires_in * 1000;
          tokenCache = { ...json, expires_at };
          return tokenCache;
        }

        const body = await resp.text();
        const err = await errorFromResponse(resp, body);

        if (resp.status === 401 || resp.status === 400) {
          throw new AppError(
            'INVALID_CREDENTIALS',
            'Spotify rejected credentials',
            { httpStatus: 502 }
          );
        }

        throw err;
      })().finally(() => {
        inflight = null;
      });
    }

    const token = await inflight;
    res.setHeader('Cache-Control', 'no-store');
    res.setHeader('Content-Type', 'application/json');
    return res.status(200).json({
      access_token: token.access_token,
      token_type: token.token_type,
      expires_in: Math.max(
        0,
        Math.floor((token.expires_at - Date.now()) / 1000)
      ),
    });
  } catch (e: any) {
    const normalized = normalizeError(e, {
      code: 'SPOTIFY_API_ERROR',
      message: 'Spotify service temporarily unavailable',
    });
    // Return 503 for service unavailable to trigger proper fallback
    res.setHeader('Content-Type', 'application/json');
    res.status(503).json({
      error: {
        ...normalized,
        httpStatus: 503,
        retryable: true,
      },
    });
  }
}

export default apiConfig.ENABLE_IDEMPOTENCY
  ? withIdempotency(spotifyTokenHandler)
  : spotifyTokenHandler;

import type { VercelRequest, VercelResponse } from '@vercel/node';
import { withIdempotency } from '../utils/idempotency.js';
import apiConfig from './config.js';
import { AppError, normalizeError } from '../src/utils/errors.js';
import { validateYouTubeSearch } from '../shared/validators.js';
import { checkAndConsume } from '../utils/apiRateLimiter.js';

async function fetchWithTimeout(
  input: RequestInfo | URL,
  init: RequestInit = {},
  timeoutMs = 12000
): Promise<Response> {
  const controller = new AbortController();
  const id = setTimeout(() => controller.abort(), timeoutMs);
  try {
    return await fetch(input, { ...init, signal: controller.signal });
  } finally {
    clearTimeout(id);
  }
}

async function youtubeSearchHandler(req: VercelRequest, res: VercelResponse) {
  if (req.method !== 'GET') {
    res.setHeader('Content-Type', 'application/json');
    return res
      .status(405)
      .json({ error: { code: 'BAD_REQUEST', message: 'Method not allowed' } });
  }

  const apiKey = apiConfig.YOUTUBE_API_KEY;
  if (!apiKey) {
    res.setHeader('Content-Type', 'application/json');
    return res.status(503).json({
      error: {
        code: 'MISSING_CREDENTIALS',
        message: 'YouTube service temporarily unavailable',
        httpStatus: 503,
        retryable: true,
      },
    });
  }

  try {
    const decision = await checkAndConsume(req, 'youtube-search', 100, 60_000);
    if (!decision.allowed) {
      res.setHeader(
        'Retry-After',
        Math.ceil(decision.retryAfter / 1000).toString()
      );
      res.setHeader('Content-Type', 'application/json');
      return res
        .status(429)
        .json({
          error: { code: 'RATE_LIMITED', message: 'Too many requests' },
        });
    }

    const { q: query, maxResults } = validateYouTubeSearch(req.query);

    const searchUrl = new URL('https://www.googleapis.com/youtube/v3/search');
    searchUrl.searchParams.set('part', 'snippet');
    searchUrl.searchParams.set('q', query.trim());
    searchUrl.searchParams.set('type', 'video');
    searchUrl.searchParams.set('videoCategoryId', '10'); // Music category
    searchUrl.searchParams.set('videoDefinition', 'any');
    searchUrl.searchParams.set('videoEmbeddable', 'true');
    searchUrl.searchParams.set('maxResults', maxResults.toString());
    searchUrl.searchParams.set('order', 'relevance');
    searchUrl.searchParams.set('key', apiKey);

    const response = await fetchWithTimeout(searchUrl.toString(), {}, 15000);

    if (!response.ok) {
      const errorText = await response.text();
      console.error('YouTube API Error:', response.status, errorText);

      if (response.status === 403) {
        throw new AppError('QUOTA_EXCEEDED', 'YouTube API quota exceeded', {
          httpStatus: 503,
        });
      }

      if (response.status === 401) {
        throw new AppError(
          'INVALID_CREDENTIALS',
          'YouTube API key is invalid',
          { httpStatus: 502 }
        );
      }

      throw new AppError('YOUTUBE_API_ERROR', 'YouTube search failed', {
        httpStatus: response.status,
      });
    }

    const data = await response.json();

    // Filter and clean the results with guards for shape changes
    const cleanedItems = (Array.isArray(data.items) ? data.items : [])
      .filter(
        (item: any) =>
          item &&
          item.id &&
          (item.id.videoId || item.id.kind === 'youtube#video')
      )
      .map((item: any) => ({
        id: {
          videoId: item.id.videoId || item.id.videoId || null,
        },
        snippet: {
          title: item.snippet?.title ?? '',
          channelTitle: item.snippet?.channelTitle ?? '',
          description: item.snippet?.description ?? '',
          publishedAt: item.snippet?.publishedAt ?? '',
          thumbnails: item.snippet?.thumbnails ?? {},
        },
      }))
      .filter((i: any) => i.id.videoId);

    const result = {
      items: cleanedItems,
      pageInfo: {
        totalResults: data.pageInfo?.totalResults || cleanedItems.length,
        resultsPerPage: data.pageInfo?.resultsPerPage || cleanedItems.length,
      },
    };

    res.setHeader('Cache-Control', 'public, max-age=300'); // Cache for 5 minutes
    res.setHeader('Content-Type', 'application/json');
    return res.status(200).json(result);
  } catch (e: any) {
    const normalized = normalizeError(e, {
      code: 'YOUTUBE_API_ERROR',
      message: 'YouTube search temporarily unavailable',
    });

    console.error('YouTube search error:', normalized);

    res.setHeader('Content-Type', 'application/json');
    res.status(503).json({
      error: {
        ...normalized,
        httpStatus: 503,
        retryable: true,
      },
    });
  }
}

export default apiConfig.ENABLE_IDEMPOTENCY
  ? withIdempotency(youtubeSearchHandler)
  : youtubeSearchHandler;

