// --- Central Logger ---
// Wrapper for shared logger to match prior lightweight usage in this file
const Logger = {
  info: (...args: any[]) => {
    const [message, ...rest] = args;
    const data = rest.length
      ? rest.length === 1
        ? rest[0]
        : { args: rest }
      : undefined;
    logger.info('App', String(message), data);
  },
  warn: (...args: any[]) => {
    const [message, ...rest] = args;
    const data = rest.length
      ? rest.length === 1
        ? rest[0]
        : { args: rest }
      : undefined;
    logger.warn('App', String(message), data);
  },
  error: (...args: any[]) => {
    const [message, ...rest] = args;
    const err = rest.find((r: any) => r instanceof Error) ?? rest[0];
    logger.error('App', String(message), err);
  },
};

// --- State ---
interface AppState {
  user: User | null;
  savedPlaylists: Playlist[];
  recentSessions: Session[];
  currentPlaylist: Playlist | null;
  currentSession: Session | null;
  isPlaying: boolean;
  isEditingPlaylist: boolean;
  isLoading: boolean;
  error: string | null;
  showAuthModal: boolean;
  authModalMode: 'signin' | 'signup';
}

const initialState: AppState = {
  user: null, // Start without user to enable authentication
  savedPlaylists: [],
  recentSessions: [],
  currentPlaylist: null,
  currentSession: null,
  isPlaying: false,
  isEditingPlaylist: false,
  isLoading: false,
  error: null,
  showAuthModal: false,
  authModalMode: 'signin',
};

type Action =
  | { type: 'SET_USER'; payload: User | null }
  | { type: 'SET_PLAYLIST'; payload: Playlist | null }
  | { type: 'SET_SESSION'; payload: Session | null }
  | { type: 'SET_PLAYLISTS'; payload: Playlist[] }
  | { type: 'SET_SESSIONS'; payload: Session[] }
  | { type: 'SET_LOADING'; payload: boolean }
  | { type: 'SET_ERROR'; payload: string | null }
  | { type: 'SET_PLAYING'; payload: boolean }
  | { type: 'SET_EDITING'; payload: boolean }
  | {
      type: 'SHOW_AUTH_MODAL';
      payload: { show: boolean; mode?: 'signin' | 'signup' };
    };

function appReducer(state: AppState, action: Action): AppState {
  switch (action.type) {
    case 'SET_USER':
      return { ...state, user: action.payload };
    case 'SET_PLAYLIST':
      return { ...state, currentPlaylist: action.payload };
    case 'SET_SESSION':
      return { ...state, currentSession: action.payload };
    case 'SET_PLAYLISTS':
      return { ...state, savedPlaylists: action.payload };
    case 'SET_SESSIONS':
      return { ...state, recentSessions: action.payload };
    case 'SET_LOADING':
      return { ...state, isLoading: action.payload };
    case 'SET_ERROR':
      return { ...state, error: action.payload };
    case 'SET_PLAYING':
      return { ...state, isPlaying: action.payload };
    case 'SET_EDITING':
      return { ...state, isEditingPlaylist: action.payload };
    case 'SHOW_AUTH_MODAL':
      return {
        ...state,
        showAuthModal: action.payload.show,
        authModalMode: action.payload.mode || state.authModalMode,
      };
    default:
      return state;
  }
}

// --- Main AppContent ---
function AppContent() {
  const navigate = useNavigate();
  const location = useLocation();
  const { showToast } = useToast();
  const [state, dispatch] = useReducer(appReducer, initialState);
  // Save function indirection to allow debounced calls before declaration
  const saveFnRef = React.useRef<(pl: Playlist) => void>(() => {});
  const saveDebounceRef = React.useRef<number | null>(null);
  const saveCurrentPlaylistDebounced = useCallback((pl: Playlist) => {
    if (saveDebounceRef.current) {
      window.clearTimeout(saveDebounceRef.current);
    }
    saveDebounceRef.current = window.setTimeout(() => {
      try {
        saveFnRef.current?.(pl);
      } catch {}
      localStorage.setItem('last-resume-at', String(Date.now()));
    }, 500);
  }, []);

  // Spotify token
  const { isLoading: tokenLoading, fetchLazy: fetchSpotifyTokenLazy } =
    useSpotifyToken();

  // Local storage
  const [userPreferences] = useLocalStorage('user-preferences', {
    theme: 'dark',
    autoSave: true,
    notifications: true,
  });
  const [lastPlaylistId, setLastPlaylistId] = useLocalStorage<string>(
    'last-playlist-id',
    ''
  );

  const [lastRoute, setLastRoute] = useLocalStorage<string>('last-route', '/');
  const [authDismissedAt, setAuthDismissedAt] = useLocalStorage<number>(
    'auth-dismissed-at',
    0
  );

  // --- Spotify is now lazily initialized when needed as fallback ---
  // Removed automatic initialization to improve startup performance

  // Provide lazy Spotify initialization function for services
  // @ts-ignore - Function reserved for future lazy initialization
  const unused__initializeSpotifyLazy =
    useCallback(async (): Promise<boolean> => {
      try {
        const token = await fetchSpotifyTokenLazy();
        if (token) {
          spotifyService.initialize(token);
          Logger.info('Spotify service lazily initialized');
          return true;
        }
        return false;
      } catch (error) {
        Logger.error('Lazy Spotify initialization failed', error);
        return false;
      }
    }, [fetchSpotifyTokenLazy]);

  // --- Initialize App ---
  useEffect(() => {
    const initializeApp = async () => {
      dispatch({ type: 'SET_LOADING', payload: true });
      dispatch({ type: 'SET_ERROR', payload: null });

      try {
        // Check if user is already authenticated
        const { data: sessionData } = await supabase.auth.getSession();
        if (sessionData?.session?.user) {
          const supabaseUser = sessionData.session.user;
          const appUser: User = {
            id: supabaseUser.id,
            email: supabaseUser.email || '',
            name:
              supabaseUser.user_metadata?.name ||
              supabaseUser.email?.split('@')[0] ||
              'User',
            created_at: supabaseUser.created_at,
          };
          dispatch({ type: 'SET_USER', payload: appUser });
          Logger.info('User already authenticated');
        } else {
          // Set up popup timer for unauthenticated users on homepage, respect dismissal for 7 days
          if (window.location.pathname === '/') {
            const dismissedAgo = Date.now() - (authDismissedAt || 0);
            const sevenDays = 7 * 24 * 60 * 60 * 1000;
            if (dismissedAgo > sevenDays) {
              setTimeout(() => {
                dispatch({
                  type: 'SHOW_AUTH_MODAL',
                  payload: { show: true, mode: 'signup' },
                });
              }, 5000);
            }
          }
        }

        // Mock sessions (replace with Supabase)
        const mockSessions: Session[] = [
          {
            id: '1',
            name: 'Electronic Night',
            tracks: 15,
            duration: 3600,
            user_id: state.user?.id || 'guest',
            playlist_id: 'mock',
            started_at: new Date().toISOString(),
            status: 'completed' as const,
            created_at: new Date().toISOString(),
            updated_at: new Date().toISOString(),
          },
        ];
        dispatch({ type: 'SET_SESSIONS', payload: mockSessions });
        Logger.info('MagicDJ initialized');
      } catch (err) {
        Logger.error('Init error', err);
        dispatch({
          type: 'SET_ERROR',
          payload: 'Failed to load application data',
        });
        showToast('Failed to load application data', 'error');
      } finally {
        dispatch({ type: 'SET_LOADING', payload: false });
      }
    };
    initializeApp();

    // Listen for auth state changes
    const { data: authListener } = supabase.auth.onAuthStateChange(
      (event, session) => {
        if (event === 'SIGNED_IN' && session?.user) {
          const supabaseUser = session.user;
          const appUser: User = {
            id: supabaseUser.id,
            email: supabaseUser.email || '',
            name:
              supabaseUser.user_metadata?.name ||
              supabaseUser.email?.split('@')[0] ||
              'User',
            created_at: supabaseUser.created_at,
          };
          dispatch({ type: 'SET_USER', payload: appUser });
          dispatch({ type: 'SHOW_AUTH_MODAL', payload: { show: false } });
          Logger.info('User signed in');
        } else if (event === 'SIGNED_OUT') {
          dispatch({ type: 'SET_USER', payload: null });
          Logger.info('User signed out');
        }
      }
    );

    return () => {
      authListener.subscription.unsubscribe();
    };
  }, [authDismissedAt]);

  // Persist last route for resume
  useEffect(() => {
    setLastRoute(location.pathname + location.search);
  }, [location.pathname, location.search, setLastRoute]);

  // Initialize Spotify token on player route
  useEffect(() => {
    if (location.pathname.startsWith('/play')) {
      fetchSpotifyTokenLazy().catch(() => {});
      localStorage.setItem('last-resume-at', String(Date.now()));
    }
  }, [location.pathname, fetchSpotifyTokenLazy]);

  // Optional resume: only when user explicitly enables it (prevents home → create jump)
  useEffect(() => {
    if (location.pathname !== '/') return;

    const autoResumeEnabled =
      localStorage.getItem('auto-resume-enabled') === 'true';
    if (!autoResumeEnabled) return; // disabled by default

    const last = lastRoute || '/';
    const within12h =
      Date.now() - (Number(localStorage.getItem('last-resume-at')) || 0) <
      12 * 60 * 60 * 1000;
    const canResume = state.currentPlaylist || lastPlaylistId;
    if (
      canResume &&
      (last.startsWith('/create') ||
        last.startsWith('/edit') ||
        last.startsWith('/play')) &&
      within12h
    ) {
      showToast('Resuming where you left off', 'info');
      navigate(last);
    }
  }, [
    location.pathname,
    lastRoute,
    state.currentPlaylist,
    lastPlaylistId,
    navigate,
    showToast,
  ]);

  // --- Load user data ---
  const loadUserData = useCallback(
    async (userId: string) => {
      if (!userId) {
        Logger.error('loadUserData', 'No user ID provided');
        return;
      }

      try {
        Logger.info('loadUserData', 'Loading playlists for user', { userId });
        const playlists = await supabasePlaylistService.getPlaylists(userId);

        // Ensure playlists is an array and all have required properties
        const safePlaylists: Playlist[] = Array.isArray(playlists)
          ? (playlists as Playlist[]).filter(
              (p): p is Playlist => !!p && typeof p.id === 'string' && !!p.name
            )
          : [];
        dispatch({ type: 'SET_PLAYLISTS', payload: safePlaylists });

        // Restore last playlist with additional safety checks
        if (safePlaylists.length > 0) {
          const candidate = lastPlaylistId
            ? safePlaylists.find((p: Playlist) => p && p.id === lastPlaylistId)
            : null;

          const playlistToRestore =
            candidate ||
            safePlaylists
              .filter((p: Playlist) => p && p.updated_at) // Filter out invalid playlists
              .sort(
                (a: Playlist, b: Playlist) =>
                  new Date(b.updated_at || 0).getTime() -
                  new Date(a.updated_at || 0).getTime()
              )[0];

          if (
            playlistToRestore &&
            playlistToRestore.id &&
            playlistToRestore.name
          ) {
            dispatch({ type: 'SET_PLAYLIST', payload: playlistToRestore });
            setLastPlaylistId(playlistToRestore.id);
            Logger.info('Restored playlist', playlistToRestore.name);
            showToast(
              `Restored playlist: ${playlistToRestore.name}`,
              'success'
            );
          }
        }
      } catch (err) {
        Logger.error('Load user data error', err);

        // Graceful fallback - don't crash the app
        dispatch({ type: 'SET_PLAYLISTS', payload: [] });

        const errorMessage =
          err instanceof Error ? err.message : 'Unknown error';
        if (
          errorMessage.includes('network') ||
          errorMessage.includes('fetch')
        ) {
          showToast('Network error - working offline', 'warning');
        } else {
          showToast('Failed to load playlists - working offline', 'warning');
        }
      }
    },
    [setLastPlaylistId, showToast]
  );

  // Separate effect for user data loading
  useEffect(() => {
    if (state.user?.id) {
      loadUserData(state.user.id).catch(err => {
        Logger.error('Load user data error', err);
        showToast('Failed to load user data', 'error');
      });
    }
  }, [state.user?.id]); // Remove function dependencies to prevent infinite loop

  // --- Playlist save handler ---
  const saveCurrentPlaylist = useCallback(
    async (playlist: Playlist) => {
      if (!playlist || !playlist.id) {
        Logger.error(
          'saveCurrentPlaylist',
          'Invalid playlist provided',
          playlist
        );
        return;
      }

      if (!state.user || !state.user.id) {
        Logger.warn('saveCurrentPlaylist', 'No user logged in, skipping save');
        return;
      }

      if (!userPreferences.autoSave) {
        Logger.info('saveCurrentPlaylist', 'Auto-save disabled, skipping save');
        return;
      }

      try {
        Logger.info('saveCurrentPlaylist', 'Saving playlist', {
          playlistId: playlist.id,
          userId: state.user.id,
        });

        const saved = await supabasePlaylistService.savePlaylist(
          playlist,
          state.user.id
        );

        if (saved && saved.id) {
          setLastPlaylistId(playlist.id);

          // Safely update playlists array
          const updatedPlaylists = state.savedPlaylists.map(p =>
            p && p.id === playlist.id ? saved : p
          );

          // Add playlist if it's new
          if (!state.savedPlaylists.find(p => p && p.id === playlist.id)) {
            updatedPlaylists.push(saved);
          }

          // Ensure updatedPlaylists is filtered to only valid Playlist objects with defined id
          dispatch({
            type: 'SET_PLAYLISTS',
            payload: updatedPlaylists.filter(
              (p): p is Playlist => !!p && typeof p.id === 'string'
            ),
          });

          if (userPreferences.notifications) {
            showToast('Playlist saved', 'success', { dedupe: true });
          }
        } else {
          throw new Error('Invalid saved playlist response');
        }
      } catch (err) {
        Logger.error('Save playlist error', err);

        const errorMessage =
          err instanceof Error ? err.message : 'Unknown error';
        if (
          errorMessage.includes('network') ||
          errorMessage.includes('fetch')
        ) {
          showToast('Network error - playlist saved locally', 'warning');
        } else {
          showToast('Failed to save playlist to cloud', 'error');
        }
      }
    },
    [
      state.user,
      state.savedPlaylists,
      userPreferences,
      setLastPlaylistId,
      showToast,
    ]
  );

  // Bind latest save function to ref used by debounced saver
  useEffect(() => {
    saveFnRef.current = saveCurrentPlaylist;
  }, [saveCurrentPlaylist]);

  // --- Auth handlers ---
  const handleAuthClick = (isSignUp: boolean) => {
    dispatch({
      type: 'SHOW_AUTH_MODAL',
      payload: { show: true, mode: isSignUp ? 'signup' : 'signin' },
    });
  };

  const handleAuthModalClose = () => {
    dispatch({ type: 'SHOW_AUTH_MODAL', payload: { show: false } });
    setAuthDismissedAt(Date.now());
  };

  // --- Playlist handlers ---
  const handlePlaylistGenerated = (pl: Playlist) => {
    dispatch({ type: 'SET_PLAYLIST', payload: pl });
    dispatch({ type: 'SET_EDITING', payload: true });
    saveCurrentPlaylist(pl);
    showToast('Playlist generated!', 'success');
    navigate('/edit');
  };

  const handlePlaylistEdited = (pl: Playlist) => {
    dispatch({ type: 'SET_PLAYLIST', payload: pl });
    dispatch({ type: 'SET_EDITING', payload: false });
    saveCurrentPlaylist(pl);
    navigate('/play');
  };

  const handlePlaylistSelect = (pl: Playlist) => {
    dispatch({ type: 'SET_PLAYLIST', payload: pl });
    dispatch({ type: 'SET_EDITING', payload: true });
    setLastPlaylistId(pl.id);
    navigate('/edit');
  };

  const handleTrackReorder = (fromIndex: number, toIndex: number) => {
    if (!state.currentPlaylist || !state.currentPlaylist.tracks) {
      Logger.error('handleTrackReorder', 'No playlist or tracks available');
      showToast('Cannot reorder tracks: No playlist selected', 'error');
      return;
    }

    // Validate indices
    if (
      fromIndex < 0 ||
      fromIndex >= state.currentPlaylist.tracks.length ||
      toIndex < 0 ||
      toIndex >= state.currentPlaylist.tracks.length
    ) {
      Logger.error('handleTrackReorder', 'Invalid track indices', {
        fromIndex,
        toIndex,
        trackCount: state.currentPlaylist.tracks.length,
      });
      showToast('Cannot reorder tracks: Invalid track position', 'error');
      return;
    }

    try {
      const newTracks = [...state.currentPlaylist.tracks];
      const [movedTrack] = newTracks.splice(fromIndex, 1);
      newTracks.splice(toIndex, 0, movedTrack);

      const updatedPlaylist = {
        ...state.currentPlaylist,
        tracks: newTracks,
        updated_at: new Date().toISOString(),
      };
      dispatch({ type: 'SET_PLAYLIST', payload: updatedPlaylist });
      saveCurrentPlaylistDebounced(updatedPlaylist);
    } catch (error) {
      Logger.error('handleTrackReorder', 'Failed to reorder tracks', error);
      showToast('Failed to reorder tracks', 'error');
    }
  };

  const handleTrackRemove = (index: number) => {
    if (!state.currentPlaylist || !state.currentPlaylist.tracks) {
      Logger.error('handleTrackRemove', 'No playlist or tracks available');
      showToast('Cannot remove track: No playlist selected', 'error');
      return;
    }

    // Validate index
    if (index < 0 || index >= state.currentPlaylist.tracks.length) {
      Logger.error('handleTrackRemove', 'Invalid track index', {
        index,
        trackCount: state.currentPlaylist.tracks.length,
      });
      showToast('Cannot remove track: Invalid track position', 'error');
      return;
    }

    try {
      const newTracks = state.currentPlaylist.tracks.filter(
        (_, i) => i !== index
      );
      const updatedPlaylist = {
        ...state.currentPlaylist,
        tracks: newTracks,
        updated_at: new Date().toISOString(),
      };
      dispatch({ type: 'SET_PLAYLIST', payload: updatedPlaylist });
      saveCurrentPlaylistDebounced(updatedPlaylist);
      showToast('Track removed successfully', 'success');
    } catch (error) {
      Logger.error('handleTrackRemove', 'Failed to remove track', error);
      showToast('Failed to remove track', 'error');
    }
  };

  const handlePlaylistUpdate = (playlist: Playlist) => {
    dispatch({ type: 'SET_PLAYLIST', payload: playlist });
    saveCurrentPlaylistDebounced(playlist);
  };

  // --- Session handlers ---
  const handleSessionEnd = () => {
    dispatch({ type: 'SET_SESSION', payload: null });
    dispatch({ type: 'SET_PLAYING', payload: false });
    navigate('/');
    showToast('Session ended', 'info');
  };

  // --- Render states ---
  if (state.isLoading || tokenLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <LoadingSpinner size="large" text="Loading The New Magic DJ..." />
      </div>
    );
  }

  // Authentication removed - direct access to app

  return (
    <div className="min-h-screen gradient-bg-primary">
      <Navigation
        user={state.user}
        hasPlaylist={!!state.currentPlaylist}
        hasSession={!!state.currentSession}
        onAuthClick={handleAuthClick}
      />

      {state.error && (
        <div className="mx-4 mt-4">
          <div className="glass-card p-4 bg-red-500/10 border-red-500/20">
            <div className="flex items-center justify-between">
              <div className="flex items-center space-x-3">
                <div className="w-8 h-8 bg-red-500/20 rounded-full flex items-center justify-center">
                  <span className="text-red-400 text-sm">⚠</span>
                </div>
                <div>
                  <p className="text-red-400 font-medium">
                    Something went wrong
                  </p>
                  <p className="text-red-300 text-sm">{state.error}</p>
                </div>
              </div>
              <button
                onClick={() => dispatch({ type: 'SET_ERROR', payload: null })}
                className="glass-button w-8 h-8 flex items-center justify-center text-red-400 hover:bg-red-500/20"
                aria-label="Dismiss error"
              >
                ✕
              </button>
            </div>
          </div>
        </div>
      )}

      <Suspense
        fallback={
          <div className="min-h-screen flex items-center justify-center gradient-bg-primary">
            <LoadingSpinner
              variant="futuristic"
              size="large"
              text="Loading MagicDJ..."
              subtext="Preparing your AI studio"
            />
          </div>
        }
      >
        <Routes>
          <Route
            path="/"
            element={
              <ErrorBoundary>
                <LandingPage
                  onStartMixing={() => navigate('/create')}
                  onLibraryAccess={() => navigate('/library')}
                  recentSessions={state.recentSessions}
                />
              </ErrorBoundary>
            }
          />

          <Route
            path="/create"
            element={
              <ErrorBoundary>
                <MagicStudio
                  user={state.user}
                  onPlaylistGenerated={handlePlaylistGenerated}
                  onBack={() => navigate('/')}
                  onLibraryAccess={() => navigate('/library')}
                  recentSessions={state.recentSessions}
                />
              </ErrorBoundary>
            }
          />

          <Route
            path="/edit"
            element={
              <ErrorBoundary>
                {state.currentPlaylist ? (
                  <PlaylistEditor
                    playlist={state.currentPlaylist}
                    currentTrackIndex={0}
                    isPlaying={state.isPlaying}
                    onTrackSelect={() => {}}
                    onTrackRemove={handleTrackRemove}
                    onTrackReorder={handleTrackReorder}
                    onPlaylistUpdate={handlePlaylistUpdate}
                    onSendToPlayer={() =>
                      state.currentPlaylist &&
                      handlePlaylistEdited(state.currentPlaylist)
                    }
                    onSavePlaylist={() =>
                      state.currentPlaylist &&
                      saveCurrentPlaylist(state.currentPlaylist)
                    }
                  />
                ) : (
                  <Navigate to="/create" replace />
                )}
              </ErrorBoundary>
            }
          />

          <Route
            path="/play"
            element={
              <ErrorBoundary>
                {state.currentPlaylist ? (
                  <ProfessionalMagicPlayer
                    playlist={state.currentPlaylist}
                    session={state.currentSession}
                    isPlaying={state.isPlaying}
                    onPlayPause={async playing => {
                      dispatch({ type: 'SET_PLAYING', payload: playing });
                      // best-effort event
                      logEvent(playing ? 'player.play' : 'player.pause');
                    }}
                    onSessionEnd={handleSessionEnd}
                    onBack={() => navigate('/edit')}
                    onSavePlaylist={saveCurrentPlaylist}
                  />
                ) : (
                  <Navigate to="/create" replace />
                )}
              </ErrorBoundary>
            }
          />

          <Route
            path="/library"
            element={
              <ErrorBoundary>
                <LibraryProfile
                  user={state.user}
                  savedPlaylists={state.savedPlaylists}
                  onBack={() => window.history.back()}
                  onPlaylistSelect={handlePlaylistSelect}
                  onCreateNew={() => navigate('/create')}
                />
              </ErrorBoundary>
            }
          />

          <Route
            path="/analytics"
            element={
              <ErrorBoundary>
                {state.currentPlaylist && state.currentSession ? (
                  <AnalyticsExport
                    playlist={state.currentPlaylist}
                    session={state.currentSession}
                    onBack={() => window.history.back()}
                    onSaveToLibrary={saveCurrentPlaylist}
                    onEditAgain={() => navigate('/edit')}
                  />
                ) : (
                  <Navigate to="/" replace />
                )}
              </ErrorBoundary>
            }
          />

          <Route path="*" element={<NotFound />} />
        </Routes>
      </Suspense>

      {/* Auth Modal */}
      <AuthModal
        isOpen={state.showAuthModal}
        onClose={handleAuthModalClose}
        initialMode={state.authModalMode}
      />
    </div>
  );
}

// --- App wrapper ---
function App() {
  return (
    <ErrorBoundary>
      <Router>
        <AppContent />
      </Router>
    </ErrorBoundary>
  );
}

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { AlertTriangle, Play, Pause, Volume2, Headphones } from 'lucide-react';
import { logger } from '../utils/logger';

interface AudioDebugInfo {
  audioContext: {
    state: string;
    sampleRate: number;
    supported: boolean;
  };
  htmlAudio: {
    supported: boolean;
    canPlayMP3: boolean;
    canPlayWAV: boolean;
    canPlayAAC: boolean;
  };
  permissions: {
    autoplay: string;
    microphone: string;
  };
  currentAudio: {
    src: string;
    readyState: number;
    networkState: number;
    error: string | null;
    duration: number;
    volume: number;
  } | null;
}

interface AudioDebuggerProps {
  testAudioUrl?: string;
  className?: string;
}

const AudioDebugger: React.FC<AudioDebuggerProps> = ({
  testAudioUrl = '',
  className = '',
}) => {
  const [debugInfo, setDebugInfo] = useState<AudioDebugInfo | null>(null);
  const [isTestPlaying, setIsTestPlaying] = useState(false);
  const [testError, setTestError] = useState<string | null>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);

  // Initialize debug info
  useEffect(() => {
    const checkAudioSupport = async () => {
      const info: AudioDebugInfo = {
        audioContext: {
          state: 'unknown',
          sampleRate: 0,
          supported: false,
        },
        htmlAudio: {
          supported: false,
          canPlayMP3: false,
          canPlayWAV: false,
          canPlayAAC: false,
        },
        permissions: {
          autoplay: 'unknown',
          microphone: 'unknown',
        },
        currentAudio: null,
      };

      // Check AudioContext support
      try {
        const AudioContextClass =
          window.AudioContext || (window as any).webkitAudioContext;
        if (AudioContextClass) {
          audioContextRef.current = new AudioContextClass();
          info.audioContext = {
            state: audioContextRef.current.state,
            sampleRate: audioContextRef.current.sampleRate,
            supported: true,
          };
        }
      } catch (error) {
        logger.warn('AudioDebugger', 'AudioContext not supported', error);
      }

      // Check HTML Audio support
      try {
        const testAudio = new Audio();
        info.htmlAudio = {
          supported: true,
          canPlayMP3: testAudio.canPlayType('audio/mpeg') !== '',
          canPlayWAV: testAudio.canPlayType('audio/wav') !== '',
          canPlayAAC: testAudio.canPlayType('audio/aac') !== '',
        };
      } catch (error) {
        logger.warn('AudioDebugger', 'HTML Audio not supported', error);
      }

      // Check autoplay policy
      try {
        const testAudio = new Audio();
        testAudio.volume = 0;
        const playPromise = testAudio.play();
        if (playPromise) {
          await playPromise;
          info.permissions.autoplay = 'allowed';
          testAudio.pause();
        }
      } catch (error: any) {
        if (error.name === 'NotAllowedError') {
          info.permissions.autoplay = 'blocked';
        } else {
          info.permissions.autoplay = 'unknown';
        }
      }

      // Check microphone permission
      try {
        const stream = await navigator.mediaDevices.getUserMedia({
          audio: true,
        });
        info.permissions.microphone = 'granted';
        stream.getTracks().forEach(track => track.stop());
      } catch (error: any) {
        if (error.name === 'NotAllowedError') {
          info.permissions.microphone = 'denied';
        } else {
          info.permissions.microphone = 'unknown';
        }
      }

      setDebugInfo(info);
    };

    checkAudioSupport();
  }, []);

  // Update current audio info
  useEffect(() => {
    if (!audioRef.current || !debugInfo) return;

    const updateAudioInfo = () => {
      const audio = audioRef.current!;
      setDebugInfo(prev =>
        prev
          ? {
              ...prev,
              currentAudio: {
                src: audio.src,
                readyState: audio.readyState,
                networkState: audio.networkState,
                error: audio.error?.message || null,
                duration: audio.duration || 0,
                volume: audio.volume,
              },
            }
          : prev
      );
    };

    const audio = audioRef.current;
    const events = [
      'loadstart',
      'loadedmetadata',
      'canplay',
      'canplaythrough',
      'error',
      'stalled',
    ];

    events.forEach(event => {
      audio.addEventListener(event, updateAudioInfo);
    });

    updateAudioInfo();

    return () => {
      events.forEach(event => {
        audio.removeEventListener(event, updateAudioInfo);
      });
    };
  }, [debugInfo, testAudioUrl]);

  const handleTestPlay = async () => {
    if (!audioRef.current) return;

    try {
      setTestError(null);

      if (isTestPlaying) {
        audioRef.current.pause();
        setIsTestPlaying(false);
      } else {
        // Resume AudioContext if needed
        if (audioContextRef.current?.state === 'suspended') {
          await audioContextRef.current.resume();
        }

        await audioRef.current.play();
        setIsTestPlaying(true);
      }
    } catch (error: any) {
      setTestError(error.message);
      logger.error('AudioDebugger', 'Test playback failed', error);
    }
  };

  const generateTestTone = () => {
    try {
      const audioContext =
        audioContextRef.current ||
        new (window.AudioContext || (window as any).webkitAudioContext)();
      const oscillator = audioContext.createOscillator();
      const gainNode = audioContext.createGain();

      oscillator.connect(gainNode);
      gainNode.connect(audioContext.destination);

      oscillator.frequency.setValueAtTime(440, audioContext.currentTime); // A4 note
      gainNode.gain.setValueAtTime(0.1, audioContext.currentTime);
      gainNode.gain.exponentialRampToValueAtTime(
        0.01,
        audioContext.currentTime + 1
      );

      oscillator.start(audioContext.currentTime);
      oscillator.stop(audioContext.currentTime + 1);

      logger.info('AudioDebugger', 'Test tone generated');
    } catch (error) {
      logger.error('AudioDebugger', 'Failed to generate test tone', error);
      setTestError('Failed to generate test tone');
    }
  };

  if (!debugInfo) {
    return (
      <div className={`glass-card p-4 ${className}`}>
        <div className="animate-pulse">Loading audio diagnostics...</div>
      </div>
    );
  }

  const getStatusColor = (condition: boolean) =>
    condition ? 'text-green-400' : 'text-red-400';
  const getReadyStateText = (state: number) => {
    const states = [
      'HAVE_NOTHING',
      'HAVE_METADATA',
      'HAVE_CURRENT_DATA',
      'HAVE_FUTURE_DATA',
      'HAVE_ENOUGH_DATA',
    ];
    return states[state] || 'UNKNOWN';
  };

  return (
    <div className={`glass-card p-6 space-y-6 ${className}`}>
      <div className="flex items-center space-x-3 border-b border-glass pb-4">
        <Headphones className="w-6 h-6 text-cyan-400" />
        <h3 className="text-xl font-bold text-white font-orbitron">
          AUDIO DIAGNOSTICS
        </h3>
      </div>

      {/* AudioContext Status */}
      <div className="space-y-2">
        <h4 className="text-lg font-semibold text-cyan-400 font-orbitron">
          AudioContext
        </h4>
        <div className="grid grid-cols-2 gap-4 text-sm">
          <div className="flex justify-between">
            <span className="text-slate-400">Supported:</span>
            <span className={getStatusColor(debugInfo.audioContext.supported)}>
              {debugInfo.audioContext.supported ? 'YES' : 'NO'}
            </span>
          </div>
          <div className="flex justify-between">
            <span className="text-slate-400">State:</span>
            <span className="text-white">{debugInfo.audioContext.state}</span>
          </div>
          <div className="flex justify-between">
            <span className="text-slate-400">Sample Rate:</span>
            <span className="text-white">
              {debugInfo.audioContext.sampleRate} Hz
            </span>
          </div>
        </div>
      </div>

      {/* HTML Audio Support */}
      <div className="space-y-2">
        <h4 className="text-lg font-semibold text-fuchsia-400 font-orbitron">
          HTML Audio
        </h4>
        <div className="grid grid-cols-2 gap-4 text-sm">
          <div className="flex justify-between">
            <span className="text-slate-400">Supported:</span>
            <span className={getStatusColor(debugInfo.htmlAudio.supported)}>
              {debugInfo.htmlAudio.supported ? 'YES' : 'NO'}
            </span>
          </div>
          <div className="flex justify-between">
            <span className="text-slate-400">MP3:</span>
            <span className={getStatusColor(debugInfo.htmlAudio.canPlayMP3)}>
              {debugInfo.htmlAudio.canPlayMP3 ? 'YES' : 'NO'}
            </span>
          </div>
          <div className="flex justify-between">
            <span className="text-slate-400">WAV:</span>
            <span className={getStatusColor(debugInfo.htmlAudio.canPlayWAV)}>
              {debugInfo.htmlAudio.canPlayWAV ? 'YES' : 'NO'}
            </span>
          </div>
          <div className="flex justify-between">
            <span className="text-slate-400">AAC:</span>
            <span className={getStatusColor(debugInfo.htmlAudio.canPlayAAC)}>
