          return (
            <div
              key={index}
              className={`glass-card p-8 hover-lift group h-96 flex flex-col justify-between transition-all duration-500 cursor-pointer ${
                isActive
                  ? 'shadow-neon-cyan scale-105'
                  : 'hover:shadow-neon-pink'
              }`}
              role="article"
              aria-labelledby={`feature-${index}-title`}
              onMouseEnter={() => setActiveFeature(index)}
              onMouseLeave={() => setActiveFeature(null)}
              onClick={() => setActiveFeature(isActive ? null : index)}
            >
              <div className="flex flex-col items-center text-center">
                <div
                  className={`w-20 h-20 gradient-bg-secondary rounded-xl flex items-center justify-center mb-6 transition-all duration-500 ${
                    isActive
                      ? 'scale-125 shadow-neon-cyan rotate-12'
                      : 'group-hover:scale-110 group-hover:shadow-neon-pink'
                  }`}
                >
                  <Icon className="w-10 h-10 text-white" />
                </div>

                <h3
                  id={`feature-${index}-title`}
                  className="text-xl font-bold text-white mb-4 font-orbitron min-h-[3rem] flex items-center"
                >
                  {feature.title}
                </h3>

                {feature.highlight && (
                  <span className="inline-block px-3 py-1 bg-cyan-500/20 text-cyan-400 text-xs font-semibold rounded-full mb-4 border border-cyan-500/30">
                    {feature.highlight}
                  </span>
                )}
              </div>

              <p
                className={`text-gray-400 leading-relaxed font-inter text-center transition-all duration-300 ${
                  isActive ? 'text-gray-300' : ''
                }`}
              >
                {feature.description}
              </p>
            </div>
          );
        })}
      </div>
    </section>
  );
};

