  user,
  onPlaylistGenerated,
  onBack,
  onLibraryAccess,
  recentSessions = [],
}) => {
  const [activeMode, setActiveMode] = useState<'match' | 'set' | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [progress, setProgress] = useState(0);
  const [statusMessage, setStatusMessage] = useState('');
  const [showRecentSessions, setShowRecentSessions] = useState(false);
  const [selectedVibe, setSelectedVibe] = useState<string>('');
  const [selectedEnergy, setSelectedEnergy] = useState<
    'low' | 'medium' | 'high' | ''
  >('');
  const [trackCount, setTrackCount] = useState<number>(10);
  const [uiError, setUiError] = useState<string>('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Advanced recognition state
  const [isRecording, setIsRecording] = useState(false);
  const [recordingTime, setRecordingTime] = useState(0);
  const [audioFeatures, setAudioFeatures] =
    useState<AdvancedAudioFeatures | null>(null);
  const [realTimeAnalysis, setRealTimeAnalysis] = useState<any>(null);
  const recordingIntervalRef = useRef<number>();
  const analysisIntervalRef = useRef<number>();

  // Prefill from URL query params (?vibe=House&energy=high)
  useEffect(() => {
    try {
      const params = new URLSearchParams(window.location.search);
      const vibeParam = params.get('vibe');
      const energyParam = params.get('energy');
      if (vibeParam) {
        const canonical = ['Electronic', 'Hip-Hop', 'House', 'Techno'].find(
          v => v.toLowerCase() === vibeParam.toLowerCase()
        );
        if (canonical) setSelectedVibe(canonical);
      }
      if (energyParam) {
        const e = ['low', 'medium', 'high'].find(
          x => x === energyParam.toLowerCase()
        ) as 'low' | 'medium' | 'high' | undefined;
        if (e) setSelectedEnergy(e);
      }
      if (vibeParam && energyParam) {
        const canonical = ['Electronic', 'Hip-Hop', 'House', 'Techno'].find(
          v => v.toLowerCase() === vibeParam.toLowerCase()
        );
        const e = ['low', 'medium', 'high'].find(
          x => x === energyParam.toLowerCase()
        ) as 'low' | 'medium' | 'high' | undefined;
        if (canonical && e) {
          handleMagicSet(canonical, e);
        }
      }
    } catch {}
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const vibes = [
    {
      name: 'Electronic',
      icon: Zap,
      color: 'neon-green',
      description: 'Synth-heavy electronic beats',
    },
    {
      name: 'Hip-Hop',
      icon: Mic,
      color: 'neon-purple',
      description: 'Urban rhythms and rap flows',
    },
    {
      name: 'House',
      icon: Disc,
      color: 'neon-blue',
      description: 'Four-on-the-floor dance music',
    },
    {
      name: 'Techno',
      icon: Radio,
      color: 'neon-orange',
      description: 'Industrial electronic sounds',
    },
  ];

  const energyLevels = [
    {
      level: 'low',
      label: 'Chill',
      color: 'neon-blue',
      description: 'Relaxed and ambient',
    },
    {
      level: 'medium',
      label: 'Groove',
      color: 'neon-green',
      description: 'Steady and rhythmic',
    },
    {
      level: 'high',
      label: 'Peak',
      color: 'neon-purple',
      description: 'High energy and intense',
    },
  ];

  // Quick generate handler (streamlined UX)
  const handleQuickGenerate = async () => {
    try {
      setUiError('');
      if (!selectedVibe || !selectedEnergy) {
        setUiError('Pick a vibe and an energy level to get started.');
        return;
      }
      setIsProcessing(true);
      setStatusMessage('Summoning your Magic Set...');
      setProgress(20);
      const playlist = await simplePlaylistService.generateMagicSetPlaylist({
        vibe: selectedVibe as any,
        energyLevel: selectedEnergy as any,
        userId: user?.id,
      });
      // Trim to desired length if API returned different count
      if (
        Array.isArray(playlist.tracks) &&
        playlist.tracks.length > trackCount
      ) {
        playlist.tracks = playlist.tracks.slice(0, trackCount);
      }
      onPlaylistGenerated(playlist);
    } catch (e: any) {
      setUiError(
        e?.message || 'Failed to generate playlist. Please try again.'
      );
    } finally {
      setIsProcessing(false);
      setProgress(0);
      setStatusMessage('');
    }
  };

  const handleMagicMatch = async (source: 'mic' | 'file' | 'stream') => {
    logger.info('MagicStudio', `Starting MagicMatch with source: ${source}`);
    setActiveMode('match');
    setIsProcessing(true);
    setProgress(0);
    setStatusMessage('Initializing audio capture...');

    try {
      let fingerprint = '';

      if (source === 'mic') {
        setStatusMessage('Listening via microphone...');
        setProgress(20);

        try {
          await audioProcessingService.startMicrophoneCapture();
          const result =
            await audioProcessingService.processAudioFromMicrophone(8000);
          fingerprint = result.fingerprint;
          setStatusMessage(
            `Audio captured (${Math.round(result.confidence * 100)}% confidence)`
          );
        } catch (error) {
          logger.warn(
            'MagicStudio',
            'Microphone access failed, using mock data',
            error
          );
          fingerprint = 'mock_mic_' + Date.now().toString(16);
          setStatusMessage('Audio captured (simulated)');
        }
        setProgress(40);
      } else if (source === 'file') {
        return;
      } else if (source === 'stream') {
        setStatusMessage('Capturing from audio stream...');
        setProgress(20);

        await new Promise(resolve => setTimeout(resolve, 2000));
        fingerprint = 'stream_' + Date.now().toString(16);

        setStatusMessage('Stream audio captured');
        setProgress(40);
      }

      const steps = [
        'Analyzing frequency patterns...',
        'Generating audio fingerprint...',
        'Querying music database...',
        'Searching recognition services...',
        'Creating AI-curated playlist...',
      ];

      for (let i = 0; i < steps.length; i++) {
        setStatusMessage(steps[i]);
        setProgress(40 + ((i + 1) / steps.length) * 60);
        await new Promise(resolve => setTimeout(resolve, 800));
      }

      try {
        const playlist = await simplePlaylistService.generateMagicMatchPlaylist(
          {
            fingerprint,
            userId: user?.id,
          }
        );
        logger.info(
          'MagicStudio',
          'MagicMatch playlist generated successfully',
          {
            trackCount: playlist.tracks.length,
            duration: playlist.total_duration,
          }
        );
        onPlaylistGenerated(playlist);
      } catch (error) {
        logger.error(
          'MagicStudio',
          'Failed to generate MagicMatch playlist',
          error
        );
        setStatusMessage(
          'Failed to generate playlist. Please check your API configuration.'
        );
        setTimeout(() => {
          setIsProcessing(false);
          setActiveMode(null);
        }, 2000);
        return;
      }
    } catch (error) {
      logger.error('MagicStudio', 'MagicMatch recognition failed', error);
      setStatusMessage(
        'Recognition failed. Please try again or check your microphone permissions.'
      );
      setProgress(80);

      setTimeout(() => {
        setIsProcessing(false);
        setActiveMode(null);
      }, 2000);
      return;
    } finally {
      setIsProcessing(false);
      setActiveMode(null);
      audioProcessingService.stopMicrophoneCapture();
    }
  };

  // Advanced recording functions
  const startAdvancedRecording = async () => {
    try {
      setIsRecording(true);
      setRecordingTime(0);
      setAudioFeatures(null);
      setStatusMessage('Starting advanced audio capture...');

      await advancedAudioService.initializeCapture({
        duration: 10000,
        sampleRate: 44100,
        channels: 1,
      });

      // Start recording timer
      recordingIntervalRef.current = window.setInterval(() => {
        setRecordingTime(prev => prev + 0.1);
      }, 100);

      // Start real-time analysis updates
      analysisIntervalRef.current = window.setInterval(() => {
        const analysis = advancedAudioService.getRealTimeAnalysis();
        if (analysis) {
          setRealTimeAnalysis(analysis);
        }
      }, 100);

      setStatusMessage('Recording... Click stop when ready');
      logger.info('MagicStudio', 'Advanced recording started');
    } catch (error) {
      logger.error(
        'MagicStudio',
        'Failed to start advanced recording',
        error
      );
      setStatusMessage(
        'Failed to start recording. Check microphone permissions.'
      );
      setIsRecording(false);
    }
  };

  const stopAdvancedRecording = async () => {
    try {
      setStatusMessage('Processing audio...');

      // Clear intervals
      if (recordingIntervalRef.current) {
        clearInterval(recordingIntervalRef.current);
      }
      if (analysisIntervalRef.current) {
        clearInterval(analysisIntervalRef.current);
      }

      // Process the recorded audio
      const result = await advancedAudioService.captureAndAnalyze(
        recordingTime * 1000
      );

      // Stop capture
      await advancedAudioService.stopCapture();

      // Update state with results
      setAudioFeatures(result.features || null);

      setIsRecording(false);
      setStatusMessage('Audio analysis complete!');

      logger.info('MagicStudio', 'Advanced recording completed', {
        duration: recordingTime,
        confidence: result.confidence,
        bpm: result.features?.bpm,
        key: result.features?.key,
        genre: result.features?.genre,
      });
    } catch (error) {
      logger.error('MagicStudio', 'Failed to process recording', error);
      setStatusMessage('Processing failed. Please try again.');
      setIsRecording(false);
    }
  };

  const generatePlaylistFromFeatures = async () => {
    if (!audioFeatures) return;

    setIsProcessing(true);
    setProgress(0);
    setStatusMessage('Generating playlist from audio analysis...');

    try {
      const playlist = await simplePlaylistService.generateMagicMatchPlaylist({
        fingerprint: JSON.stringify(audioFeatures),
        userId: user?.id,
      });

      setProgress(100);
      setStatusMessage('Playlist generated successfully!');

      onPlaylistGenerated(playlist);

      logger.info('MagicStudio', 'Playlist generated from advanced features', {
        trackCount: playlist.tracks.length,
        bpm: audioFeatures.bpm,
        key: audioFeatures.key,
        genre: audioFeatures.genre,
      });
    } catch (error) {
      logger.error(
        'MagicStudio',
        'Failed to generate playlist from features',
        error
      );
      setStatusMessage('Playlist generation failed. Please try again.');
    } finally {
      setIsProcessing(false);
    }
  };

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      if (recordingIntervalRef.current) {
        clearInterval(recordingIntervalRef.current);
      }
      if (analysisIntervalRef.current) {
        clearInterval(analysisIntervalRef.current);
      }
      advancedAudioService.stopCapture().catch(() => {});
    };
  }, []);

  const handleMagicSet = async (
    vibe: string,
    energy: 'low' | 'medium' | 'high'
  ) => {
    logger.info('MagicStudio', `Starting MagicSet generation`, {
      vibe,
      energy,
    });
    setActiveMode('set');
    setIsProcessing(true);
    setProgress(0);
    setStatusMessage('Analyzing your preferences...');

    try {
      const steps = [
        'Analyzing vibe preferences...',
        'Searching music libraries...',
        'Calculating BPM compatibility...',
        'Detecting harmonic keys...',
        'Optimizing track order...',
        'Finalizing enhanced magic set...',
      ];

      for (let i = 0; i < steps.length; i++) {
        setStatusMessage(steps[i]);
        setProgress(((i + 1) / steps.length) * 100);
        await new Promise(resolve => setTimeout(resolve, 800));
      }

      try {
        const playlist = await simplePlaylistService.generateMagicSetPlaylist({
          vibe,
          energyLevel: energy,
          userId: user?.id,
        });
        logger.info('MagicStudio', 'MagicSet playlist generated successfully', {
          vibe,
          energy,
          trackCount: playlist.tracks.length,
          duration: playlist.total_duration,
          harmonicMixing: playlist.metadata?.harmonic_mixing,
          dominantKey: playlist.metadata?.dominant_key,
          bpmRange: playlist.metadata?.bpm_range,
        });

        // Enhance playlist with advanced features metadata for UI display
        const enhancedPlaylist = {
          ...playlist,
          tracks: playlist.tracks.map(track => ({
            ...track,
            recognition_source: 'magic_set' as const,
          })),
        };

        onPlaylistGenerated(enhancedPlaylist);
      } catch (error) {
        logger.error(
          'MagicStudio',
          'Failed to generate MagicSet playlist',
          error
        );
        setStatusMessage(
          'Failed to generate playlist. Please check your API configuration.'
        );
        setTimeout(() => {
          setIsProcessing(false);
          setActiveMode(null);
        }, 2000);
        return;
      }
    } catch (error) {
      logger.error('MagicStudio', 'MagicSet generation failed', error);
      setStatusMessage(
        'Generation failed. Please check your API configuration and try again.'
      );
      setTimeout(() => {
        setIsProcessing(false);
        setActiveMode(null);
      }, 2000);
      return;
    } finally {
      setIsProcessing(false);
      setActiveMode(null);
    }
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      logger.info('MagicStudio', 'Processing uploaded file', {
        fileName: file.name,
        fileSize: file.size,
        fileType: file.type,
      });

      setActiveMode('match');
      setIsProcessing(true);
      setProgress(0);
      setStatusMessage('Processing uploaded file...');

      simplePlaylistService
        .generateMagicMatchPlaylist({ userId: user?.id })
        .then(async (result: any) => {
          if (result) {
            logger.info('MagicStudio', 'Track recognized from file', {
              track: `${result.title} - ${result.artist}`,
            });
            setStatusMessage('Track recognized from file!');
            setProgress(60);

            const playlist =
              await simplePlaylistService.generateMagicMatchPlaylist({
                userId: user?.id,
              });
            playlist.tracks.unshift(result);
            onPlaylistGenerated(playlist);
            return;
          }

          logger.warn(
            'MagicStudio',
            'Direct recognition failed, trying fingerprint approach'
          );
          const fingerprintResult =
            await audioProcessingService.processAudioFile(file);
          setStatusMessage(
            `File processed (${Math.round(fingerprintResult.confidence * 100)}% confidence)`
          );
          setProgress(40);

          const steps = [
            'Analyzing audio fingerprint...',
            'Querying recognition services...',
            'Generating AI playlist...',
          ];

          for (let i = 0; i < steps.length; i++) {
            setStatusMessage(steps[i]);
            setProgress(40 + ((i + 1) / steps.length) * 60);
            await new Promise(resolve => setTimeout(resolve, 600));
          }

          const playlist =
            await simplePlaylistService.generateMagicMatchPlaylist({
              fingerprint: fingerprintResult.fingerprint,
              userId: user?.id,
            });
          onPlaylistGenerated(playlist);
        })
        .catch(async (error: any) => {
          logger.error('MagicStudio', 'File processing failed', error);
          setStatusMessage(
            'File processing failed. Please try a different audio file.'
          );
          setProgress(80);

          setTimeout(() => {
            setIsProcessing(false);
            setActiveMode(null);
          }, 2000);
        })
        .finally(() => {
          setIsProcessing(false);
          setActiveMode(null);
        });
    }
  };

  if (isProcessing) {
    return (
      <div className="min-h-screen gradient-bg-primary flex items-center justify-center relative overflow-hidden">
        {/* Animated Background Elements */}
        <div className="absolute inset-0 overflow-hidden">
          <div className="absolute top-1/4 left-1/4 w-64 h-64 bg-gradient-to-r from-purple-500/20 to-pink-500/20 rounded-full blur-3xl animate-float"></div>
          <div
            className="absolute bottom-1/4 right-1/4 w-96 h-96 bg-gradient-to-r from-cyan-500/20 to-blue-500/20 rounded-full blur-3xl animate-float"
            style={{ animationDelay: '1s' }}
            aria-hidden="true"
          ></div>
        </div>

        <div className="relative z-10 text-center max-w-lg mx-auto p-8">
          {/* Futuristic Animated Logo */}
          <div
            className={`w-32 h-32 glass-card flex items-center justify-center mx-auto mb-8 animate-pulse-glow ${activeMode === 'match' ? 'shadow-neon-cyan' : 'shadow-neon-pink'}`}
          >
            {activeMode === 'match' ? (
              <Zap className="w-16 h-16 text-gradient-accent" />
            ) : (
              <Wand2 className="w-16 h-16 text-gradient-primary" />
            )}
          </div>

          {/* Enhanced Progress Bar with neon styling */}
          <div className="progress-bar mb-8">
            <div
              className={`progress-fill transition-all duration-500 ${activeMode === 'match' ? 'gradient-bg-accent' : 'gradient-bg-secondary'}`}
              style={{ width: `${progress}%` }}
            ></div>
          </div>

          {/* Futuristic Status Message */}
          <h2
            className={`text-3xl font-bold mb-4 font-orbitron tracking-wide ${activeMode === 'match' ? 'text-gradient-accent' : 'text-gradient-primary'}`}
          >
            {activeMode === 'match' ? 'MAGICMATCH' : 'MAGICSET'} PROCESSING
          </h2>
          <p className="text-gray-300 text-xl font-inter mb-2">
            {statusMessage}
          </p>
          <p className="text-gray-500 text-sm font-mono">
            {Math.round(progress)}% COMPLETE
          </p>

          {/* Animated Waveform Visualization */}
          <div className="flex justify-center mt-12">
            <div className="flex items-end space-x-1 h-16">
              {Array.from({ length: 15 }).map((_, i) => (
                <div
                  key={i}
