// Consolidated state interface using useReducer
interface PlayerState {
  // Track management
  currentTrackIndex: number;

  // Audio state
  currentTime: number;
  duration: number;
  isLoading: boolean;

  // Volumes and mixing
  volumes: {
    deckA: number;
    deckB: number;
    master: number;
    crossfader: number; // -100 to 100
  };

  // Progress tracking
  progress: {
    deckA: number;
    deckB: number;
  };

  // Audio sources
  sources: {
    deckA: AudioSource[];
    deckB: AudioSource[];
    deckAIndex: number;
    deckBIndex: number;
    deckACurrent: AudioSource | null;
    deckBCurrent: AudioSource | null;
  };

  // Settings
  settings: {
    bpmSync: boolean;
    autoMix: boolean;
    shuffle: boolean;
    repeat: boolean;
  };

  // UI state
  ui: {
    mobileMenuOpen: boolean;
    showPlaylistEditor: boolean;
    showMagicDancer: boolean;
    showUnmuteOverlay: boolean;
    showSettings: boolean;
    showAudioDebugger: boolean;
  };

  // Error handling
  error: {
    message: string | null;
    isDegraded: boolean;
  };

  // Player readiness
  readiness: {
    youtubeA: boolean;
    youtubeB: boolean;
  };

  // Cue points
  cuePoints: {
    deckA: number[];
    deckB: number[];
  };
}

type PlayerAction =
  | { type: 'SET_TRACK_INDEX'; payload: number }
  | { type: 'SET_LOADING'; payload: boolean }
  | { type: 'SET_TIME'; payload: { currentTime: number; duration?: number } }
  | {
      type: 'SET_VOLUME';
      payload: {
        deck: 'deckA' | 'deckB' | 'master' | 'crossfader';
        value: number;
      };
    }
  | {
      type: 'SET_PROGRESS';
      payload: { deck: 'deckA' | 'deckB'; value: number };
    }
  | {
      type: 'SET_SOURCES';
      payload: {
        deck: 'deckA' | 'deckB';
        sources: AudioSource[];
        index?: number;
      };
    }
  | {
      type: 'SET_SOURCE_INDEX';
      payload: { deck: 'deckA' | 'deckB'; index: number };
    }
  | {
      type: 'SET_SETTING';
      payload: { key: keyof PlayerState['settings']; value: boolean };
    }
  | {
      type: 'SET_UI';
      payload: { key: keyof PlayerState['ui']; value: boolean };
    }
  | {
      type: 'SET_ERROR';
      payload: { message: string | null; isDegraded?: boolean };
    }
  | {
      type: 'SET_READINESS';
      payload: { player: 'youtubeA' | 'youtubeB'; ready: boolean };
    }
  | {
      type: 'ADD_CUE_POINT';
      payload: { deck: 'deckA' | 'deckB'; position: number };
    }
  | { type: 'CLEAR_CUE_POINTS'; payload: { deck: 'deckA' | 'deckB' } }
  | { type: 'RESET_ERROR' };

const initialState: PlayerState = {
  currentTrackIndex: 0,
  currentTime: 0,
  duration: 0,
  isLoading: false,
  volumes: {
    deckA: 85,
    deckB: 0,
    master: 75,
    crossfader: -50,
  },
  progress: {
    deckA: 0,
    deckB: 0,
  },
  sources: {
    deckA: [],
    deckB: [],
    deckAIndex: 0,
    deckBIndex: 0,
    deckACurrent: null,
    deckBCurrent: null,
  },
  settings: {
    bpmSync: true,
    autoMix: false,
    shuffle: false,
    repeat: false,
  },
  ui: {
    mobileMenuOpen: false,
    showPlaylistEditor: false,
    showMagicDancer: true,
    showUnmuteOverlay: false,
    showSettings: false,
    showAudioDebugger: false,
  },
  error: {
    message: null,
    isDegraded: false,
  },
  readiness: {
    youtubeA: false,
    youtubeB: false,
  },
  cuePoints: {
    deckA: [],
    deckB: [],
  },
};

function playerReducer(state: PlayerState, action: PlayerAction): PlayerState {
  switch (action.type) {
    case 'SET_TRACK_INDEX':
      return {
        ...state,
        currentTrackIndex: action.payload,
        progress: { ...state.progress, deckA: 0 },
        currentTime: 0,
      };

    case 'SET_LOADING':
      return { ...state, isLoading: action.payload };

    case 'SET_TIME':
      return {
        ...state,
        currentTime: action.payload.currentTime,
        ...(action.payload.duration !== undefined && {
          duration: action.payload.duration,
        }),
      };

    case 'SET_VOLUME':
      return {
        ...state,
        volumes: {
          ...state.volumes,
          [action.payload.deck]: action.payload.value,
        },
      };

    case 'SET_PROGRESS':
      return {
        ...state,
        progress: {
          ...state.progress,
          [action.payload.deck]: action.payload.value,
        },
      };

    case 'SET_SOURCES':
      const deckKey = action.payload.deck === 'deckA' ? 'deckA' : 'deckB';
      const indexKey =
        action.payload.deck === 'deckA' ? 'deckAIndex' : 'deckBIndex';
      const currentKey =
        action.payload.deck === 'deckA' ? 'deckACurrent' : 'deckBCurrent';

      return {
        ...state,
        sources: {
          ...state.sources,
          [deckKey]: action.payload.sources,
          [indexKey]: action.payload.index ?? 0,
          [currentKey]:
            action.payload.sources[action.payload.index ?? 0] || null,
        },
      };

    case 'SET_SOURCE_INDEX':
      const deck = action.payload.deck === 'deckA' ? 'deckA' : 'deckB';
      const sources = state.sources[deck];
      const current =
        action.payload.deck === 'deckA' ? 'deckACurrent' : 'deckBCurrent';
      const index =
        action.payload.deck === 'deckA' ? 'deckAIndex' : 'deckBIndex';

      return {
        ...state,
        sources: {
          ...state.sources,
          [index]: action.payload.index,
          [current]: sources[action.payload.index] || null,
        },
      };

    case 'SET_SETTING':
      return {
        ...state,
        settings: {
          ...state.settings,
          [action.payload.key]: action.payload.value,
        },
      };

    case 'SET_UI':
      return {
        ...state,
        ui: { ...state.ui, [action.payload.key]: action.payload.value },
      };

    case 'SET_ERROR':
      return {
        ...state,
        error: {
          message: action.payload.message,
          isDegraded: action.payload.isDegraded ?? state.error.isDegraded,
        },
      };

    case 'SET_READINESS':
      return {
        ...state,
        readiness: {
          ...state.readiness,
          [action.payload.player]: action.payload.ready,
        },
      };

    case 'ADD_CUE_POINT':
      return {
        ...state,
        cuePoints: {
          ...state.cuePoints,
          [action.payload.deck]: [
            ...state.cuePoints[action.payload.deck],
            action.payload.position,
          ],
        },
      };

    case 'CLEAR_CUE_POINTS':
      return {
        ...state,
        cuePoints: {
          ...state.cuePoints,
          [action.payload.deck]: [],
        },
      };

    case 'RESET_ERROR':
      return {
        ...state,
        error: { message: null, isDegraded: false },
      };

    default:
      return state;
  }
}

// Custom hook for resource cleanup
const useResourceCleanup = () => {
  const cleanupFunctions = useRef<(() => void)[]>([]);

  const addCleanup = useCallback((fn: () => void) => {
    cleanupFunctions.current.push(fn);
  }, []);

  useEffect(() => {
    return () => {
      cleanupFunctions.current.forEach(fn => {
        try {
          fn();
        } catch (error) {
          logger.warn(
            'ProfessionalMagicPlayer',
            'Cleanup function failed',
            error
          );
        }
      });
      cleanupFunctions.current = [];
    };
  }, []);

  return { addCleanup };
};

// Custom hook for audio source management
const useAudioSources = () => {
  const loadAudioSources = useCallback(
    async (track: Track): Promise<AudioSource[]> => {
      try {
        logger.info(
          'ProfessionalMagicPlayer',
          'Loading audio sources for track',
          {
            trackId: track.id,
            trackTitle: track.title,
          }
        );

        const sources = await audioSourceService.getAudioSourcesForTrack(track);
        logger.info('ProfessionalMagicPlayer', 'Audio sources loaded', {
          trackId: track.id,
          sourceCount: sources.length,
          sourceTypes: sources.map(s => s.type),
        });

        return sources;
      } catch (error) {
        logger.error(
          'ProfessionalMagicPlayer',
          'Failed to load audio sources',
          {
            trackId: track.id,
            error,
          }
        );
        return [];
      }
    },
    []
  );

  return { loadAudioSources };
};

// Custom hook for waveform generation
const useWaveform = () => {
  const waveformDataA = useRef<number[]>([]);
  const waveformDataB = useRef<number[]>([]);

  const generateWaveformData = useCallback((width: number): number[] => {
    const bars = Math.floor(width / 3);
    const data: number[] = [];

    for (let i = 0; i < bars; i++) {
      const frequency = (i / bars) * 10 + 1;
      const baseAmplitude = Math.sin(frequency * 0.5) * 0.3 + 0.7;
      data.push(baseAmplitude);
    }

    return data;
  }, []);

  const updateWaveformData = useCallback(
    (deck: 'A' | 'B', track: Track | undefined) => {
      if (track) {
        const data = generateWaveformData(320);
        if (deck === 'A') {
          waveformDataA.current = data;
        } else {
          waveformDataB.current = data;
        }
      }
    },
    [generateWaveformData]
  );

  return { waveformDataA, waveformDataB, updateWaveformData };
};

const ProfessionalMagicPlayer: React.FC<ProfessionalMagicPlayerProps> = ({
  playlist,
  session,
  isPlaying,
  onPlayPause,
  onSessionEnd,
  onBack,
  onSavePlaylist,
}) => {
  const [state, dispatch] = useReducer(playerReducer, initialState);
  const { addCleanup } = useResourceCleanup();
  const { loadAudioSources } = useAudioSources();
  const { waveformDataA, waveformDataB, updateWaveformData } = useWaveform();

  // Refs for audio and YouTube players
  const audioARef = useRef<HTMLAudioElement | null>(null);
  const audioBRef = useRef<HTMLAudioElement | null>(null);
  const youtubeARef = useRef<YouTubePlayerRef | null>(null);
  const youtubeBRef = useRef<YouTubePlayerRef | null>(null);

  // Canvas refs for waveform
  const waveformCanvasA = useRef<HTMLCanvasElement>(null);
  const waveformCanvasB = useRef<HTMLCanvasElement>(null);

  // Interval refs
  const autoMixIntervalRef = useRef<number>();
  const fadeIntervalRef = useRef<number>();

  // Memoized current and next tracks
  const currentTrack = useMemo(
    () => playlist?.tracks[state.currentTrackIndex],
    [playlist, state.currentTrackIndex]
  );
  const nextTrack = useMemo(
    () => playlist?.tracks[state.currentTrackIndex + 1],
    [playlist, state.currentTrackIndex]
  );

  // Memoized volume calculations for performance
  const volumeCalculations = useMemo(() => {
    const { volumes } = state;
    const deckAVol = (volumes.deckA / 100) * (volumes.master / 100);
    const deckBVol = (volumes.deckB / 100) * (volumes.master / 100);

    const crossfadeA =
      volumes.crossfader <= 0 ? 1 : Math.max(0, 1 - volumes.crossfader / 100);
    const crossfadeB =
      volumes.crossfader >= 0 ? 1 : Math.max(0, 1 + volumes.crossfader / 100);

    return {
      deckA: Math.max(0, Math.min(1, deckAVol * crossfadeA)),
      deckB: Math.max(0, Math.min(1, deckBVol * crossfadeB)),
    };
  }, [state.volumes]);

  // Error auto-clear effect
  useEffect(() => {
    if (state.error.message) {
      const timeout = setTimeout(() => {
        dispatch({ type: 'RESET_ERROR' });
      }, 5000);
      return () => clearTimeout(timeout);
    }
  }, [state.error.message]);

  // Log session information
  useEffect(() => {
    if (session?.id) {
      logger.info('ProfessionalMagicPlayer', 'Session active', {
        sessionId: session.id,
      });
    }
  }, [session?.id]);

  // Update waveform data when tracks change
  useEffect(() => {
    updateWaveformData('A', currentTrack);
  }, [currentTrack, updateWaveformData]);

  useEffect(() => {
    updateWaveformData('B', nextTrack);
  }, [nextTrack, updateWaveformData]);

  // Audio cleanup utility
  const cleanupAudioElement = useCallback((audio: HTMLAudioElement) => {
    try {
      audio.pause();
      audio.currentTime = 0;

      // Remove all event listeners
      const events = [
        'loadedmetadata',
        'canplaythrough',
        'timeupdate',
        'ended',
        'error',
      ];
      events.forEach(event => {
        audio.removeEventListener(event, () => {});
      });

      audio.src = '';
      audio.load();

      logger.debug(
        'ProfessionalMagicPlayer',
        'Audio element cleaned up successfully'
      );
    } catch (error) {
      logger.warn(
        'ProfessionalMagicPlayer',
        'Error during audio cleanup',
        error
      );
    }
  }, []);

  // Handle track end
  const handleTrackEnd = useCallback(() => {
    if (
      state.settings.repeat &&
      state.currentTrackIndex === (playlist?.tracks.length ?? 0) - 1
    ) {
      dispatch({ type: 'SET_TRACK_INDEX', payload: 0 });
      return;
    }

    if (state.currentTrackIndex < (playlist?.tracks.length ?? 0) - 1) {
      let nextIndex = state.currentTrackIndex + 1;

      if (state.settings.shuffle) {
        const availableIndices = Array.from(
          { length: playlist?.tracks.length ?? 0 },
          (_, i) => i
        ).filter(i => i !== state.currentTrackIndex);
        nextIndex =
          availableIndices[
            Math.floor(Math.random() * availableIndices.length)
          ] ?? nextIndex;
      }

      dispatch({ type: 'SET_TRACK_INDEX', payload: nextIndex });
    } else if (state.settings.repeat) {
      dispatch({ type: 'SET_TRACK_INDEX', payload: 0 });
    } else {
      onSessionEnd();
    }
  }, [
    state.currentTrackIndex,
    state.settings.shuffle,
    state.settings.repeat,
    playlist?.tracks.length,
    onSessionEnd,
  ]);

  // Handle source errors with retry logic and rate limiting
  const errorCountRef = useRef<{ [key: string]: number }>({});
  const handleSourceError = useCallback(
    (deck: 'A' | 'B', error: any) => {
      const sources = deck === 'A' ? state.sources.deckA : state.sources.deckB;
      const currentIndex =
        deck === 'A' ? state.sources.deckAIndex : state.sources.deckBIndex;

      // Rate limit error logging (max 3 errors per deck)
      const errorKey = `deck${deck}`;
      errorCountRef.current[errorKey] =
        (errorCountRef.current[errorKey] || 0) + 1;

      if (errorCountRef.current[errorKey] <= 3) {
        logger.warn(
          'ProfessionalMagicPlayer',
          `Audio source error on deck ${deck} (${errorCountRef.current[errorKey]}/3)`,
          {
            error: error?.message || 'Unknown error',
            currentIndex,
            totalSources: sources.length,
          }
        );
      }

      // Try next source
      const nextIndex = currentIndex + 1;
      if (nextIndex < sources.length && errorCountRef.current[errorKey] <= 5) {
        dispatch({
          type: 'SET_SOURCE_INDEX',
          payload: { deck: deck === 'A' ? 'deckA' : 'deckB', index: nextIndex },
        });
      } else {
        // No more sources available or too many errors
        dispatch({
          type: 'SET_ERROR',
          payload: {
            message: `Audio unavailable for deck ${deck}`,
            isDegraded: true,
          },
        });
        // Reset error count for future attempts
        errorCountRef.current[errorKey] = 0;
      }
    },
    [state.sources]
  );

  // Load sources for current track
  useEffect(() => {
    if (!currentTrack) {
      dispatch({
        type: 'SET_SOURCES',
        payload: { deck: 'deckA', sources: [] },
      });
      return;
    }

    // Ensure track has proper metadata structure
    if (!currentTrack.meta) {
      currentTrack.meta = {};
    }

    let cancelled = false;

    const loadSources = async () => {
      dispatch({ type: 'SET_LOADING', payload: true });

      try {
        const sources = await loadAudioSources(currentTrack);

        // Validate sources have proper URLs
        const validSources = sources.filter(source => {
          if (!source.url || typeof source.url !== 'string') return false;
          // Check for valid audio URLs (direct audio files or generated blobs)
          return (
            source.url.startsWith('blob:') ||
            source.url.startsWith('data:audio/') ||
            source.url.match(/\.(mp3|wav|m4a|ogg|aac)$/i) ||
            source.url.startsWith('https://')
          );
        });

        if (!cancelled) {
          if (validSources.length > 0) {
            dispatch({
              type: 'SET_SOURCES',
              payload: { deck: 'deckA', sources: validSources, index: 0 },
            });
          } else {
            dispatch({
              type: 'SET_ERROR',
              payload: {
                message: 'No valid audio sources available',
                isDegraded: true,
              },
            });
          }
        }
      } catch (error) {
        if (!cancelled) {
          dispatch({
            type: 'SET_ERROR',
            payload: {
              message: 'Failed to load audio sources',
              isDegraded: true,
            },
          });
        }
      } finally {
        if (!cancelled) {
          dispatch({ type: 'SET_LOADING', payload: false });
        }
      }
    };

    loadSources();

    return () => {
      cancelled = true;
    };
  }, [currentTrack, loadAudioSources]);

  // Load sources for next track
  useEffect(() => {
    if (!nextTrack) {
      dispatch({
        type: 'SET_SOURCES',
        payload: { deck: 'deckB', sources: [] },
      });
      return;
    }

    let cancelled = false;

    const loadSources = async () => {
      try {
        const sources = await loadAudioSources(nextTrack);

        if (!cancelled && sources.length > 0) {
          dispatch({
            type: 'SET_SOURCES',
            payload: { deck: 'deckB', sources, index: 0 },
          });
        }
      } catch (error) {
        // Silently fail for deck B sources
        logger.warn(
          'ProfessionalMagicPlayer',
          'Failed to load deck B sources',
          error
        );
      }
    };

    loadSources();

    return () => {
      cancelled = true;
    };
  }, [nextTrack, loadAudioSources]);

  // Initialize Audio A
  useEffect(() => {
    const { deckA, deckACurrent } = state.sources;

    if (!deckACurrent || deckA.length === 0) {
      return;
    }

    // Clean up existing audio
    if (audioARef.current) {
      cleanupAudioElement(audioARef.current);
      audioARef.current = null;
    }

    // Skip YouTube sources - iframe player handles audio
    if (deckACurrent.type === 'youtube') {
      dispatch({ type: 'SET_LOADING', payload: false });
      dispatch({
        type: 'SET_TIME',
        payload: {
          currentTime: 0,
          duration: deckACurrent.duration || 180,
        },
      });
      return;
    }

    // Create HTML audio element
    const audio = new Audio();
    audio.preload = 'metadata';
    audio.volume = volumeCalculations.deckA;

    // Validate and set source
    if (!deckACurrent.url || typeof deckACurrent.url !== 'string') {
      handleSourceError('A', new Error('Invalid audio source URL'));
      return;
    }

    audio.src = deckACurrent.url;

    // Validate that src was set
    if (!audio.src) {
      handleSourceError('A', new Error('Empty audio src'));
      return;
    }

    // Event listeners
    const onLoadedMetadata = () => {
      const duration = audio.duration || deckACurrent.duration || 180;
      dispatch({ type: 'SET_TIME', payload: { currentTime: 0, duration } });
      dispatch({ type: 'SET_LOADING', payload: false });
    };

    const onTimeUpdate = () => {
      dispatch({
        type: 'SET_TIME',
        payload: { currentTime: audio.currentTime },
      });
      const progress =
        audio.duration > 0 ? (audio.currentTime / audio.duration) * 100 : 0;
      dispatch({
        type: 'SET_PROGRESS',
        payload: { deck: 'deckA', value: progress },
      });
    };

    const onError = () => {
      dispatch({ type: 'SET_LOADING', payload: false });
      handleSourceError('A', new Error('Audio load failed'));
    };

    // REALITY-BOUND DIRECTIVE: Spotify Preview Playback Logging
    const onPlay = () => {
      const currentTrack = playlist?.tracks[state.currentTrackIndex];
      if (currentTrack && currentTrack.preview_url) {
        const duration = audio.duration || currentTrack.duration || 30; // Spotify previews are 30s
        logger.info('ProfessionalMagicPlayer', 'SPOTIFY PLAYBACK STARTED', {
          trackId: currentTrack.id,
          title: currentTrack.title,
          artist: currentTrack.artist,
          playback: 'started',
          duration: duration,
          sourceUrl: currentTrack.preview_url,
          sourceTypes: [
            currentTrack.youtube_url ? 'youtube' : null,
            currentTrack.preview_url ? 'spotify' : null,
          ].filter(Boolean),
          provider: 'spotify',
        });

        console.log(
          `[PLAYBACK] ✅ Started: trackId="${currentTrack.id}", title="${currentTrack.title}", duration=${duration}s, provider=spotify, url="${currentTrack.preview_url}"`
        );
      }
    };

    // Add listeners
    audio.addEventListener('loadedmetadata', onLoadedMetadata);
    audio.addEventListener('timeupdate', onTimeUpdate);
    audio.addEventListener('ended', handleTrackEnd);
    audio.addEventListener('error', onError);
    audio.addEventListener('play', onPlay); // Add playback start logging

    audioARef.current = audio;
    dispatch({ type: 'SET_LOADING', payload: true });

    // Cleanup function
    const cleanup = () => {
      if (audio) {
        cleanupAudioElement(audio);
      }
    };

    addCleanup(cleanup);

    return cleanup;
  }, [
    state.sources.deckACurrent,
    volumeCalculations.deckA,
    cleanupAudioElement,
    handleSourceError,
    handleTrackEnd,
    addCleanup,
  ]);

  // Initialize Audio B
  useEffect(() => {
    const { deckB, deckBCurrent } = state.sources;

    if (!deckBCurrent || deckB.length === 0) {
      return;
    }

    // Clean up existing audio
    if (audioBRef.current) {
      cleanupAudioElement(audioBRef.current);
      audioBRef.current = null;
    }

    // Skip YouTube sources for deck B - iframe player handles audio
    if (deckBCurrent.type === 'youtube') {
      dispatch({ type: 'SET_LOADING', payload: false });
      dispatch({
        type: 'SET_TIME',
        payload: {
          currentTime: 0,
          duration: deckBCurrent.duration || 180,
        },
      });
      return;
    }

    // Create HTML audio element
    const audio = new Audio();
    audio.preload = 'auto';
    audio.crossOrigin = 'anonymous';
    audio.volume = volumeCalculations.deckB;

    try {
      audio.src = deckBCurrent.url;
    } catch (error) {
      handleSourceError('B', error);
      return;
    }

    // Event listeners
    const onTimeUpdate = () => {
      const progress =
        audio.duration > 0 ? (audio.currentTime / audio.duration) * 100 : 0;
      dispatch({
        type: 'SET_PROGRESS',
        payload: { deck: 'deckB', value: progress },
      });
    };

    const onError = (e: Event) => {
      handleSourceError('B', (e.target as HTMLAudioElement).error);
    };

    // Add listeners
    audio.addEventListener('timeupdate', onTimeUpdate);
    audio.addEventListener('error', onError);

    audioBRef.current = audio;

    // Cleanup function
    const cleanup = () => {
      if (audio) {
        cleanupAudioElement(audio);
      }
    };

    addCleanup(cleanup);

    return cleanup;
  }, [
    state.sources.deckBCurrent,
    volumeCalculations.deckB,
    cleanupAudioElement,
    handleSourceError,
    addCleanup,
  ]);

  // Volume update effect
  useEffect(() => {
