        }

        if (shouldUpdateB) {
          drawWaveform(
            waveformCanvasB.current,
            nextTrack,
            state.progress.deckB,
            'purple',
            waveformDataB.current
          );
        }

        lastUpdate = timestamp;
      }

      animationId = requestAnimationFrame(animate);
    };

    animationId = requestAnimationFrame(animate);

    addCleanup(() => {
      if (animationId) {
        cancelAnimationFrame(animationId);
      }
    });

    return () => {
      if (animationId) {
        cancelAnimationFrame(animationId);
