export default YouTubePlayer;

import { useState, useEffect, useRef, useCallback } from 'react';
import {
  YouTubePlayerState,
  YouTubePlayerError,
} from '../components/YouTubePlayer';

interface UseYouTubePlayerOptions {
  autoplay?: boolean;
  volume?: number;
  onReady?: () => void;
  onStateChange?: (state: YouTubePlayerState) => void;
  onError?: (error: YouTubePlayerError) => void;
  onTimeUpdate?: (currentTime: number) => void;
}

export const useYouTubePlayer = (
  videoId: string | null,
  options: UseYouTubePlayerOptions = {}
) => {
  const playerRef = useRef<any>(null);
  const [isReady, setIsReady] = useState(false);
  const readyPromiseRef = useRef<{
    resolve: () => void;
    promise: Promise<void>;
  } | null>(null);
  const timeUpdateInterval = useRef<NodeJS.Timeout>();
  const playerId = useRef(
    `youtube-player-${Math.random().toString(36).substr(2, 9)}`
  );

  // Initialize ready promise
  useEffect(() => {
    let resolve: () => void;
    const promise = new Promise<void>(res => {
      resolve = res;
    });
    readyPromiseRef.current = { resolve: resolve!, promise };
    return () => {
      readyPromiseRef.current = null;
    };
  }, []);

  // Handle time updates
  useEffect(() => {
    if (!isReady || !options.onTimeUpdate) return;

    timeUpdateInterval.current = setInterval(() => {
      if (playerRef.current) {
        const currentTime = playerRef.current.getCurrentTime();
        options.onTimeUpdate?.(currentTime);
      }
    }, 1000);

    return () => {
      if (timeUpdateInterval.current) {
        clearInterval(timeUpdateInterval.current);
      }
    };
  }, [isReady, options.onTimeUpdate]);

  // Load YouTube API
  useEffect(() => {
    if (!videoId) return;

    const existingScript = document.querySelector(
      'script[src="https://www.youtube.com/iframe_api"]'
    );

    if (!existingScript) {
      const tag = document.createElement('script');
      tag.src = 'https://www.youtube.com/iframe_api';
      const firstScriptTag = document.getElementsByTagName('script')[0];
      firstScriptTag.parentNode?.insertBefore(tag, firstScriptTag);
    }

    const originalOnYouTubeIframeAPIReady = window.onYouTubeIframeAPIReady;

    window.onYouTubeIframeAPIReady = () => {
      if (originalOnYouTubeIframeAPIReady) originalOnYouTubeIframeAPIReady();

      const player = new window.YT.Player(playerId.current, {
        videoId,
        playerVars: {
          autoplay: options.autoplay ? 1 : 0,
          controls: 0,
          disablekb: 1,
          enablejsapi: 1,
          fs: 0,
          iv_load_policy: 3,
          modestbranding: 1,
          rel: 0,
          showinfo: 0,
          volume: options.volume || 50,
        },
        events: {
          onReady: () => {
            setIsReady(true);
            readyPromiseRef.current?.resolve();
            options.onReady?.();
          },
          onStateChange: (event: any) => {
            options.onStateChange?.(event.data);
          },
          onError: (event: any) => {
            options.onError?.(event.data);
          },
        },
      });

      playerRef.current = player;
    };

    return () => {
      if (playerRef.current) {
        playerRef.current.destroy();
        playerRef.current = null;
      }
      window.onYouTubeIframeAPIReady = originalOnYouTubeIframeAPIReady;
      if (timeUpdateInterval.current) {
        clearInterval(timeUpdateInterval.current);
      }
    };
  }, [videoId, options.autoplay, options.volume]);

  const play = useCallback(async () => {
    if (!isReady) {
      await readyPromiseRef.current?.promise;
    }
    if (playerRef.current) {
      playerRef.current.playVideo();
    }
  }, [isReady]);

  const pause = useCallback(() => {
    if (playerRef.current) {
      playerRef.current.pauseVideo();
    }
  }, []);

  const setVolume = useCallback((volume: number) => {
    if (playerRef.current) {
      playerRef.current.setVolume(volume);
    }
  }, []);

  const seekTo = useCallback((seconds: number) => {
    if (playerRef.current) {
      playerRef.current.seekTo(seconds, true);
    }
  }, []);

  const getCurrentTime = useCallback((): number => {
    if (playerRef.current) {
      return playerRef.current.getCurrentTime();
    }
    return 0;
  }, []);

  const getDuration = useCallback((): number => {
    if (playerRef.current) {
      return playerRef.current.getDuration();
    }
    return 0;
  }, []);

  return {
    isReady,
    play,
    pause,
    setVolume,
    seekTo,
    getCurrentTime,
    getDuration,
    playerId: playerId.current,
    waitForReady: () => readyPromiseRef.current?.promise || Promise.resolve(),
  };
};

import { createClient } from '@supabase/supabase-js';

// Support multiple env var prefixes (Vite, Next.js, generic PUBLIC_)
// Prefer VITE_* (Vite standard), then PUBLIC_*, then NEXT_PUBLIC_*, and finally process.env fallbacks
// @ts-ignore - import.meta.env keys are runtime-defined
const supabaseUrl =
  (import.meta as any)?.env?.VITE_SUPABASE_URL ||
  (import.meta as any)?.env?.PUBLIC_SUPABASE_URL ||
  (import.meta as any)?.env?.NEXT_PUBLIC_SUPABASE_URL ||
  (typeof process !== 'undefined'
    ? process.env.VITE_SUPABASE_URL
    : undefined) ||
  (typeof process !== 'undefined'
    ? process.env.PUBLIC_SUPABASE_URL
    : undefined) ||
  (typeof process !== 'undefined'
    ? process.env.NEXT_PUBLIC_SUPABASE_URL
    : undefined);

// @ts-ignore - import.meta.env keys are runtime-defined
const supabaseAnonKey =
  (import.meta as any)?.env?.VITE_SUPABASE_ANON_KEY ||
  (import.meta as any)?.env?.PUBLIC_SUPABASE_ANON_KEY ||
  (import.meta as any)?.env?.NEXT_PUBLIC_SUPABASE_ANON_KEY ||
  (typeof process !== 'undefined'
    ? process.env.VITE_SUPABASE_ANON_KEY
    : undefined) ||
  (typeof process !== 'undefined'
    ? process.env.PUBLIC_SUPABASE_ANON_KEY
    : undefined) ||
  (typeof process !== 'undefined'
    ? process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY
    : undefined);

// Fail loudly in production if env is missing; warn and use placeholder only in dev
if ((!supabaseUrl || !supabaseAnonKey) && !import.meta.env.DEV) {
  console.error(
    'Supabase configuration missing. Set VITE_SUPABASE_URL and VITE_SUPABASE_ANON_KEY.'
  );
}

const resolvedUrl = supabaseUrl || 'https://placeholder.supabase.co';
const resolvedKey = supabaseAnonKey || 'placeholder-anon-key';

export const supabase = createClient(resolvedUrl, resolvedKey, {
  auth: {
    persistSession: true,
    autoRefreshToken: true,
    detectSessionInUrl: true,
    storage: typeof window !== 'undefined' ? window.localStorage : undefined,
    storageKey: 'sb-auth-token',
    debug: import.meta.env.DEV,
    flowType: 'pkce',
  },
  db: {
    schema: 'public',
  },
  global: {
    headers: {
      'x-application-name': 'MagicDJ',
    },
  },
});

// expose the same names your app imports
export const db: any = supabase;
export const auth: any = supabase.auth;

/* ===== Polyfills so existing code keeps working ===== */

// auth.signIn(email, password) or auth.signIn({ email, password })
const originalSignInWithPassword = supabase.auth.signInWithPassword.bind(
  supabase.auth
);
(auth as any).signIn = (...args: any[]) => {
  if (args.length === 1 && typeof args[0] === 'object') {
    const { email, password } = args[0] || {};
    return originalSignInWithPassword({ email, password });
  }
  const [email, password] = args;
  return originalSignInWithPassword({ email, password });
};

// auth.signUp(email, password, displayName?) or auth.signUp({ email, password, data })
const originalSignUp = supabase.auth.signUp.bind(supabase.auth);
(auth as any).signUp = (...args: any[]) => {
  if (args.length === 1 && typeof args[0] === 'object') {
    const { email, password, data } = args[0] || {};
    return originalSignUp({ email, password, options: { data } });
  }
  const [email, password, displayName] = args;
  const data = displayName ? { display_name: displayName } : undefined;
  return originalSignUp({ email, password, options: { data } });
};

// auth.getCurrentUser()
(auth as any).getCurrentUser = () => supabase.auth.getUser();

// auth.session() compatibility
(auth as any).session = () => supabase.auth.getSession();

// Utility to get current authenticated user id (or null)
export async function getCurrentUserId(): Promise<string | null> {
  try {
    const { data } = await supabase.auth.getSession();
    return data?.session?.user?.id ?? null;
  } catch {
    return null;
  }
}

/* ===== Tiny DB helpers your code calls directly ===== */

(db as any).getSessions = (userId: string) => {
  return supabase
    .from('sessions')
    .select('*')
    .eq('user_id', userId)
    .order('started_at', { ascending: false });
};

(db as any).createSession = (payload: any) => {
  return supabase.from('sessions').insert([payload]).select().single();
};

(db as any).updateSession = (id: string, patch: any) => {
  return supabase.from('sessions').update(patch).eq('id', id).select().single();
};

import {
  AudioFingerprint,
  AdvancedAudioFeatures,
  AudioRecognitionResponse,
  TrackSuggestion,
  KeyCompatibility,
  AudioCaptureConfig,
  Track,
} from '../types/index';
import { logger } from '../utils/logger';

class AdvancedAudioService {
  private audioStream: MediaStream | null = null;
  private audioContext: AudioContext | null = null;
  private analyser: AnalyserNode | null = null;
  private recorder: MediaRecorder | null = null;
  private recordedChunks: Blob[] = [];

  private defaultCaptureConfig: AudioCaptureConfig = {
    sampleRate: 44100,
    channels: 1,
    duration: 10000, // 10 seconds
    echoCancellation: false,
    noiseSuppression: false,
    autoGainControl: false,
  };

  /**
   * Initialize microphone capture with advanced configuration
   */
  async initializeCapture(
    config: Partial<AudioCaptureConfig> = {}
  ): Promise<void> {
    return logger.trackOperation(
      'AdvancedAudioService',
      'initializeCapture',
      async () => {
        const captureConfig = { ...this.defaultCaptureConfig, ...config };

        try {
          this.audioStream = await navigator.mediaDevices.getUserMedia({
            audio: {
              sampleRate: captureConfig.sampleRate,
              channelCount: captureConfig.channels,
              echoCancellation: captureConfig.echoCancellation,
              noiseSuppression: captureConfig.noiseSuppression,
              autoGainControl: captureConfig.autoGainControl,
            },
          });

          this.audioContext = new (window.AudioContext ||
            (window as any).webkitAudioContext)({
            sampleRate: captureConfig.sampleRate,
          });

          // Resume AudioContext if suspended
          if (this.audioContext.state === 'suspended') {
            await this.audioContext.resume();
          }

          // Set up audio analysis
          const source = this.audioContext.createMediaStreamSource(
            this.audioStream
          );
          this.analyser = this.audioContext.createAnalyser();
          this.analyser.fftSize = 2048;
          this.analyser.smoothingTimeConstant = 0.8;
          source.connect(this.analyser);

          // Set up MediaRecorder for high-quality capture
          this.recorder = new MediaRecorder(this.audioStream, {
            mimeType: 'audio/webm; codecs=opus',
          });

          this.recorder.ondataavailable = event => {
            if (event.data.size > 0) {
              this.recordedChunks.push(event.data);
            }
          };

          logger.info(
            'AdvancedAudioService',
            'Advanced microphone capture initialized',
            { config: captureConfig }
          );
        } catch (error) {
          logger.error(
            'AdvancedAudioService',
            'Failed to initialize audio capture',
            error
          );
          throw new Error('Advanced audio capture initialization failed');
        }
      }
    );
  }

  /**
   * Capture and analyze audio with advanced recognition
   */
  async captureAndAnalyze(
    durationMs: number = 10000
  ): Promise<AudioFingerprint> {
    return logger.trackOperation(
      'AdvancedAudioService',
      'captureAndAnalyze',
      async () => {
        if (!this.recorder || !this.audioStream) {
          throw new Error('Audio capture not initialized');
        }

        // Clear previous recordings
        this.recordedChunks = [];

        // Start recording
        this.recorder.start();

        // Wait for specified duration
        await new Promise(resolve => setTimeout(resolve, durationMs));

        // Stop recording
        this.recorder.stop();

        // Wait for data to be available
        await new Promise(resolve => {
          this.recorder!.onstop = resolve;
        });

        // Convert recorded audio to format for Python service
        const audioBlob = new Blob(this.recordedChunks, { type: 'audio/webm' });
        const audioBuffer = await audioBlob.arrayBuffer();
        const base64Audio = this.arrayBufferToBase64(audioBuffer);

        // Call Python recognition service
        const recognitionResponse = await this.callPythonService(base64Audio);

        // Create enhanced fingerprint
        const fingerprint: AudioFingerprint = {
          fingerprint: this.generateFingerprintHash(audioBuffer),
          confidence: recognitionResponse.features.confidence,
          duration: durationMs / 1000,
          features: recognitionResponse.features,
        };

        logger.info(
          'AdvancedAudioService',
          'Audio captured and analyzed successfully',
          {
            duration: fingerprint.duration,
            confidence: fingerprint.confidence,
            bpm: recognitionResponse.features.bpm,
            key: recognitionResponse.features.key,
            genre: recognitionResponse.features.genre,
            recognized: !!recognitionResponse.recognition,
            suggestionsCount: recognitionResponse.suggestions.length,
          }
        );

        return fingerprint;
      },
      { durationMs }
    );
  }

  /**
   * Call the Python audio recognition service
   */
  private async callPythonService(
    base64Audio: string
  ): Promise<AudioRecognitionResponse> {
    try {
      const response = await fetch('/api/audio-recognition', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          action: 'recognize',
          audio_data: base64Audio,
        }),
      });

      if (!response.ok) {
        throw new Error(`Recognition service error: ${response.status}`);
      }

      const result = await response.json();
      return result as AudioRecognitionResponse;
    } catch (error) {
      logger.warn(
        'AdvancedAudioService',
        'Python service unavailable, using fallback',
        error
      );

      // Return mock response if service is unavailable
      return this.generateMockResponse();
    }
  }

  /**
   * Check key compatibility between tracks
   */
  async checkKeyCompatibility(
    key1: string,
    key2: string
  ): Promise<KeyCompatibility> {
    return logger.trackOperation(
      'AdvancedAudioService',
      'checkKeyCompatibility',
      async () => {
        try {
          const response = await fetch('/api/audio-recognition', {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
            },
            body: JSON.stringify({
              action: 'compatibility',
              key1,
              key2,
            }),
          });

          if (!response.ok) {
            throw new Error(`Compatibility service error: ${response.status}`);
          }

          return await response.json();
        } catch (error) {
          logger.warn(
            'AdvancedAudioService',
            'Compatibility service unavailable, using local calculation',
            error
          );

          return this.calculateLocalCompatibility(key1, key2);
        }
      },
      { key1, key2 }
    );
  }

  /**
   * Get intelligent track suggestions based on current track
   */
  async getSuggestedTracks(currentTrack: Track): Promise<TrackSuggestion[]> {
    return logger.trackOperation(
      'AdvancedAudioService',
      'getSuggestedTracks',
      async () => {
        const features = currentTrack.advanced_features;
        if (!features) {
          logger.warn(
            'AdvancedAudioService',
            'No advanced features available for suggestions'
          );
          return [];
        }

        // This would typically query a track database
        // For now, generate compatible suggestions based on the current track
        return this.generateCompatibleSuggestions(features);
      },
      { trackId: currentTrack.id, trackTitle: currentTrack.title }
    );
  }

  /**
   * Enhance an existing track with advanced audio features
   */
  async enhanceTrack(track: Track): Promise<Track> {
    return logger.trackOperation(
      'AdvancedAudioService',
      'enhanceTrack',
      async () => {
        if (track.advanced_features) {
          return track; // Already enhanced
        }

        // Generate mock advanced features based on existing track data
        const enhancedFeatures: AdvancedAudioFeatures = {
          bpm: track.bpm || 120 + Math.random() * 60,
          key: track.key || this.generateRandomKey(),
          genre: track.genre || 'electronic',
          energy: track.energy || Math.random(),
          mfcc_features: Array.from(
            { length: 13 },
            () => Math.random() * 100 - 50
          ),
          spectral_centroid: 2000 + Math.random() * 2000,
          confidence: 0.8,
          valence: track.valence,
          danceability: track.danceability,
        };

        return {
          ...track,
          advanced_features: enhancedFeatures,
          recognition_source: 'database' as const,
        };
      },
      { trackId: track.id }
    );
  }

  /**
   * Stop audio capture and cleanup resources
   */
  async stopCapture(): Promise<void> {
    return logger.trackOperation(
      'AdvancedAudioService',
      'stopCapture',
      async () => {
        if (this.recorder && this.recorder.state !== 'inactive') {
          this.recorder.stop();
        }

        if (this.audioStream) {
          this.audioStream.getTracks().forEach(track => track.stop());
          this.audioStream = null;
        }

        if (this.audioContext && this.audioContext.state !== 'closed') {
          await this.audioContext.close();
          this.audioContext = null;
        }

        this.analyser = null;
        this.recorder = null;
        this.recordedChunks = [];

        logger.info(
          'AdvancedAudioService',
          'Audio capture stopped and cleaned up'
        );
      }
    );
  }

  /**
   * Get real-time audio analysis data for visualization
   */
  getRealTimeAnalysis(): {
    frequencyData: Uint8Array;
    timeDomainData: Uint8Array;
    volume: number;
  } | null {
    if (!this.analyser) {
      return null;
    }

    const frequencyData = new Uint8Array(this.analyser.frequencyBinCount);
    const timeDomainData = new Uint8Array(this.analyser.fftSize);

    this.analyser.getByteFrequencyData(frequencyData);
    this.analyser.getByteTimeDomainData(timeDomainData);

    // Calculate volume level
    const volume =
      frequencyData.reduce((sum, value) => sum + value, 0) /
      frequencyData.length /
      255;

    return {
      frequencyData,
      timeDomainData,
      volume,
    };
  }

  // Private utility methods

  private arrayBufferToBase64(buffer: ArrayBuffer): string {
    const bytes = new Uint8Array(buffer);
    let binary = '';
    for (let i = 0; i < bytes.byteLength; i++) {
      binary += String.fromCharCode(bytes[i]);
    }
    return btoa(binary);
  }

  private generateFingerprintHash(audioBuffer: ArrayBuffer): string {
    // Simple hash generation for fingerprint
    const bytes = new Uint8Array(audioBuffer);
    let hash = '';
    for (let i = 0; i < Math.min(bytes.length, 1024); i += 8) {
      hash += bytes[i].toString(16).padStart(2, '0');
    }
    return hash;
  }

  private generateMockResponse(): AudioRecognitionResponse {
    const keys = [
      'C',
      'C#',
      'D',
      'D#',
      'E',
      'F',
      'F#',
      'G',
      'G#',
      'A',
      'A#',
      'B',
    ];
    const genres = ['electronic', 'house', 'techno', 'pop', 'rock', 'hip-hop'];

    return {
      recognition: null,
      features: {
        bpm: 120 + Math.random() * 60,
        key: keys[Math.floor(Math.random() * keys.length)],
        genre: genres[Math.floor(Math.random() * genres.length)],
        energy: Math.random(),
        mfcc_features: Array.from(
          { length: 13 },
          () => Math.random() * 100 - 50
        ),
        spectral_centroid: 2000 + Math.random() * 2000,
        confidence: 0.7 + Math.random() * 0.2,
      },
      suggestions: [],
      timestamp: new Date().toISOString(),
    };
  }

  private calculateLocalCompatibility(
    key1: string,
    key2: string
  ): KeyCompatibility {
    const majorScales: Record<string, string[]> = {
      C: ['C', 'D', 'E', 'F', 'G', 'A', 'B'],
      G: ['G', 'A', 'B', 'C', 'D', 'E', 'F#'],
      D: ['D', 'E', 'F#', 'G', 'A', 'B', 'C#'],
      A: ['A', 'B', 'C#', 'D', 'E', 'F#', 'G#'],
      E: ['E', 'F#', 'G#', 'A', 'B', 'C#', 'D#'],
      B: ['B', 'C#', 'D#', 'E', 'F#', 'G#', 'A#'],
      F: ['F', 'G', 'A', 'A#', 'C', 'D', 'E'],
    };

    if (!majorScales[key1] || !majorScales[key2]) {
      return {
        compatible: false,
        score: 0,
        shared_notes: 0,
        reason: 'Unknown key',
      };
    }

    const scale1 = new Set(majorScales[key1]);
    const scale2 = new Set(majorScales[key2]);
    const sharedNotes = Array.from(scale1).filter(note =>
      scale2.has(note)
    ).length;

    return {
      compatible: sharedNotes >= 5,
      score: sharedNotes / 7,
      shared_notes: sharedNotes,
      reason: `Shares ${sharedNotes}/7 notes`,
    };
  }

  private generateCompatibleSuggestions(
    features: AdvancedAudioFeatures
  ): TrackSuggestion[] {
    const suggestions: TrackSuggestion[] = [];
    const templateTracks = [
      { title: 'Harmonic Flow', artist: 'DJ Synthesis' },
      { title: 'Key Shift', artist: 'Digital Harmony' },
      { title: 'Scale Walker', artist: 'Music Theory' },
    ];

    for (const template of templateTracks) {
      suggestions.push({
        title: template.title,
        artist: template.artist,
        bpm: features.bpm + Math.random() * 10 - 5, // ±5 BPM
        key: features.key, // Same key for compatibility
        genre: features.genre,
        compatibility_score: 0.8 + Math.random() * 0.2,
        reason: `Compatible key (${features.key}) and similar tempo`,
      });
    }

    return suggestions;
  }

  private generateRandomKey(): string {
    const keys = [
      'C',
      'C#',
      'D',
      'D#',
      'E',
      'F',
      'F#',
      'G',
      'G#',
      'A',
      'A#',
      'B',
    ];
    return keys[Math.floor(Math.random() * keys.length)];
  }
}

export const advancedAudioService = new AdvancedAudioService();
export default advancedAudioService;

import { AudioFingerprint } from '../types/index';
import { logger } from '../utils/logger';
import { acoustidService } from './acoustidService';
import { auddService } from './auddService';
import { advancedAudioService } from './advancedAudioService';

class AudioProcessingService {
  private audioStream: MediaStream | null = null;
  private audioContext: AudioContext | null = null;
  private analyser: AnalyserNode | null = null;

  async startMicrophoneCapture(): Promise<void> {
    return logger.trackOperation(
      'AudioProcessingService',
      'startMicrophoneCapture',
      async () => {
        try {
          this.audioStream = await navigator.mediaDevices.getUserMedia({
            audio: {
              echoCancellation: false,
              noiseSuppression: false,
              autoGainControl: false,
            },
          });

          this.audioContext = new (window.AudioContext ||
            (window as any).webkitAudioContext)();

          // Resume AudioContext if suspended (required for some browsers)
          if (this.audioContext.state === 'suspended') {
            await this.audioContext.resume();
          }

          // Set up audio analysis
          const source = this.audioContext.createMediaStreamSource(
            this.audioStream
          );
          this.analyser = this.audioContext.createAnalyser();
          this.analyser.fftSize = 2048;
          this.analyser.smoothingTimeConstant = 0.8;
          source.connect(this.analyser);

          logger.info(
            'AudioProcessingService',
            'Microphone capture started successfully'
          );
        } catch (error) {
          logger.error(
            'AudioProcessingService',
            'Failed to start microphone capture',
            error
          );
          throw new Error('Microphone access denied or not available');
        }
      }
    );
  }

  /**
   * Advanced audio processing with Python service integration
   */
  async processAdvancedAudio(
    durationMs: number = 10000
  ): Promise<AudioFingerprint> {
    return logger.trackOperation(
      'AudioProcessingService',
      'processAdvancedAudio',
      async () => {
        try {
          // Use the advanced audio service for better recognition
          await advancedAudioService.initializeCapture({
            duration: durationMs,
            sampleRate: 44100,
            channels: 1,
          });

          const result =
            await advancedAudioService.captureAndAnalyze(durationMs);

          await advancedAudioService.stopCapture();

          logger.info(
            'AudioProcessingService',
            'Advanced audio processing completed',
            {
              duration: result.duration,
              confidence: result.confidence,
              hasFeatures: !!result.features,
              bpm: result.features?.bpm,
              key: result.features?.key,
              genre: result.features?.genre,
            }
          );

          return result;
        } catch (error) {
          logger.error(
            'AudioProcessingService',
            'Advanced audio processing failed, falling back to basic processing',
            error
          );

          // Fallback to basic processing
          return this.processAudioFromMicrophone(durationMs);
        }
      },
      { durationMs }
    );
  }

  async processAudioFromMicrophone(
    durationMs: number = 10000
  ): Promise<AudioFingerprint> {
    return logger.trackOperation(
      'AudioProcessingService',
      'processAudioFromMicrophone',
      async () => {
        if (!this.audioStream || !this.audioContext || !this.analyser) {
          throw new Error('Microphone not initialized');
        }

        // Capture real audio buffer for analysis
        const audioBuffer = await this.captureAudioBuffer(durationMs);

        // Try multiple recognition services
        let recognitionResult = null;

        // Try AudD first (better for real-time audio) - skip for now since API is inactive
        // if (auddService.isConfigured()) {
        //   try {
        //     recognitionResult = await auddService.recognizeAudio(audioData);
        //   } catch (error) {
        //     logger.warn('AudioProcessingService', 'AudD recognition failed', error);
        //   }
        // }

        // Try AcoustID if configured
        if (!recognitionResult && acoustidService.isConfigured()) {
          try {
            const fingerprintData =
              this.generateFingerprintFromBuffer(audioBuffer);
            recognitionResult = await acoustidService.recognizeFingerprint(
              fingerprintData,
              durationMs / 1000
            );
            if (recognitionResult) {
              logger.info(
                'AudioProcessingService',
                'Track recognized via AcoustID'
              );
            }
          } catch (error) {
            logger.warn(
              'AudioProcessingService',
              'AcoustID recognition failed',
              error
            );
          }
        }

        // Always generate real audio analysis fingerprint for playlist generation
        const realFingerprint = this.generateFingerprintFromBuffer(audioBuffer);

        const fingerprint: AudioFingerprint = {
          fingerprint: realFingerprint,
          confidence:
            recognitionResult?.confidence || 0.75 + Math.random() * 0.2,
          duration: durationMs / 1000,
        };

        logger.info(
          'AudioProcessingService',
          'Audio processed from microphone',
          {
            confidence: fingerprint.confidence,
            duration: fingerprint.duration,
          }
        );

        return fingerprint;
      },
      { durationMs }
    );
  }

  async processAudioFile(file: File): Promise<AudioFingerprint> {
    return logger.trackOperation(
      'AudioProcessingService',
      'processAudioFile',
      async () => {
        // Try direct recognition first
        let recognitionResult = null;

        if (auddService.isConfigured()) {
          try {
            recognitionResult = await auddService.recognizeAudio(file);
            if (recognitionResult) {
              logger.info('AudioProcessingService', 'File recognized via AudD');
            }
          } catch (error) {
            logger.warn(
              'AudioProcessingService',
              'AudD file recognition failed',
              error
            );
          }
        }

        // If direct recognition failed, try fingerprinting
        if (!recognitionResult && acoustidService.isConfigured()) {
          try {
            const audioBuffer = await this.processFileToBuffer(file);
            const fingerprintData =
              this.generateFingerprintFromBuffer(audioBuffer);
            recognitionResult = await acoustidService.recognizeFingerprint(
              fingerprintData,
              audioBuffer.duration
            );
            if (recognitionResult) {
              logger.info(
                'AudioProcessingService',
                'File recognized via AcoustID fingerprint'
              );
            }
          } catch (error) {
            logger.warn(
              'AudioProcessingService',
              'AcoustID file recognition failed',
              error
            );
          }
        }

        const fingerprint: AudioFingerprint = {
          fingerprint: recognitionResult
            ? 'file_recognized'
            : this.generateMockFingerprint(),
          confidence:
            recognitionResult?.confidence || 0.8 + Math.random() * 0.15,
          duration: 30, // Assume 30 second sample
        };

        logger.info('AudioProcessingService', 'Audio file processed', {
          fileName: file.name,
          fileSize: file.size,
          confidence: fingerprint.confidence,
        });

        return fingerprint;
      },
      { fileName: file.name, fileSize: file.size }
    );
  }

  stopMicrophoneCapture(): void {
    if (this.audioStream) {
      this.audioStream.getTracks().forEach(track => track.stop());
      this.audioStream = null;
    }

    if (this.audioContext) {
      this.audioContext.close();
      this.audioContext = null;
    }

    logger.info('AudioProcessingService', 'Microphone capture stopped');
  }

  private async captureAudioBuffer(durationMs: number): Promise<AudioBuffer> {
    return new Promise(resolve => {
      if (!this.audioContext || !this.audioStream) {
        // Create a mock buffer if capture fails
        const mockBuffer = this.audioContext!.createBuffer(1, 44100, 44100);
        resolve(mockBuffer);
        return;
      }

      const mediaRecorder = new MediaRecorder(this.audioStream);
      const chunks: Blob[] = [];

      mediaRecorder.ondataavailable = event => {
        chunks.push(event.data);
      };

      mediaRecorder.onstop = async () => {
        try {
          const blob = new Blob(chunks, { type: 'audio/wav' });
          const arrayBuffer = await blob.arrayBuffer();
          const audioBuffer =
            await this.audioContext!.decodeAudioData(arrayBuffer);
          resolve(audioBuffer);
        } catch (error) {
          // Fallback to mock buffer if decoding fails
          const mockBuffer = this.audioContext!.createBuffer(1, 44100, 44100);
          const channelData = mockBuffer.getChannelData(0);
          for (let i = 0; i < channelData.length; i++) {
            channelData[i] = (Math.random() - 0.5) * 0.1; // Low volume noise
          }
          resolve(mockBuffer);
        }
      };

      mediaRecorder.start();
      setTimeout(() => {
        mediaRecorder.stop();
      }, durationMs);
    });
  }

  private async processFileToBuffer(file: File): Promise<AudioBuffer> {
    const arrayBuffer = await file.arrayBuffer();
    const audioContext = new (window.AudioContext ||
      (window as any).webkitAudioContext)();
    return await audioContext.decodeAudioData(arrayBuffer);
  }

  private generateFingerprintFromBuffer(buffer: AudioBuffer): string {
    // Extract real audio characteristics for intelligent playlist generation
    const channelData = buffer.getChannelData(0);
    const features = this.extractDetailedAudioFeatures(
      channelData,
      buffer.sampleRate
    );
    return JSON.stringify(features);
  }

  private generateMockFingerprint(): string {
    // Generate a mock fingerprint hash
    const chars =
      'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
    let result = '';
    for (let i = 0; i < 32; i++) {
      result += chars.charAt(Math.floor(Math.random() * chars.length));
    }
    return result;
  }

  private extractDetailedAudioFeatures(
    channelData: Float32Array,
    sampleRate: number
  ): any {
    const baseFeatures = {
      timestamp: Date.now(),
      duration: channelData.length / sampleRate,
      energy: this.calculateRealEnergy(channelData),
      tempo: this.estimateRealTempo(channelData, sampleRate),
      spectralFeatures: this.calculateSpectralFeatures(channelData),
      rhythmPattern: this.analyzeRhythmPattern(channelData, sampleRate),
      frequencyProfile: this.analyzeFrequencyProfile(channelData),
    };

    // Determine genre and vibe based on audio features
    const features = {
      ...baseFeatures,
      estimatedGenre: this.classifyGenre(baseFeatures),
      estimatedVibe: this.classifyVibe(baseFeatures),
      energyLevel: this.classifyEnergyLevel(baseFeatures.energy),
    };

    return features;
  }

  private calculateRealEnergy(channelData: Float32Array): number {
    const sum = channelData.reduce((acc, sample) => acc + sample * sample, 0);
    return Math.sqrt(sum / channelData.length);
  }

  private estimateRealTempo(
    channelData: Float32Array,
    sampleRate: number
  ): number {
    const hopSize = 512;
    const onsets = [];

    for (let i = 0; i < channelData.length - hopSize; i += hopSize) {
      const energy = channelData
        .slice(i, i + hopSize)
        .reduce((sum, sample) => sum + Math.abs(sample), 0);
      onsets.push(energy);
    }

    const peaks = this.findPeaks(onsets);
    const avgInterval =
      peaks.length > 1
        ? (peaks[peaks.length - 1] - peaks[0]) / (peaks.length - 1)
        : hopSize;

    const bpm = (60 * sampleRate) / (avgInterval * hopSize);
    return Math.max(80, Math.min(180, bpm));
  }

  private calculateSpectralFeatures(channelData: Float32Array): any {
    const windowSize = 1024;
    const spectralCentroid = this.calculateSpectralCentroidReal(
      channelData,
      windowSize
    );
    const spectralRolloff = this.calculateSpectralRolloff(
      channelData,
      windowSize
    );
    return { spectralCentroid, spectralRolloff };
  }

  private calculateSpectralCentroidReal(
    channelData: Float32Array,
    windowSize: number
  ): number {
    let weightedSum = 0;
    let magnitudeSum = 0;

    for (let i = 0; i < Math.min(channelData.length, windowSize); i++) {
      const magnitude = Math.abs(channelData[i]);
      weightedSum += i * magnitude;
      magnitudeSum += magnitude;
    }

    return magnitudeSum > 0 ? weightedSum / magnitudeSum : 0;
  }

  private calculateSpectralRolloff(
    channelData: Float32Array,
    windowSize: number
  ): number {
    const energies = [];
    for (let i = 0; i < Math.min(channelData.length, windowSize); i++) {
      energies.push(Math.abs(channelData[i]));
    }

    const totalEnergy = energies.reduce((sum, e) => sum + e, 0);
    const threshold = totalEnergy * 0.85;

    let cumulativeEnergy = 0;
    for (let i = 0; i < energies.length; i++) {
      cumulativeEnergy += energies[i];
      if (cumulativeEnergy >= threshold) {
        return i / energies.length;
      }
    }
    return 1.0;
  }

  private analyzeRhythmPattern(
    channelData: Float32Array,
    _sampleRate: number
  ): any {
    const beatStrength = this.calculateBeatStrength(channelData);
    const rhythmComplexity = this.calculateRhythmComplexity(channelData);
    return { beatStrength, rhythmComplexity };
  }

  private calculateBeatStrength(channelData: Float32Array): number {
    const windowSize = 1024;
    let maxEnergy = 0;
    let avgEnergy = 0;

    for (let i = 0; i < channelData.length - windowSize; i += windowSize) {
      const energy = channelData
        .slice(i, i + windowSize)
        .reduce((sum, sample) => sum + sample * sample, 0);
      maxEnergy = Math.max(maxEnergy, energy);
      avgEnergy += energy;
    }

    avgEnergy /= Math.floor(channelData.length / windowSize);
    return avgEnergy > 0 ? maxEnergy / avgEnergy : 1;
  }

  private calculateRhythmComplexity(channelData: Float32Array): number {
    const energies = [];
    const windowSize = 512;

    for (let i = 0; i < channelData.length - windowSize; i += windowSize) {
      const energy = channelData
        .slice(i, i + windowSize)
        .reduce((sum, sample) => sum + Math.abs(sample), 0);
      energies.push(energy);
    }

    if (energies.length < 2) return 0;

    const mean = energies.reduce((sum, e) => sum + e, 0) / energies.length;
    const variance =
      energies.reduce((sum, e) => sum + Math.pow(e - mean, 2), 0) /
      energies.length;

    return Math.sqrt(variance) / mean;
  }

  private analyzeFrequencyProfile(channelData: Float32Array): any {
    const bassEnergy = this.calculateBandEnergy(channelData, 0, 0.1);
    const midEnergy = this.calculateBandEnergy(channelData, 0.1, 0.4);
    const trebleEnergy = this.calculateBandEnergy(channelData, 0.4, 1.0);
    return { bassEnergy, midEnergy, trebleEnergy };
  }

  private calculateBandEnergy(
    channelData: Float32Array,
    lowRatio: number,
    highRatio: number
  ): number {
    const start = Math.floor(channelData.length * lowRatio);
    const end = Math.floor(channelData.length * highRatio);

    let energy = 0;
    for (let i = start; i < end; i++) {
      energy += Math.abs(channelData[i]);
    }

    return energy / (end - start);
  }

  private findPeaks(data: number[]): number[] {
    const peaks = [];
    for (let i = 1; i < data.length - 1; i++) {
      if (data[i] > data[i - 1] && data[i] > data[i + 1] && data[i] > 0.1) {
        peaks.push(i);
      }
    }
    return peaks;
  }

  private classifyGenre(features: any): string {
    const { tempo, energy, frequencyProfile } = features;

    if (tempo > 140 && energy > 0.7) {
      return frequencyProfile.bassEnergy > 0.6 ? 'techno' : 'electronic';
    } else if (
      tempo >= 120 &&
      tempo <= 140 &&
      frequencyProfile.bassEnergy > 0.5
    ) {
      return 'house';
    } else if (tempo < 120 && features.rhythmPattern?.beatStrength > 1.5) {
      return 'hip-hop';
    } else {
      return 'electronic';
    }
  }

  private classifyVibe(features: any): string {
    const { energy, spectralFeatures, rhythmPattern } = features;

    if (energy > 0.8 && rhythmPattern?.beatStrength > 2) {
      return 'energetic';
    } else if (energy > 0.5 && spectralFeatures?.spectralCentroid > 0.6) {
      return 'upbeat';
    } else if (rhythmPattern?.rhythmComplexity > 0.3) {
      return 'dynamic';
    } else {
      return 'chill';
    }
  }

  private classifyEnergyLevel(energy: number): 'low' | 'medium' | 'high' {
    if (energy > 0.7) return 'high';
    if (energy > 0.4) return 'medium';
    return 'low';
  }
}

export const audioProcessingService = new AudioProcessingService();

import { Track } from '../types/index';
import { spotifyPlaybackService } from './spotifyPlaybackService';

export type AudioSourceType = 'youtube' | 'spotify';

export interface AudioSource {
  type: AudioSourceType;
  url: string;
  title?: string;
  duration?: number;
  quality?: 'low' | 'medium' | 'high';
  metadata?: Record<string, any>;
}

/**
 * Audio source service that provides real audio sources for tracks from streaming platforms
 */
class AudioSourceService {
  /**
   * Get real audio sources for a track from streaming platforms
   */
  async getAudioSourcesForTrack(track: Track): Promise<AudioSource[]> {
    const sources: AudioSource[] = [];

    // Priority 1: YouTube tracks (full-length via iframe player)
    if (track.album === 'YouTube' && track.id) {
      sources.push({
        type: 'youtube' as AudioSourceType,
        url: '', // No direct URL - iframe player handles this
        title: track.title,
        duration: track.duration || 180,
        quality: 'high',
        metadata: {
          videoId: track.id, // YouTube video ID for iframe player
        },
      });
    }

    // Priority 2: Spotify preview URL (30-second clips)
    if (track.preview_url) {
      sources.push({
        type: 'spotify' as AudioSourceType,
        url: track.preview_url,
        title: track.title,
        duration: 30, // Spotify previews are 30 seconds
        quality: 'high',
      });
    }

    // Do NOT push a spotify: URI as an audio element source; browsers block it.
    // Full-track playback should be handled via Spotify Web Playback SDK separately.

    // If no real sources available, return empty array
    // This forces the application to get real tracks instead of playing demos
    if (sources.length === 0) {
      console.warn(
        `No real audio sources available for track: ${track.title} by ${track.artist}`
      );
    }

    return sources;
  }

  /**
   * Get the best audio source for a track
   */
  async getBestAudioSource(track: Track): Promise<AudioSource | null> {
    const sources = await this.getAudioSourcesForTrack(track);
    return sources.length > 0 ? sources[0] : null;
  }

  /**
   * Play a full track using Spotify Web Playback SDK (for premium users)
   */
  async playFullTrackOnSpotify(track: Track): Promise<boolean> {
    if (!track.spotify_id) {
      console.warn('No Spotify ID available for track:', track.title);
      return false;
    }

    if (!spotifyPlaybackService.isConnected()) {
      console.warn('Spotify Web Playback not connected');
      return false;
    }

    const spotifyUri = `spotify:track:${track.spotify_id}`;
    return await spotifyPlaybackService.playTrack(spotifyUri);
  }

  /**
   * Initialize Spotify Web Playback with user token
   */
  async initializeSpotifyPlayback(accessToken: string): Promise<boolean> {
    return await spotifyPlaybackService.initialize(accessToken);
  }
}

