const CACHE_TTL_MS = 5 * 60 * 1000; // 5 minutes
const MAX_PLAYLIST_NAME_LENGTH = 100;
const MAX_DESCRIPTION_LENGTH = 500;
const MAX_TRACKS_PER_PLAYLIST = 1000;
