// Supabase playlist service - Improved version
import { supabase, getCurrentUserId } from '../lib/supabase';
import { AppError } from '../utils/errors';
import { logger } from '../utils/logger';

// Types for better type safety
interface Track {
  id?: string;
  title: string;
  artist: string;
  bpm?: number;
  energy?: number;
  duration?: number;
  url?: string;
  source_url?: string;
  // Optional metadata commonly present from generators/providers
  key?: string;
  genre?: string;
  position?: number;
  spotify_id?: string | null;
  youtube_id?: string | null;
  preview_url?: string | null;
  thumbnail?: string | null;
}

interface Playlist {
  id?: string;
  name: string;
  user_id?: string;
  description?: string;
  tracks?: Track[];
  created_at?: string;
  updated_at?: string;
}

interface CacheEntry {
  data: any;
  expiry: number;
}

// Enhanced cache management
class PlaylistCache {
  private cache = new Map<string, CacheEntry>();
  private readonly TTL_MS = 15_000; // 15 seconds

  get(key: string): any | null {
    const entry = this.cache.get(key);
    if (entry && Date.now() < entry.expiry) {
      return entry.data;
    }
    if (entry) {
      this.cache.delete(key);
    }
    return null;
  }

  set(key: string, data: any): void {
    this.cache.set(key, {
      data,
      expiry: Date.now() + this.TTL_MS,
    });
  }

  delete(key: string): void {
    this.cache.delete(key);
  }

  // Bust all playlist caches for a user
  bustUserCache(userId: string): void {
    const userKey = this.getUserPlaylistsKey(userId);
    this.delete(userKey);
  }

  // Bust all playlist caches (when we don't know the user)
  bustAllPlaylistCaches(): void {
    for (const key of this.cache.keys()) {
      if (key.startsWith('playlists:')) {
        this.cache.delete(key);
      }
    }
  }

  private getUserPlaylistsKey(userId: string): string {
    return `playlists:${userId}`;
  }
}

const cache = new PlaylistCache();

// Authentication helper
class AuthHelper {
  static async checkAuthentication(
    retries = 3
  ): Promise<{ isAuthenticated: boolean; session: any }> {
    for (let i = 0; i < retries; i++) {
      try {
        const { data: sessionData } = await supabase.auth.getSession();
        const session = sessionData?.session;
        const isAuthenticated = !!(session?.access_token && session?.user);

        // If auth is ready or this is the last retry, return the result
        if (isAuthenticated || i === retries - 1) {
          return { isAuthenticated, session };
        }

        // Wait before retrying if authentication is not ready
        await new Promise(resolve => setTimeout(resolve, 100));
      } catch (error) {
        logger.error(
          'supabasePlaylistService',
          'Authentication check failed',
          error as any
        );
        if (i === retries - 1) {
          return { isAuthenticated: false, session: null };
        }
        await new Promise(resolve => setTimeout(resolve, 100));
      }
    }

    return { isAuthenticated: false, session: null };
  }

  static handleUnauthenticated(operation: string, fallbackValue: any = null) {
    logger.warn(
      'supabasePlaylistService',
      `Supabase not authenticated; skipping ${operation}.`
    );
    return fallbackValue;
  }
}

// Data validation helpers
class ValidationHelper {
  static validatePlaylist(playlist: Partial<Playlist>): void {
    if (!playlist.name || !playlist.name.trim()) {
      throw new AppError('BAD_REQUEST', 'Playlist name is required');
    }
  }

  static validateUserId(userId: string): void {
    if (!userId) {
      throw new AppError('BAD_REQUEST', 'User ID is required');
    }
  }

  static sanitizeTrackData(tracks: Track[], playlistId: string) {
    return tracks
      .map(track => ({
        playlist_id: playlistId,
        title: track.title || 'Untitled',
        artist: track.artist || 'Unknown Artist',
        bpm: typeof track.bpm === 'number' ? Math.floor(track.bpm) : null,
        energy:
          typeof track.energy === 'number' ? Math.floor(track.energy) : null,
        duration:
          typeof track.duration === 'number' ? Math.floor(track.duration) : 180,
        key: (track as any).key || null,
        genre: (track as any).genre || null,
        position:
          typeof (track as any).position === 'number'
            ? (track as any).position
            : null,
        spotify_id: (track as any).spotify_id ?? null,
        youtube_id: (track as any).youtube_id ?? null,
        preview_url: (track as any).preview_url ?? null,
        thumbnail: (track as any).thumbnail ?? null,
        source_url:
          (track as any).source_url ||
          track.url ||
          (track as any).youtube_url ||
          (track as any).preview_url ||
          null,
      }))
      .filter(row => row.title);
  }
}

export const supabasePlaylistService = {
  async savePlaylist(playlist: Playlist, userId: string): Promise<Playlist> {
    try {
      ValidationHelper.validatePlaylist(playlist);

      // For now, use a default user ID if none provided to test save functionality
      const saveUserId = userId || 'anonymous-user';

      logger.info('supabasePlaylistService', 'Saving playlist', {
        playlistId: playlist.id,
        name: playlist.name,
        userId: saveUserId,
        trackCount: playlist.tracks?.length || 0,
      });

      const result = await this._savePlaylistToDatabase(playlist, saveUserId);
      cache.bustUserCache(saveUserId);

      return result;
    } catch (error) {
      logger.error(
        'supabasePlaylistService',
        'SavePlaylist error',
        error as any
      );
      throw error;
    }
  },

  async _savePlaylistToDatabase(
    playlist: Playlist,
    userId: string
  ): Promise<Playlist> {
    const { id: playlistId, name, tracks = [] } = playlist;

    // Generate a proper UUID if the ID is not a valid UUID format
    const isValidUUID =
      /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(
        playlistId || ''
      );
    const finalPlaylistId = playlistId && isValidUUID ? playlistId : undefined;

    // Save playlist
    const playlistPayload = {
      id: finalPlaylistId,
      name: name.trim(),
      user_id: userId,
      description: playlist.description || null,
    };

    const { data: playlistData, error: playlistError } = await supabase
      .from('playlists')
      .upsert(playlistPayload)
      .select()
      .single();

    if (playlistError) {
      logger.error(
        'supabasePlaylistService',
        'Supabase playlist save error',
        playlistError as any
      );
      throw new AppError('UPSTREAM_ERROR', 'Failed to save playlist', {
        details: { playlistError },
      });
    }

    logger.info('supabasePlaylistService', 'Playlist saved', playlistData);

    // Save tracks if provided
    if (tracks.length > 0) {
      await this._saveTracksToDatabase(tracks, playlistData.id);
    }

    return { ...playlistData, tracks };
  },

  async _saveTracksToDatabase(
    tracks: Track[],
    playlistId: string
  ): Promise<void> {
    const trackData = ValidationHelper.sanitizeTrackData(tracks, playlistId);

    if (trackData.length === 0) return;

    // Group tracks by available conflict keys for idempotent upserts
    const spotifyGroup = trackData.filter(t => t.spotify_id);
    const youtubeGroup = trackData.filter(t => !t.spotify_id && t.youtube_id);
    const positionGroup = trackData.filter(
      t => !t.spotify_id && !t.youtube_id && typeof t.position === 'number'
    );
    const insertGroup = trackData.filter(
      t =>
        !spotifyGroup.includes(t) &&
        !youtubeGroup.includes(t) &&
        !positionGroup.includes(t)
    );

    let saved = 0;

    // Upsert by (playlist_id, spotify_id)
    if (spotifyGroup.length > 0) {
      const { error } = await supabase.from('tracks').upsert(spotifyGroup);
      if (error) {
        logger.error(
          'supabasePlaylistService',
          'Tracks upsert error (spotify_id)',
          error as any
        );
      } else {
        saved += spotifyGroup.length;
      }
    }

    // Upsert by (playlist_id, youtube_id)
    if (youtubeGroup.length > 0) {
      const { error } = await supabase.from('tracks').upsert(youtubeGroup);
      if (error) {
        logger.error(
          'supabasePlaylistService',
          'Tracks upsert error (youtube_id)',
          error as any
        );
      } else {
        saved += youtubeGroup.length;
      }
    }

    // Upsert by (playlist_id, position)
    if (positionGroup.length > 0) {
      const { error } = await supabase.from('tracks').upsert(positionGroup);
      if (error) {
        logger.error(
          'supabasePlaylistService',
          'Tracks upsert error (position)',
          error as any
        );
      } else {
        saved += positionGroup.length;
      }
    }

    // Fallback insert for items without any conflict key
    if (insertGroup.length > 0) {
      const { error } = await supabase.from('tracks').insert(insertGroup);
      if (error) {
        logger.error(
          'supabasePlaylistService',
          'Tracks insert error (no conflict key)',
          error as any
        );
      } else {
        saved += insertGroup.length;
      }
    }

    logger.info(
      'supabasePlaylistService',
      `Saved/Upserted ${saved} tracks (playlist ${playlistId})`
    );
  },

  async getPlaylists(userId: string): Promise<Playlist[]> {
    const cacheKey = `playlists:${userId}`;
    const cached = cache.get(cacheKey);

    if (cached) {
      return cached;
    }

    try {
      ValidationHelper.validateUserId(userId);

      // Wait a bit longer for authentication to be fully established
      await new Promise(resolve => setTimeout(resolve, 200));

      const { isAuthenticated, session } =
        await AuthHelper.checkAuthentication();
      const authUserId = await getCurrentUserId();

      logger.info('supabasePlaylistService', 'Auth check for playlists', {
        isAuthenticated,
        authUserId,
        requestedUserId: userId,
        sessionExists: !!session,
        sessionUserId: session?.user?.id,
      });

      if (authUserId && authUserId !== userId) {
        logger.warn(
          'supabasePlaylistService',
          'Auth/userId mismatch detected during fetch',
          { authUserId, userId }
        );
      }

      if (!isAuthenticated || !session?.user) {
        const emptyResult = AuthHelper.handleUnauthenticated(
          'playlist fetch',
          []
        );
        cache.set(cacheKey, emptyResult);
        return emptyResult;
      }

      // Ensure the session user ID matches the requested user ID
      if (session.user.id !== userId) {
        logger.error('supabasePlaylistService', 'Session user ID mismatch', {
          sessionUserId: session.user.id,
          requestedUserId: userId,
        });
        throw new AppError(
          'UNAUTHORIZED',
          'Authentication mismatch - please sign in again'
        );
      }

      const playlists = await this._fetchPlaylistsFromDatabase(userId);
      cache.set(cacheKey, playlists);

      return playlists;
    } catch (error) {
      logger.error(
        'supabasePlaylistService',
        'Supabase getPlaylists error',
        error as any
      );
      throw new AppError('UPSTREAM_ERROR', 'Failed to fetch playlists', {
        details: { error },
      });
    }
  },

  async _fetchPlaylistsFromDatabase(userId: string): Promise<Playlist[]> {
    // Fetch playlists
    const { data: playlists, error: playlistError } = await supabase
      .from('playlists')
      .select('id, user_id, name, created_at, updated_at')
      .eq('user_id', userId)
      .order('created_at', { ascending: false });

    if (playlistError) {
      logger.error(
        'supabasePlaylistService',
        'Supabase playlist query error',
        playlistError as any
      );

      // Provide more specific error messages for common auth issues
      if (
        playlistError.code === '42501' ||
        playlistError.message?.includes('permission denied') ||
        playlistError.message?.includes('Row Level Security') ||
        playlistError.code === 'PGRST301'
      ) {
        // Log additional context for debugging
        logger.error('Context', 'Error message', {
          errorCode: playlistError.code,
          errorMessage: playlistError.message,
          userId,
        }, playlistError.message ?? JSON.stringify(playlistError));

        throw new AppError(
          'UNAUTHORIZED',
          'Access denied: Your session may have expired. Please sign out and sign in again.',
          {
            details: { playlistError },
          }
        );
      }

      throw new AppError('UPSTREAM_ERROR', 'Failed to fetch playlists', {
        details: { playlistError },
      });
    }

    if (!playlists || playlists.length === 0) {
      return [];
    }

    // Fetch tracks for all playlists
    const tracks = await this._fetchTracksForPlaylists(
      playlists.map(p => p.id)
    );

    // Combine playlists with tracks
    return this._combinePlaylistsWithTracks(playlists, tracks);
  },

  async _fetchTracksForPlaylists(playlistIds: string[]): Promise<Track[]> {
    const { data: tracks, error: tracksError } = await supabase
      .from('tracks')
      .select('id, playlist_id, title, artist, bpm, energy, duration')
      .in('playlist_id', playlistIds)
      .order('created_at', { ascending: true });

    if (tracksError) {
      logger.error(
        'supabasePlaylistService',
        'Supabase tracks query error',
        tracksError as any
      );
      return []; // Return empty array rather than failing
    }

    return tracks || [];
  },

  _combinePlaylistsWithTracks(playlists: any[], tracks: Track[]): Playlist[] {
    // Group tracks by playlist ID
    const tracksByPlaylist = tracks.reduce(
      (acc: Record<string, Track[]>, track: any) => {
        if (!acc[track.playlist_id]) {
          acc[track.playlist_id] = [];
        }

        acc[track.playlist_id].push({
          id: track.id,
          title: track.title,
          artist: track.artist,
          bpm: track.bpm ?? undefined,
          energy:
            typeof track.energy === 'number' ? Number(track.energy) : undefined,
          duration: track.duration ?? 180,
        });

        return acc;
      },
      {}
    );

    // Combine playlists with their tracks
    return playlists.map(playlist => ({
      ...playlist,
      tracks: tracksByPlaylist[playlist.id] || [],
    }));
  },

  async createPlaylist(userId: string, name: string): Promise<Playlist> {
    try {
      ValidationHelper.validateUserId(userId);

      if (!name || !name.trim()) {
        throw new AppError('BAD_REQUEST', 'Playlist name is required');
      }

      const { isAuthenticated } = await AuthHelper.checkAuthentication();

      if (!isAuthenticated) {
        return AuthHelper.handleUnauthenticated('remote create', {
          id: `local-${Date.now()}`,
          user_id: userId,
          name: name.trim(),
          created_at: new Date().toISOString(),
          tracks: [],
        });
      }

      const authUserId = await getCurrentUserId();
      if (authUserId && authUserId !== userId) {
        logger.warn(
          'supabasePlaylistService',
          'Auth/userId mismatch detected during create',
          { authUserId, userId }
        );
      }

      const { data, error } = await supabase
        .from('playlists')
        .insert([{ user_id: userId, name: name.trim() }])
        .select()
        .single();

      if (error) {
        throw new AppError('UPSTREAM_ERROR', 'Failed to create playlist', {
          details: { error },
        });
      }

      cache.bustUserCache(userId);
      return { ...data, tracks: [] };
    } catch (error) {
      logger.error(
        'supabasePlaylistService',
        'Create playlist error',
        error as any
      );
      throw error;
    }
  },

  async deletePlaylist(playlistId: string, userId?: string): Promise<boolean> {
    try {
      if (!playlistId) {
        throw new AppError('BAD_REQUEST', 'Playlist ID is required');
      }

      const { isAuthenticated } = await AuthHelper.checkAuthentication();

      if (!isAuthenticated) {
        return AuthHelper.handleUnauthenticated('remote delete', false);
      }

      const query = supabase.from('playlists').delete().eq('id', playlistId);

      // Scope delete to owner if userId provided (defense-in-depth with RLS)
      const { error } = userId
        ? await query.eq('user_id', userId)
        : await query;

      if (error) {
        throw new AppError('UPSTREAM_ERROR', 'Failed to delete playlist', {
          details: { error },
        });
      }

      // Efficient cache busting
      if (userId) {
        cache.bustUserCache(userId);
      } else {
        cache.bustAllPlaylistCaches();
      }

      return true;
    } catch (error) {
      logger.error(
        'supabasePlaylistService',
        'Delete playlist error',
        error as any
      );
      throw error;
    }
  },

  // Utility methods
  async updatePlaylist(
    playlistId: string,
    updates: Partial<Playlist>,
    userId: string
  ): Promise<Playlist> {
    try {
      ValidationHelper.validateUserId(userId);

      if (!playlistId) {
        throw new AppError('BAD_REQUEST', 'Playlist ID is required');
      }

      const { isAuthenticated } = await AuthHelper.checkAuthentication();

      if (!isAuthenticated) {
        throw new AppError(
          'UNAUTHORIZED',
          'Authentication required for playlist updates'
        );
      }

      const { data, error } = await supabase
        .from('playlists')
        .update({
          name: updates.name?.trim(),
          description: updates.description,
          updated_at: new Date().toISOString(),
        })
        .eq('id', playlistId)
        .eq('user_id', userId) // Ensure user owns the playlist
        .select()
        .single();

      if (error) {
        throw new AppError('UPSTREAM_ERROR', 'Failed to update playlist', {
          details: { error },
        });
      }

      cache.bustUserCache(userId);
      return data;
    } catch (error) {
      logger.error(
        'supabasePlaylistService',
        'Update playlist error',
        error as any
      );
      throw error;
    }
  },

  // Clear all caches (useful for logout)
  clearCache(): void {
    cache.bustAllPlaylistCaches();
  },
};

import { Track } from '../types';
import { logger } from '../utils/logger';
import { fetchWithRetry } from '../utils/http';
import config from '../config';
// Removed audio fallback imports

// =============================================================================
// TYPE DEFINITIONS & INTERFACES
// =============================================================================

/**
 * Standard error response format for YouTube API errors
 */
interface YouTubeServiceError {
  readonly code: string;
  readonly message: string;
  readonly details?: string;
  readonly retryable: boolean;
}

/**
 * YouTube API Search Response Schema
 */
interface YouTubeSearchResponse {
  readonly items: ReadonlyArray<{
    readonly id: { readonly videoId: string };
    readonly snippet: {
      readonly title: string;
      readonly channelTitle: string;
      readonly description?: string;
      readonly publishedAt: string;
      readonly thumbnails?: {
        readonly default?: { readonly url: string };
        readonly medium?: { readonly url: string };
        readonly high?: { readonly url: string };
      };
    };
  }>;
  readonly nextPageToken?: string;
  readonly prevPageToken?: string;
  readonly pageInfo: {
    readonly totalResults: number;
    readonly resultsPerPage: number;
  };
}

/**
 * YouTube API Video Details Response Schema
 */
interface YouTubeVideoResponse {
  readonly items: ReadonlyArray<{
    readonly id: string;
    readonly contentDetails: {
      readonly duration: string; // ISO 8601 duration format
    };
    readonly snippet: {
      readonly title: string;
      readonly channelTitle: string;
      readonly description: string;
    };
  }>;
}

/**
 * Search parameters for YouTube video search
 */
interface YouTubeSearchParams {
  readonly query: string;
  readonly maxResults?: number;
  readonly pageToken?: string;
  readonly publishedAfter?: string;
  readonly videoCategoryId?: string;
  readonly videoDefinition?: 'any' | 'high' | 'standard';
  readonly videoDuration?: 'any' | 'long' | 'medium' | 'short';
}

/**
 * Recommendation parameters matching the app's interface
 */
interface YouTubeRecommendationParams {
  readonly seed_genres?: readonly string[];
  readonly limit?: number;
  readonly vibe?: string;
  readonly energy?: string;
}

/**
 * Cache entry structure
 */
interface CacheEntry<T> {
  readonly data: T;
  readonly expiry: number;
}

/**
 * Rate limiter state
 */
interface RateLimitState {
  requestCount: number;
  windowStart: number;
}

// =============================================================================
// CONSTANTS & CONFIGURATION
// =============================================================================

const YOUTUBE_API_BASE_URL = 'https://www.googleapis.com/youtube/v3';
const CACHE_TTL_MS = 5 * 60 * 1000; // 5 minutes
const RATE_LIMIT_WINDOW_MS = 60 * 1000; // 1 minute
const RATE_LIMIT_MAX_REQUESTS = 100; // Conservative limit per minute

// =============================================================================
// UTILITY FUNCTIONS
// =============================================================================

/**
 * Converts ISO 8601 duration to seconds
 * @param duration - ISO 8601 duration string (e.g., "PT4M13S")
 * @returns Duration in seconds
 */
function parseDuration(duration: string): number {
  const match = duration.match(/PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+)S)?/);
  if (!match) return 180; // Default 3 minutes

  const hours = parseInt(match[1] || '0', 10);
  const minutes = parseInt(match[2] || '0', 10);
  const seconds = parseInt(match[3] || '0', 10);

  return hours * 3600 + minutes * 60 + seconds;
}

// =============================================================================
// MAIN SERVICE CLASS
// =============================================================================

/**
 * Comprehensive YouTube API service with full error handling, caching,
 * rate limiting, and type safety
 */
export class YouTubeService {
  private readonly apiKey: string;
  private readonly cache = new Map<string, CacheEntry<any>>();
  private rateLimitState: RateLimitState = {
    requestCount: 0,
    windowStart: Date.now(),
  };

  constructor() {
    this.apiKey = config.YOUTUBE_API_KEY;
  }

  // ===========================================================================
  // PUBLIC API METHODS
  // ===========================================================================

  /**
   * Checks if the YouTube service is properly configured with an API key
   * @returns True if API key is available
   */
  public isConfigured(): boolean {
    return Boolean(this.apiKey);
  }

  /**
   * Searches for music videos on YouTube
   * @param params - Search parameters
   * @returns Promise resolving to array of Track objects or null if error
   */
  public async searchTracks(
    params: YouTubeSearchParams
  ): Promise<Track[] | null> {
    try {
      // Input validation
      if (!params.query || params.query.trim().length === 0) {
        logger.warn('YouTubeService', 'Search query is empty');
        return null;
      }

      if (!this.isConfigured()) {
        logger.warn('YouTubeService', 'YouTube API key not configured');
        return null;
      }

      // Rate limiting check
      if (!this.checkRateLimit()) {
        logger.warn('YouTubeService', 'Rate limit exceeded');
        return null;
      }

      // Check cache first
      const cacheKey = `search:${JSON.stringify(params)}`;
      const cached = this.getCached<Track[]>(cacheKey);
      if (cached !== null) {
        logger.debug('YouTubeService', 'Serving search results from cache');
        return cached;
      }

      // Execute search
      const searchResults = await this.executeSearch(params);
      if (!searchResults) {
        return null;
      }

      // Get detailed video information including duration
      const tracks = await this.enrichWithVideoDetails(searchResults);

      // Cache results
      this.setCached(cacheKey, tracks);

      logger.info('YouTubeService', 'Search completed successfully', {
        query: params.query,
        resultCount: tracks.length,
      });

      return tracks;
    } catch (error) {
      logger.error('YouTubeService', 'Search operation failed', error);
      return null;
    }
  }

  /**
   * Gets music recommendations based on genres, vibe, and energy
   * @param params - Recommendation parameters
   * @returns Promise resolving to array of Track objects or null if error
   */
  public async getRecommendations(
    params: YouTubeRecommendationParams
  ): Promise<Track[]> {
    const searchTerms = [
      ...(params.seed_genres || []),
      params.vibe || '',
      params.energy || '',
      'music mix',
    ].filter(Boolean);

    const query =
      searchTerms.length > 0 ? searchTerms.join(' ') : 'electronic music mix';

    const result = await this.searchTracks({
      query,
      maxResults: params.limit || 15,
      videoDuration: 'medium', // Prefer medium-length tracks for DJ sets
    });

    return result || []; // Always return array, never null
  }

  /**
   * No more fallback tracks - if YouTube API fails, we return empty array
   * This forces the app to handle real failures instead of hiding them with fake data
   */
  public async getFallbackTracks(
    seed: string,
    count: number
  ): Promise<Track[]> {
    logger.warn(
      'YouTubeService',
      'YouTube API unavailable - no fallback tracks',
      {
        seed,
        count,
      }
    );
    return [];
  }

  // ===========================================================================
  // PRIVATE IMPLEMENTATION METHODS
  // ===========================================================================

  /**
   * Executes YouTube search API call
   * @param params - Search parameters
   * @returns Search results or null if error
   */
  private async executeSearch(
    params: YouTubeSearchParams
  ): Promise<YouTubeSearchResponse | null> {
    const searchParams = new URLSearchParams({
      part: 'snippet',
      q: params.query,
      type: 'video',
      maxResults: String(params.maxResults || 10),
      key: this.apiKey,
      videoCategory: '10', // Music category
      ...(params.pageToken && { pageToken: params.pageToken }),
      ...(params.publishedAfter && { publishedAfter: params.publishedAfter }),
      ...(params.videoCategoryId && {
        videoCategoryId: params.videoCategoryId,
      }),
      ...(params.videoDefinition && {
        videoDefinition: params.videoDefinition,
      }),
      ...(params.videoDuration && { videoDuration: params.videoDuration }),
    });

    const url = `${YOUTUBE_API_BASE_URL}/search?${searchParams.toString()}`;

    const response = await fetchWithRetry(
      url,
      {
        method: 'GET',
      },
      { timeoutMs: 12000, retries: 2 }
    );

    if (!response.ok) {
      const errorInfo = await this.handleApiError(response);
      logger.error('YouTubeService', 'Search API call failed', errorInfo);
      return null;
    }

    return await response.json();
  }

  /**
   * Enriches search results with detailed video information
   * @param searchResults - Raw search results from YouTube
   * @returns Array of enriched Track objects
   */
  private async enrichWithVideoDetails(
    searchResults: YouTubeSearchResponse
  ): Promise<Track[]> {
    const videoIds = searchResults.items.map(item => item.id.videoId);

    // Batch request for video details
    const videoDetails = await this.getVideoDetails(videoIds);

    return searchResults.items.map(item => {
      const details = videoDetails?.items.find(
        detail => detail.id === item.id.videoId
      );
      const duration = details?.contentDetails.duration
        ? parseDuration(details.contentDetails.duration)
        : 180 + Math.floor(Math.random() * 120);

      return {
        id: item.id.videoId,
        title: item.snippet.title,
        artist: item.snippet.channelTitle,
        album: 'YouTube',
        duration,
        preview_url: undefined, // YouTube URLs cause CORS errors - no direct streaming
        bpm: Math.floor(Math.random() * 60) + 100, // 100-160 BPM
        key: ['C', 'C#', 'D', 'D#', 'E', 'F', 'F#', 'G', 'G#', 'A', 'A#', 'B'][
          Math.floor(Math.random() * 12)
        ],
        energy: 0.5 + Math.random() * 0.5, // 0.5-1.0 for music
        danceability: 0.4 + Math.random() * 0.6, // 0.4-1.0 for music
        valence: Math.random(),
      };
    });
  }

  /**
   * Gets detailed information for multiple videos in a batch request
   * @param videoIds - Array of video IDs
   * @returns Video details or null if error
   */
  private async getVideoDetails(
    videoIds: string[]
  ): Promise<YouTubeVideoResponse | null> {
    if (videoIds.length === 0) return null;

    const detailsParams = new URLSearchParams({
      part: 'contentDetails,snippet',
      id: videoIds.join(','),
      key: this.apiKey,
    });

    const url = `${YOUTUBE_API_BASE_URL}/videos?${detailsParams.toString()}`;

    try {
      const response = await fetchWithRetry(
        url,
        {
          method: 'GET',
        },
        { timeoutMs: 12000, retries: 2 }
      );

      if (!response.ok) {
        logger.warn('YouTubeService', 'Video details request failed', {
          status: response.status,
          statusText: response.statusText,
        });
        return null;
      }

      return await response.json();
    } catch (error) {
      logger.error('YouTubeService', 'Failed to fetch video details', error);
      return null;
    }
  }

  /**
   * Handles YouTube API errors with specific error codes
   * @param response - Failed API response
   * @returns Structured error information
   */
  private async handleApiError(
    response: Response
  ): Promise<YouTubeServiceError> {
    let errorDetails: string = '';

    try {
      const errorBody = await response.text();
      errorDetails = errorBody;
    } catch {
      errorDetails = 'Unable to read error response';
    }

    switch (response.status) {
      case 400:
        return {
          code: 'INVALID_REQUEST',
          message: 'The request was invalid or malformed',
          details: errorDetails,
          retryable: false,
        };

      case 403:
        return {
          code: 'QUOTA_EXCEEDED_OR_FORBIDDEN',
          message: 'API quota exceeded or access forbidden',
          details: errorDetails,
          retryable: true, // Might work later
        };

      case 404:
        return {
          code: 'NOT_FOUND',
          message: 'The requested resource was not found',
          details: errorDetails,
          retryable: false,
        };

      case 429:
        return {
          code: 'RATE_LIMITED',
          message: 'Too many requests, please try again later',
          details: errorDetails,
          retryable: true,
        };

      default:
        return {
          code: 'UNKNOWN_ERROR',
          message: `HTTP ${response.status}: ${response.statusText}`,
          details: errorDetails,
          retryable: true,
        };
    }
  }

  /**
   * Checks if request is within rate limits
   * @returns True if request can proceed
   */
  private checkRateLimit(): boolean {
    const now = Date.now();

    // Reset window if needed
    if (now - this.rateLimitState.windowStart >= RATE_LIMIT_WINDOW_MS) {
      this.rateLimitState = { requestCount: 0, windowStart: now };
    }

    // Check if we can make another request
    if (this.rateLimitState.requestCount >= RATE_LIMIT_MAX_REQUESTS) {
      return false;
    }

    this.rateLimitState.requestCount++;
    return true;
  }

  /**
   * Gets cached data if available and not expired
   * @param key - Cache key
   * @returns Cached data or null
   */
  private getCached<T>(key: string): T | null {
    const entry = this.cache.get(key);

    if (!entry) return null;

    if (Date.now() > entry.expiry) {
      this.cache.delete(key);
      return null;
    }

    return entry.data;
  }

  /**
   * Stores data in cache with expiration
   * @param key - Cache key
   * @param data - Data to cache
   */
  private setCached<T>(key: string, data: T): void {
    this.cache.set(key, {
      data,
      expiry: Date.now() + CACHE_TTL_MS,
    });

    // Periodic cleanup of expired entries
    if (this.cache.size > 100) {
      this.cleanupCache();
    }
  }

  /**
   * Removes expired entries from cache
   */
  private cleanupCache(): void {
    const now = Date.now();

    for (const [key, entry] of this.cache.entries()) {
      if (now > entry.expiry) {
        this.cache.delete(key);
      }
    }
  }
}

