import { createClient } from '@supabase/supabase-js';

// Support both browser (Vite) and serverless (Node) environments
const isBrowser = typeof window !== 'undefined';
// @ts-ignore Node process may be undefined in browser builds
const SUPABASE_URL =
  (typeof process !== 'undefined' &&
    (process?.env?.SUPABASE_URL || process?.env?.VITE_SUPABASE_URL)) ||
  (isBrowser ? (import.meta as any)?.env?.VITE_SUPABASE_URL : undefined);
// @ts-ignore Node process may be undefined in browser builds
const SUPABASE_ANON_KEY =
  (typeof process !== 'undefined' &&
    (process?.env?.SUPABASE_ANON_KEY ||
      process?.env?.VITE_SUPABASE_ANON_KEY)) ||
  (isBrowser ? (import.meta as any)?.env?.VITE_SUPABASE_ANON_KEY : undefined);

const supabase = createClient(
  SUPABASE_URL as string,
  SUPABASE_ANON_KEY as string
);

export async function verifySupabaseJWT(
  authHeader: string
): Promise<{ user: any; error?: string }> {
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return { user: null, error: 'Missing or invalid Authorization header' };
  }

  const token = authHeader.substring(7);

  try {
    const {
      data: { user },
      error,
    } = await supabase.auth.getUser(token);

    if (error || !user) {
      return { user: null, error: 'Invalid token' };
    }

    return { user };
  } catch (error) {
    return { user: null, error: 'Token verification failed' };
  }
}

export function requireAuth(handler: any) {
  return async (req: any, res: any) => {
    const authHeader = req.headers.authorization;
    const { user, error } = await verifySupabaseJWT(authHeader);

    if (error || !user) {
      return res
        .status(401)
        .json({ error: { code: 'UNAUTHORIZED', message: 'Unauthorized' } });
    }

    req.user = user;
    return handler(req, res);
  };
}

export function debounce<T extends (...args: any[]) => any>(
  func: T,
  delay: number
): (...args: Parameters<T>) => void {
  let timeoutId: NodeJS.Timeout;

  return function (...args: Parameters<T>) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => func(...args), delay);
  };
}

export function throttle<T extends (...args: any[]) => any>(
  func: T,
  delay: number
): (...args: Parameters<T>) => void {
  let lastCallTime = 0;
  let timeoutId: NodeJS.Timeout;

  return function (...args: Parameters<T>) {
    const now = Date.now();
    const timeSinceLastCall = now - lastCallTime;

    if (timeSinceLastCall >= delay) {
      lastCallTime = now;
      func(...args);
    } else {
      clearTimeout(timeoutId);
      timeoutId = setTimeout(() => {
        lastCallTime = Date.now();
        func(...args);
      }, delay - timeSinceLastCall);
    }
  };
}

import { logger } from './logger';

export interface AppError {
  code: string;
  message: string;
  userMessage: string;
  severity: 'low' | 'medium' | 'high' | 'critical';
  recoverable: boolean;
  context?: Record<string, any>;
  timestamp: string;
}

export class ErrorHandler {
  private static instance: ErrorHandler;
  private errorQueue: AppError[] = [];
  private maxErrors = 100;

  static getInstance(): ErrorHandler {
    if (!ErrorHandler.instance) {
      ErrorHandler.instance = new ErrorHandler();
    }
    return ErrorHandler.instance;
  }

  private constructor() {
    // Global error handlers
    window.addEventListener('error', this.handleGlobalError.bind(this));
    window.addEventListener(
      'unhandledrejection',
      this.handleUnhandledRejection.bind(this)
    );
  }

  private handleGlobalError(event: ErrorEvent): void {
    this.handleError({
      code: 'GLOBAL_ERROR',
      message: event.message,
      userMessage: 'An unexpected error occurred. Please try again.',
      severity: 'high',
      recoverable: true,
      context: {
        filename: event.filename,
        lineno: event.lineno,
        colno: event.colno,
        stack: event.error?.stack,
      },
      timestamp: new Date().toISOString(),
    });
  }

  private handleUnhandledRejection(event: PromiseRejectionEvent): void {
    this.handleError({
      code: 'UNHANDLED_PROMISE_REJECTION',
      message: String(event.reason),
      userMessage:
        'A background operation failed. Some features may not work correctly.',
      severity: 'medium',
      recoverable: true,
      context: {
        reason: event.reason,
        stack: event.reason?.stack,
      },
      timestamp: new Date().toISOString(),
    });
  }

  handleError(error: AppError): void {
    // Add to queue
    this.errorQueue.push(error);
    if (this.errorQueue.length > this.maxErrors) {
      this.errorQueue.shift();
    }

    // Log the error
    logger.error('Context', 'Error message', {
      code: error.code,
      severity: error.severity,
      recoverable: error.recoverable,
      context: error.context,
    });

    // Track error analytics
    logger.trackEvent('error_occurred', {
      code: error.code,
      severity: error.severity,
      recoverable: error.recoverable,
      userMessage: error.userMessage,
    });

    // Notify user if appropriate
    if (error.severity === 'high' || error.severity === 'critical') {
      this.notifyUser(error);
    }
  }

  private notifyUser(error: AppError): void {
    // This would integrate with your notification system
    console.warn('User notification:', error.userMessage);

    // You could dispatch a custom event here for UI components to listen to
    window.dispatchEvent(
      new CustomEvent('app-error', {
        detail: error,
      })
    );
  }

  // Specific error creators
  createAPIError(
    service: string,
    endpoint: string,
    status: number,
    message: string
  ): AppError {
    return {
      code: `API_ERROR_${service.toUpperCase()}`,
      message: `${service} API error: ${message}`,
      userMessage: `Unable to connect to ${service}. Please check your internet connection and try again.`,
      severity: status >= 500 ? 'high' : 'medium',
      recoverable: true,
      context: {
        service,
        endpoint,
        status,
        originalMessage: message,
      },
      timestamp: new Date().toISOString(),
    };
  }

  createAuthError(service: string): AppError {
    return {
      code: `AUTH_ERROR_${service.toUpperCase()}`,
      message: `Authentication failed for ${service}`,
      userMessage: `Unable to authenticate with ${service}. Please check your API credentials.`,
      severity: 'high',
      recoverable: false,
      context: { service },
      timestamp: new Date().toISOString(),
    };
  }

  createRateLimitError(service: string, retryAfter: number): AppError {
    return {
      code: `RATE_LIMIT_${service.toUpperCase()}`,
      message: `Rate limit exceeded for ${service}`,
      userMessage: `Too many requests to ${service}. Please wait ${Math.ceil(retryAfter / 1000)} seconds and try again.`,
      severity: 'medium',
      recoverable: true,
      context: { service, retryAfter },
      timestamp: new Date().toISOString(),
    };
  }

  createValidationError(field: string, value: any, rule: string): AppError {
    return {
      code: 'VALIDATION_ERROR',
      message: `Validation failed for ${field}: ${rule}`,
      userMessage: `Please check your input for ${field} and try again.`,
      severity: 'low',
      recoverable: true,
      context: { field, value, rule },
      timestamp: new Date().toISOString(),
    };
  }

  createNetworkError(operation: string): AppError {
    return {
      code: 'NETWORK_ERROR',
      message: `Network error during ${operation}`,
      userMessage:
        'Network connection failed. Please check your internet connection and try again.',
      severity: 'medium',
      recoverable: true,
      context: { operation },
      timestamp: new Date().toISOString(),
    };
  }

  getErrors(severity?: AppError['severity']): AppError[] {
    if (severity) {
      return this.errorQueue.filter(error => error.severity === severity);
    }
    return [...this.errorQueue];
  }

  clearErrors(): void {
    this.errorQueue = [];
  }

  getErrorStats(): Record<string, number> {
    const stats: Record<string, number> = {};
    this.errorQueue.forEach(error => {
      stats[error.code] = (stats[error.code] || 0) + 1;
    });
    return stats;
  }
}

export const errorHandler = ErrorHandler.getInstance();

export type AppErrorCode =
  | 'UNAUTHORIZED'
  | 'FORBIDDEN'
  | 'BAD_REQUEST'
  | 'NOT_FOUND'
  | 'RATE_LIMITED'
  | 'TIMEOUT'
  | 'NETWORK_ERROR'
  | 'UPSTREAM_ERROR'
  | 'INTERNAL_ERROR'
  | 'INVALID_CREDENTIALS'
  | 'MISSING_CREDENTIALS'
  | 'SPOTIFY_API_ERROR'
  | 'SPOTIFY_AUTH_FAILED'
  | 'SPOTIFY_SEARCH_FAILED'
  | 'YOUTUBE_API_ERROR'
  | 'YOUTUBE_SEARCH_FAILED'
  | 'QUOTA_EXCEEDED'
  | 'MAGIC_SET_ERROR'
  | 'HEALTH_CHECK_ERROR'
  | 'DATABASE_ERROR'
  | 'MISSING_CONFIG'
  | 'PLAYLIST_CREATE_ERROR'
  | 'PLAYLIST_GET_ERROR'
  | 'PLAYLISTS_GET_ERROR'
  | 'PLAYLIST_UPDATE_ERROR'
  | 'PLAYLIST_DELETE_ERROR'
  | 'TRACK_ADD_ERROR'
  | 'TRACK_REMOVE_ERROR'
  | 'SESSION_CREATE_ERROR'
  | 'SESSION_UPDATE_ERROR'
  | 'SESSIONS_GET_ERROR';

export interface NormalizedError {
  code: AppErrorCode;
  message: string;
  httpStatus?: number;
  retriable?: boolean;
  details?: any;
}

export class AppError extends Error implements NormalizedError {
  code: AppErrorCode;
  httpStatus?: number;
  retriable?: boolean;
  details?: any;

  constructor(
    code: AppErrorCode,
    message: string,
    options?: {
      httpStatus?: number;
      retriable?: boolean;
      details?: any;
      cause?: any;
    }
  ) {
    super(message);
    this.name = 'AppError';
    this.code = code;
    this.httpStatus = options?.httpStatus;
    this.retriable = options?.retriable;
    this.details = options?.details;
    // Preserve original cause where supported
    // @ts-ignore
    if (options?.cause) this.cause = options.cause;
  }

  toJSON(): NormalizedError {
    return {
      code: this.code,
      message: this.message,
      httpStatus: this.httpStatus,
      retriable: this.retriable,
      details: this.details,
    };
  }
}

export function normalizeError(
  err: unknown,
  fallback: Partial<NormalizedError> = {}
): NormalizedError {
  if (err instanceof AppError) return err.toJSON();
  if (err instanceof Error) {
    return {
      code: (fallback.code as AppErrorCode) || 'INTERNAL_ERROR',
      message: err.message || fallback.message || 'Unexpected error',
      httpStatus: fallback.httpStatus,
      retriable: fallback.retriable,
      details: fallback.details,
    };
  }
  return {
    code: (fallback.code as AppErrorCode) || 'INTERNAL_ERROR',
    message: fallback.message || 'Unexpected error',
    httpStatus: fallback.httpStatus,
    retriable: fallback.retriable,
    details: fallback.details ?? err,
  };
}

export async function errorFromResponse(
  resp: Response,
  bodyText?: string
): Promise<AppError> {
  const status = resp.status;
  const message = `${status} ${resp.statusText}`;
  let code: AppErrorCode = 'UPSTREAM_ERROR';
  if (status === 400) code = 'BAD_REQUEST';
  else if (status === 401) code = 'UNAUTHORIZED';
  else if (status === 403) code = 'FORBIDDEN';
  else if (status === 404) code = 'NOT_FOUND';
  else if (status === 408) code = 'TIMEOUT';
  else if (status === 429) code = 'RATE_LIMITED';
  else if (status >= 500) code = 'UPSTREAM_ERROR';

  return new AppError(code, message, {
    httpStatus: status,
    retriable: status >= 500 || status === 429 || status === 408,
    details: { body: bodyText?.slice(0, 200) },
  });
}

export interface RetryOptions {
  retries?: number;
  timeoutMs?: number;
  retryOn?: number[]; // status codes to retry
  backoffBaseMs?: number; // initial delay
  backoffMaxMs?: number; // cap
  budget?: number; // max total time to spend on retries
}

interface CircuitBreakerState {
  failures: number;
  lastFailureTime: number;
  state: 'closed' | 'open' | 'half-open';
}

class CircuitBreaker {
  private states = new Map<string, CircuitBreakerState>();
  private readonly failureThreshold = 5;
  private readonly recoveryTimeMs = 30000; // 30 seconds

  private getKey(url: string): string {
    try {
      const urlObj = new URL(url);
      return urlObj.hostname;
    } catch {
      return url;
    }
  }

  private getState(key: string): CircuitBreakerState {
    if (!this.states.has(key)) {
      this.states.set(key, {
        failures: 0,
        lastFailureTime: 0,
        state: 'closed',
      });
    }
    return this.states.get(key)!;
  }

  canExecute(url: string): boolean {
    const key = this.getKey(url);
    const state = this.getState(key);
    const now = Date.now();

    if (state.state === 'closed') {
      return true;
    }

    if (state.state === 'open') {
      if (now - state.lastFailureTime > this.recoveryTimeMs) {
        state.state = 'half-open';
        return true;
      }
      return false;
    }

    // half-open: allow one request
    return true;
  }

  onSuccess(url: string): void {
    const key = this.getKey(url);
    const state = this.getState(key);
    state.failures = 0;
    state.state = 'closed';
  }

  onFailure(url: string): void {
    const key = this.getKey(url);
    const state = this.getState(key);
    state.failures++;
    state.lastFailureTime = Date.now();

    if (state.failures >= this.failureThreshold) {
      state.state = 'open';
    }
  }
}

const circuitBreaker = new CircuitBreaker();

export async function fetchWithTimeout(
  input: RequestInfo | URL,
  init: RequestInit = {},
  timeoutMs = 12000
): Promise<Response> {
  const controller = new AbortController();
  const id = setTimeout(() => controller.abort(), timeoutMs);
  try {
    const res = await fetch(input, { ...init, signal: controller.signal });
    return res;
  } finally {
    clearTimeout(id);
  }
}

export async function fetchWithRetry(
  input: RequestInfo | URL,
  init: RequestInit = {},
  opts: RetryOptions = {}
): Promise<Response> {
  const {
    retries = 2,
    timeoutMs = 12000,
    retryOn = [429, 500, 502, 503, 504],
    backoffBaseMs = 400,
    backoffMaxMs = 4000,
    budget = 30000, // 30 second max budget
  } = opts;

  const url = typeof input === 'string' ? input : input.toString();
  const startTime = Date.now();

  // Check circuit breaker
  if (!circuitBreaker.canExecute(url)) {
    throw new Error(`Circuit breaker open for ${url}`);
  }

  let attempt = 0;
  // eslint-disable-next-line no-constant-condition
  while (true) {
    try {
      const res = await fetchWithTimeout(input, init, timeoutMs);

      if (res.ok) {
        circuitBreaker.onSuccess(url);
      } else {
        circuitBreaker.onFailure(url);
      }

      if (retryOn.includes(res.status) && attempt < retries) {
        // Check budget before retrying
        const elapsed = Date.now() - startTime;
        if (elapsed >= budget) {
          throw new Error('Retry budget exceeded');
        }

        const jitter = Math.random() * 200; // Add jitter
        const delay = Math.min(
          backoffBaseMs * Math.pow(2, attempt) + jitter,
          backoffMaxMs
        );
        await new Promise(r => setTimeout(r, delay));
        attempt++;
        continue;
      }
      return res;
    } catch (err: any) {
      circuitBreaker.onFailure(url);

      if (attempt >= retries) throw err;

      // Check budget before retrying
      const elapsed = Date.now() - startTime;
      if (elapsed >= budget) {
        throw new Error('Retry budget exceeded');
      }

      const jitter = Math.random() * 200; // Add jitter
      const delay = Math.min(
        backoffBaseMs * Math.pow(2, attempt) + jitter,
        backoffMaxMs
      );
      await new Promise(r => setTimeout(r, delay));
      attempt++;
    }
  }
}

interface IdempotencyRecord {
  key: string;
  response: any;
  timestamp: number;
  expiresAt: number;
}

// Shared storage adapter interface
interface StorageAdapter {
  get(key: string): Promise<any | null>;
  set(key: string, value: any, ttlSeconds: number): Promise<void>;
}

class MemoryAdapter implements StorageAdapter {
  private cache = new Map<string, IdempotencyRecord>();
  async get(key: string): Promise<any | null> {
    const rec = this.cache.get(key);
    if (!rec) return null;
    if (rec.expiresAt < Date.now()) {
      this.cache.delete(key);
      return null;
    }
    return rec.response;
  }
  async set(key: string, value: any, ttlSeconds: number): Promise<void> {
    const now = Date.now();
    this.cache.set(key, {
      key,
      response: value,
      timestamp: now,
      expiresAt: now + ttlSeconds * 1000,
    });
  }
}

class KvAdapter implements StorageAdapter {
  constructor(_ttlSeconds: number) {}
  async get(key: string): Promise<any | null> {
    const { kv } = await import('../../utils/kv.js');
    const raw = await kv.get(`idem:${key}`);
    if (!raw) return null;
    try {
      return JSON.parse(raw);
    } catch {
      return null;
    }
  }
  async set(key: string, value: any, ttlSeconds: number): Promise<void> {
    const { kv } = await import('../../utils/kv.js');
    await kv.setex(`idem:${key}`, ttlSeconds, JSON.stringify(value));
  }
}

class IdempotencyManager {
  private readonly TTL_SECONDS = 24 * 60 * 60; // 24 hours
  private adapter: StorageAdapter;

  constructor() {
    // Choose adapter based on env
    if (process.env.DURABLE_STORE_URL && process.env.DURABLE_STORE_TOKEN) {
      this.adapter = new KvAdapter(this.TTL_SECONDS);
    } else {
      this.adapter = new MemoryAdapter();
      // In-memory cleanup loop (browser only or long-lived)
      if (typeof window !== 'undefined') {
        setInterval(() => this.cleanup?.(), 60 * 60 * 1000);
      }
    }
  }

  private cleanup?(): void;

  generateKey(request: Request, body?: any): string {
    const url = new URL(request.url);
    const method = request.method;
    const bodyStr = body ? JSON.stringify(body) : '';
    // Use a Node-safe base64 when window.btoa is unavailable
    const base64 =
      typeof window === 'undefined'
        ? Buffer.from(bodyStr).toString('base64')
        : btoa(bodyStr);
    return `${method}:${url.pathname}:${base64}`;
  }

  async store(key: string, response: any): Promise<void> {
    await this.adapter.set(key, response, this.TTL_SECONDS);
  }

  async retrieve(key: string): Promise<any | null> {
    return this.adapter.get(key);
  }

  isValidKey(key: string): boolean {
    return Boolean(key && key.length >= 16 && key.length <= 255);
  }
}

export const idempotencyManager = new IdempotencyManager();

export function withIdempotency(handler: (req: any, res: any) => Promise<any>) {
  return async (req: any, res: any): Promise<any> => {
    const idempotencyKey =
      req.headers['idempotency-key'] || req.headers['Idempotency-Key'];

    if (!idempotencyKey) {
      return handler(req, res);
    }

    if (!idempotencyManager.isValidKey(idempotencyKey)) {
      return res.status(400).json({
        error: 'Invalid Idempotency-Key header. Must be 16-255 characters.',
      });
    }

    // Check for existing response
    const existingResponse = await idempotencyManager.retrieve(idempotencyKey);
    if (existingResponse) {
      return res.status(existingResponse.status).json(existingResponse.body);
    }

    // Execute handler and capture response
    const originalJson = res.json;
    const originalStatus = res.status;
    let capturedStatus = 200;

    res.status = function (code: number) {
      capturedStatus = code;
      return originalStatus.call(this, code);
    };

    res.json = function (body: any) {
      // Fire and forget; do not block response
      Promise.resolve(
        idempotencyManager.store(idempotencyKey, {
          status: capturedStatus,
          body,
        })
      ).catch(() => {});
      return originalJson.call(this, body);
    };

    return handler(req, res);
  };
}

interface LogEntry {
  timestamp: string;
  level: 'debug' | 'info' | 'warn' | 'error';
  component: string;
  message: string;
  data?: any;
  error?: Error;
  sessionId?: string;
  userId?: string;
  correlationId?: string;
}

interface TelemetryData {
  event: string;
  properties: Record<string, any>;
  timestamp: string;
  sessionId: string;
  userId?: string;
}

class Logger {
  private logs: LogEntry[] = [];
  private maxLogs = 2000;
  private sessionId: string;
  private logLevel: string;
  private telemetryEndpoint?: string;
  private enableObservability: boolean;

  constructor() {
    this.sessionId = this.generateSessionId();
    this.logLevel = import.meta.env.VITE_LOG_LEVEL || 'info';
    this.telemetryEndpoint = import.meta.env.VITE_TELEMETRY_ENDPOINT;
    this.enableObservability =
      import.meta.env.VITE_ENABLE_OBSERVABILITY === 'true';

    this.info('Logger', 'Logger initialized', {
      sessionId: this.sessionId,
      logLevel: this.logLevel,
      observabilityEnabled: this.enableObservability,
    });
  }

  private generateSessionId(): string {
    return `session_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
  }

  private shouldLog(level: 'debug' | 'info' | 'warn' | 'error'): boolean {
    const levels = { debug: 0, info: 1, warn: 2, error: 3 };
    return levels[level] >= levels[this.logLevel as keyof typeof levels];
  }

  private addLog(
    level: 'debug' | 'info' | 'warn' | 'error',
    component: string,
    message: string,
    data?: any,
    error?: Error,
    userId?: string,
    correlationId?: string
  ) {
    if (!this.shouldLog(level)) return;

    const entry: LogEntry = {
      timestamp: new Date().toISOString(),
      level,
      component,
      message,
      data,
      error,
      sessionId: this.sessionId,
      userId,
      correlationId,
    };

    this.logs.push(entry);

    // Keep only the most recent logs
    if (this.logs.length > this.maxLogs) {
      this.logs = this.logs.slice(-this.maxLogs);
    }

    // Console output with formatting
    const logMessage = `[${entry.timestamp}] ${component}: ${message}`;
    const logData = { ...data, sessionId: this.sessionId, correlationId };

    if (level === 'error') {
      console.error(logMessage, logData, error);
    } else if (level === 'warn') {
      console.warn(logMessage, logData);
    } else if (level === 'debug') {
      console.debug(logMessage, logData);
    } else {
      console.log(logMessage, logData);
    }

    // Send to telemetry if enabled
    if (this.enableObservability && this.telemetryEndpoint) {
      this.sendTelemetry({
        event: `log_${level}`,
        properties: {
          component,
          message,
          data,
          error: error?.message,
          stack: error?.stack,
        },
        timestamp: entry.timestamp,
        sessionId: this.sessionId,
        userId,
      });
    }
  }

  private async sendTelemetry(data: TelemetryData) {
    try {
      await fetch(this.telemetryEndpoint!, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
      });
    } catch (error) {
      console.warn('Failed to send telemetry:', error);
    }
  }

  debug(
    component: string,
    message: string,
    data?: any,
    userId?: string,
    correlationId?: string
  ) {
    this.addLog(
      'debug',
      component,
      message,
      data,
      undefined,
      userId,
      correlationId
    );
  }

  info(
    component: string,
    message: string,
    data?: any,
    userId?: string,
    correlationId?: string
  ) {
    this.addLog(
      'info',
      component,
      message,
      data,
      undefined,
      userId,
      correlationId
    );
  }

  warn(
    component: string,
    message: string,
    data?: any,
    userId?: string,
    correlationId?: string
  ) {
    this.addLog(
      'warn',
      component,
      message,
      data,
      undefined,
      userId,
      correlationId
    );
  }

  error(
    component: string,
    message: string,
    error?: any,
    userId?: string,
    correlationId?: string
  ) {
    this.addLog(
      'error',
      component,
      message,
      undefined,
      error,
      userId,
      correlationId
    );
  }

  async trackOperation<T>(
    component: string,
    operation: string,
    fn: () => Promise<T>,
    metadata?: any,
    userId?: string
  ): Promise<T> {
    const correlationId = `op_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
    const startTime = Date.now();

    this.info(
      component,
      `Starting ${operation}`,
      { metadata, correlationId },
      userId,
      correlationId
    );

    try {
      const result = await fn();
      const duration = Date.now() - startTime;

      this.info(
        component,
        `Completed ${operation}`,
        {
          duration,
          metadata,
          correlationId,
          success: true,
        },
        userId,
        correlationId
      );

      // Track successful operations
      if (this.enableObservability) {
        this.trackEvent(
          'operation_success',
          {
            component,
            operation,
            duration,
            metadata,
          },
          userId
        );
      }

      return result;
    } catch (error) {
      const duration = Date.now() - startTime;

      this.error(
        component,
        `Failed ${operation}`,
        error,
        userId,
        correlationId
      );
      this.info(
        component,
        `Operation failed after ${duration}ms`,
        {
          duration,
          metadata,
          correlationId,
          success: false,
          errorMessage:
            error instanceof Error ? error.message : String(error),
        },
        userId,
        correlationId
      );

      // Track failed operations
      if (this.enableObservability) {
        this.trackEvent(
          'operation_failure',
          {
            component,
            operation,
            duration,
            metadata,
            error: error instanceof Error ? error.message : String(error),
          },
          userId
        );
      }

      throw error;
    }
  }

  trackEvent(event: string, properties: Record<string, any>, userId?: string) {
    if (!this.enableObservability) return;

    const telemetryData: TelemetryData = {
      event,
      properties,
      timestamp: new Date().toISOString(),
      sessionId: this.sessionId,
      userId,
    };

    this.info('Analytics', `Event: ${event}`, properties, userId);

    if (this.telemetryEndpoint) {
      this.sendTelemetry(telemetryData);
    }
  }

  trackUserAction(
    action: string,
    properties?: Record<string, any>,
    userId?: string
  ) {
    this.trackEvent(`user_${action}`, properties || {}, userId);
  }

  trackAPICall(
    service: string,
    endpoint: string,
    duration: number,
    success: boolean,
    userId?: string
  ) {
    this.trackEvent(
      'api_call',
      {
        service,
        endpoint,
        duration,
        success,
      },
      userId
    );
  }

  getLogs(
    level?: 'debug' | 'info' | 'warn' | 'error',
    component?: string
  ): LogEntry[] {
    let filteredLogs = [...this.logs];

    if (level) {
      filteredLogs = filteredLogs.filter(log => log.level === level);
    }

    if (component) {
      filteredLogs = filteredLogs.filter(log => log.component === component);
    }

    return filteredLogs;
  }

  getSessionId(): string {
    return this.sessionId;
  }

  clearLogs() {
    this.logs = [];
    this.info('Logger', 'Logs cleared');
  }

  exportLogs(): string {
    return JSON.stringify(this.logs, null, 2);
  }
}

export const logger = new Logger();

