// DEFAULT INSTANCE (for environments with fixed config)
// =============================================================================

let defaultClient: BackendClient | null = null;

export function getDefaultBackendClient(): BackendClient {
  if (!defaultClient) {
    const supabaseUrl =
      process.env.SUPABASE_URL || process.env.NEXT_PUBLIC_SUPABASE_URL;
    const supabaseKey =
      process.env.SUPABASE_ANON_KEY ||
      process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY;

    if (!supabaseUrl || !supabaseKey) {
      throw new AppError('MISSING_CONFIG', 'Supabase URL and key are required');
    }

    defaultClient = createBackendClient({
      supabaseUrl,
      supabaseKey,
    });
  }

  return defaultClient;
}

interface IdempotencyRecord {
  key: string;
  response: any;
  timestamp: number;
  expiresAt: number;
}

class IdempotencyManager {
  private cache = new Map<string, IdempotencyRecord>();
  private readonly TTL_MS = 24 * 60 * 60 * 1000; // 24 hours

  constructor() {
    // Clean expired entries every hour
    setInterval(() => this.cleanup(), 60 * 60 * 1000);
  }

  private cleanup(): void {
    const now = Date.now();
    for (const [key, record] of this.cache.entries()) {
      if (record.expiresAt < now) {
        this.cache.delete(key);
      }
    }
  }

  generateKey(request: Request, body?: any): string {
    const url = new URL(request.url);
    const method = request.method;
    const bodyStr = body ? JSON.stringify(body) : '';
    return `${method}:${url.pathname}:${btoa(bodyStr)}`;
  }

  store(key: string, response: any): void {
    const now = Date.now();
    this.cache.set(key, {
      key,
      response,
      timestamp: now,
      expiresAt: now + this.TTL_MS,
    });
  }

  retrieve(key: string): any | null {
    const record = this.cache.get(key);
    if (!record) return null;

    if (record.expiresAt < Date.now()) {
      this.cache.delete(key);
      return null;
    }

    return record.response;
  }

  isValidKey(key: string): boolean {
    return Boolean(key && key.length >= 16 && key.length <= 255);
  }
}

export const idempotencyManager = new IdempotencyManager();

export function withIdempotency(handler: (req: any, res: any) => Promise<any>) {
  return async (req: any, res: any): Promise<any> => {
    const idempotencyKey =
      req.headers['idempotency-key'] || req.headers['Idempotency-Key'];

    if (!idempotencyKey) {
      return handler(req, res);
    }

    if (!idempotencyManager.isValidKey(idempotencyKey)) {
      return res.status(400).json({
        error: 'Invalid Idempotency-Key header. Must be 16-255 characters.',
      });
    }

    // Check for existing response
    const existingResponse = idempotencyManager.retrieve(idempotencyKey);
    if (existingResponse) {
      return res.status(existingResponse.status).json(existingResponse.body);
    }

    // Execute handler and capture response
    const originalJson = res.json;
    const originalStatus = res.status;
    let capturedStatus = 200;

    res.status = function (code: number) {
      capturedStatus = code;
      return originalStatus.call(this, code);
    };

    res.json = function (body: any) {
      idempotencyManager.store(idempotencyKey, {
        status: capturedStatus,
        body,
      });
      return originalJson.call(this, body);
    };

    return handler(req, res);
  };
}

// Lightweight Upstash Redis REST client (or no-op memory fallback)

type KvResult<T = any> = { result: T };

function isUpstashConfigured() {
  return !!(process.env.DURABLE_STORE_URL && process.env.DURABLE_STORE_TOKEN);
}

async function upstash<T = any>(cmd: (string | number)[]): Promise<T> {
  const base = process.env.DURABLE_STORE_URL as string;
  const token = process.env.DURABLE_STORE_TOKEN as string;
  const res = await fetch(base, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${token}`,
    },
    body: JSON.stringify(cmd),
  });
  if (!res.ok) {
    const text = await res.text();
    throw new Error(`Upstash error ${res.status}: ${text}`);
  }
  const json = (await res.json()) as KvResult<T>;
  return json.result;
}

const memory = new Map<string, { value: string; expiresAt?: number }>();

function memGet(key: string): string | null {
  const e = memory.get(key);
  if (!e) return null;
  if (e.expiresAt && Date.now() > e.expiresAt) {
    memory.delete(key);
    return null;
  }
  return e.value;
}

export const kv = {
  async get(key: string): Promise<string | null> {
    if (isUpstashConfigured()) {
      return upstash<string | null>(['GET', key]);
    }
    return memGet(key);
  },

  async setex(key: string, ttlSeconds: number, value: string): Promise<void> {
    if (isUpstashConfigured()) {
      await upstash(['SETEX', key, ttlSeconds, value]);
      return;
    }
    memory.set(key, { value, expiresAt: Date.now() + ttlSeconds * 1000 });
  },

  async incr(key: string): Promise<number> {
    if (isUpstashConfigured()) {
      return upstash<number>(['INCR', key]);
    }
    const v = parseInt(memGet(key) || '0', 10) + 1;
    memory.set(key, { value: String(v) });
    return v;
  },

  async expire(key: string, ttlSeconds: number): Promise<boolean> {
    if (isUpstashConfigured()) {
      return upstash<number>(['EXPIRE', key, ttlSeconds]).then(r => r === 1);
    }
    const v = memGet(key);
    if (v === null) return false;
    memory.set(key, { value: v, expiresAt: Date.now() + ttlSeconds * 1000 });
    return true;
  },
};

